window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["e"]={"Edward": "<b>Edward</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia angielskiego. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">języku staroangielskim</a>:", "Eugeniusz": "<b>Eugeniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Oznacza „zacny“ lub „szlachetnie urodzony”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Eugenia\" target=\"_blank\" rel=\"noopener noreferrer\">Eugenia</a>.", "Emil": "<b>Emil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a> (<i>Aemilius</i>). Łacińskie słowo <i>aemulor</i> oznacza „rywalizujący”. Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Emil_z_Kordoby\" target=\"_blank\" rel=\"noopener noreferrer\">Emil z Kordoby</a> (†852), męczennik i święty katolicki wspominany 15 września.", "Eryk": "<b>Eryk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Nadawane wielu jarlom i królom <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">szwedzkim</a> i <a href=\"https://pl.wikipedia.org/wiki/Dania\" target=\"_blank\" rel=\"noopener noreferrer\">duńskim</a>. Pochodzenie tego imienia podaje się ze staro-wysoko-niemieckiego, gdzie <b>era</b> znaczy: honor, cześć, oraz <b>richi</b> – bogaty. Całość zaś oznacza osobę zasobną w honor lub władcę, który zaszczytnie króluje. Jego popularność sięga czasów króla szwedzkiego Eryka zmarłego w <a href=\"https://pl.wikipedia.org/wiki/1160\" target=\"_blank\" rel=\"noopener noreferrer\">1160</a>. Inne spotykane znaczenie to „wieczny władca” od <i>ei(r)</i> co oznacza w staronordyjskim „wieczny” i <i>ríkr</i> – w staronordyjskim „władca”.", "Edmund": "<b>Edmund</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a>. Wywodzi się od słowa oznaczającego „zapewniający opiekę”.", "Ernest": "<b>Ernest</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego \"powaga, zapał, walka\". Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Ernest_z_Zwiefalten\" target=\"_blank\" rel=\"noopener noreferrer\">Święty Ernest</a> - opat i <a href=\"https://pl.wikipedia.org/wiki/M%C4%99czennicy_chrze%C5%9Bcija%C5%84scy\" target=\"_blank\" rel=\"noopener noreferrer\">męczennik</a> (zginął w 1148 roku).", "Eduard": "<p>Edwarda - męskie imię, pochodzące od angielsko-saksońskiego Ēadweard - ⁇ strzeganie bogactwa, szczęścia ⁇ (ead oznacza ⁇ szczęśliwy, kwitnący ⁇ , a weard tłumaczono jako ⁇ strogę ⁇).</p>", "Emanuel": "<b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Erwin": "<b>Erwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe z wyrazów <i>heri</i> – „drużyna wojenna” oraz <i>wini</i> – „przyjaciel”, oznaczające „ten, który chętnie wojuje”. Pojawia się również jako: <b>Ermin</b>, <b>Hermin</b> i <b>Irmin</b>.", "Emilian": "Utarło się kilka <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnień</a> tego imienia: <i>Emko</i>, <i>Mila</i>, <i><a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a></i>, <i>Milo</i> itp., oraz najpopularniejsze <i><b><a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a></b></i>. Ostatnie, dzięki twórczości <a href=\"https://pl.wikipedia.org/wiki/Jean-Jacques_Rousseau\" target=\"_blank\" rel=\"noopener noreferrer\">Jeana-Jacques’a Rousseau</a> (<i><a href=\"https://pl.wikipedia.org/wiki/Emil,_czyli_o_wychowaniu\" target=\"_blank\" rel=\"noopener noreferrer\">Emil, czyli O wychowaniu</a></i>), zostało upowszechnione w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX w.</a> jako odrębne imię i często stosowane wymiennie. Znane <a href=\"https://pl.wikipedia.org/wiki/Spieszczenie\" target=\"_blank\" rel=\"noopener noreferrer\">spieszczenia</a> imienia to m.in.: <i>Jemek</i>, <i>Milek</i>, <i>Miluś</i>, <i>Miłek</i> itp., oraz pochodzące od zdrobnienia <i>Emil</i>: <i>Emilek</i>, <i>Emisz</i>, <i>Emiś</i> itp.", "Edwin": "<b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Eliasz": "<b>Eliasz</b>, również <b>Eliasz z Tiszbe</b> lub <b>Eliasz Tiszbita</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֱלִיָּהוּ&#8206; <i>Eliyáhu</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἠλίας <i>Elias</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_cerkiewnos%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">cs.</a>&#160;Илья-пророк) – jeden z <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">proroków</a> <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a> żyjący w IX w. przed Chrystusem w północnym państwie Izraela (imię tłumaczone jako: „Bogiem jest <a href=\"https://pl.wikipedia.org/wiki/Jah\" target=\"_blank\" rel=\"noopener noreferrer\">Jah</a>”, „moim Bogiem jest <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”). <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ci_i_b%C5%82ogos%C5%82awieni_Ko%C5%9Bcio%C5%82a_katolickiego\" target=\"_blank\" rel=\"noopener noreferrer\">Święty Kościoła katolickiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Cerkiew_prawos%C5%82awna\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławnego</a>, <a href=\"https://pl.wikipedia.org/wiki/Koptyjski_Ko%C5%9Bci%C3%B3%C5%82_Ortodoksyjny\" target=\"_blank\" rel=\"noopener noreferrer\">koptyjskiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Apostolski_Ko%C5%9Bci%C3%B3%C5%82_Ormia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskiego</a> i <a href=\"https://pl.wikipedia.org/wiki/Syryjski_Ko%C5%9Bci%C3%B3%C5%82_Ortodoksyjny\" target=\"_blank\" rel=\"noopener noreferrer\">syryjskiego</a>.", "Erik": "<p>Erik może być: Erik, prawdziwe imię: Lê Trung Thành, wietnamski piosenkarz, były członek zespołu Monstar Erik Rhodes, amerykański aktor porno Erik, amerykański zawodowy walkacz</p>", "Eligiusz": "<b>Eligiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> czasownika <i>eligo, elegi, electum</i> oznaczające – „wybrany”.", "Eric": "<p>Eric (pełna nazwa: Eric Python IDE) - wolno dystrybuowane zintegrowane środowisko rozwoju dla języków programowania Python i Ruby. Przez pewien czas Eric4 działał tylko z Python 2, a Eric5 z Python 3, ale od Eric6 wspierają obie wersje Python jednocześnie.</p>", "Edgar": "<b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Ewald": "<b>Ewald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze złożenia słów <i>eo</i> – „prawo” i <i>wald</i> – „rządzić”, „panować”. Jego znaczenie można interpretować jako „panujący sprawiedliwie, w zgodzie z prawem”. Patronami tego imienia są bracia św. Ewald Biały i św. Ewald Czarny (<a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII wiek</a>), wspominani 3 października.", "Euzebiusz": "<b>Euzebiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> <i>eusébeios</i>. Pierwotnie przymiotnik ten użyty został dla określenia jednego z miesięcy na cześć cesarza rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Antoninus_Pius\" target=\"_blank\" rel=\"noopener noreferrer\">Antonina Piusa</a>. Wywodzi się od słowa oznaczającego „bogobojny”, „święty”.", "Enrique": "<p>Enrique - pierwszy angielski i czwarty album hiszpańskiego piosenkarza popu Enrique Iglesias, wydany w 1999 roku. Jest to pierwszy album Iglesias, który został nagrany we współpracy z amerykańską wytwórnią Interscope Records i producentami Paulem Barry'm i Markem Taylorem.</p>", "Emmanuel": "<b>Emmanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Symbol\" target=\"_blank\" rel=\"noopener noreferrer\">symboliczne</a> imię (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i> 'immanu 'el</i> – <i>Bóg jest z nami</i>), przypisywane przez <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">proroka</a> <a href=\"https://pl.wikipedia.org/wiki/Izajasz\" target=\"_blank\" rel=\"noopener noreferrer\">Izajasza</a> chłopcu, którego królowi <a href=\"https://pl.wikipedia.org/wiki/Achaz\" target=\"_blank\" rel=\"noopener noreferrer\">Achazowi</a> miała urodzić młoda kobieta (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Izajasza\" target=\"_blank\" rel=\"noopener noreferrer\">Iz</a> 7,14) w momencie poważnego zagrożenia dynastii. W chwili wygłoszenia proroctwa król <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Damaszku\" target=\"_blank\" rel=\"noopener noreferrer\">Damaszku</a>, <a href=\"https://pl.wikipedia.org/wiki/Resin\" target=\"_blank\" rel=\"noopener noreferrer\">Resin</a>, i król <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Izraela_(pa%C5%84stwo_p%C3%B3%C5%82nocne)\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a>, <a href=\"https://pl.wikipedia.org/wiki/Pekach\" target=\"_blank\" rel=\"noopener noreferrer\">Pekach</a>, oblegli Jerozolimę w ramach toczącej się <a href=\"https://pl.wikipedia.org/wiki/Wojna_syro-efraimska\" target=\"_blank\" rel=\"noopener noreferrer\">wojny syro-efraimskiej</a>. Emmanuel miał być znakiem Bożej łaski wobec Achaza, skutkującej niepowodzeniem koalicji.", "Elias": "<p>Eliusz Aleksanderski (w części źródeł Elias, grecki ⁇ λίας) - późnoantyczny grecki filozof-neoplatonik VI wieku n.e.</p>", "Egor": "<p>Gregor Yuán (ang. Gregor Ewan; rodzaj.</p>", "Ethan": "<p>Ethan jest związkiem chemicznym z formułą chemiczną C2H6. To jest alkan, czyli niezawierający kręgów.</p>", "Ewaryst": "<b>Ewaryst</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, które oznacza <i>miły, przyjemny, najlepszy</i>. Imię to nadawane jest w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII</a> w. Istnieje kilku świętych Ewarystów, m.in. <a href=\"https://pl.wikipedia.org/wiki/Ewaryst_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">Ewaryst, papież</a> oraz św. Ewaryst z Konstantynopola.", "Evgenii": "<p>Yevgeni (rosyjski: Евгений), również przetransliterowany jako Yevgeny, Yevgenii, Yevgeniy, Evgeniy, Yewgeny, Evgenii, Evgenii, Evgenyi lub Evgenij, jest rosyjską formą męskiego imienia Eugene. Krótka forma jest Zhenya (Женя), również przetłumaczana jako Jenya lub Shenya.</p>", "Emir": "<p>Emir (; arabski: أمير ʾAmīr [ʔæˈmiːr]), czasami przenoszony do Amir, Amier lub Ameer, jest szlachectwem lub szlachetnym urzędnikiem używanym w wielu regionach w krajach Arabskich. Dosłownie oznacza to dowódca, generał, król lub król.</p>", "Engelbert": "<b>Engelbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od nazwy jednego z plemion germańskich <i>Angil</i> (<a href=\"https://pl.wikipedia.org/wiki/Anglowie\" target=\"_blank\" rel=\"noopener noreferrer\">Anglowie</a>) połączonego słowem <i>beraht</i> oznaczającym \"jasny\".", "Emilio": "<p>Emilio, Luciano (ur. 1978) - brazylijski piłkarz.</p>", "Eyal": "<p>Eyal to hebrajskie imię męskie oznaczające \"żenię\". Kobieta jest Ayala.</p>", "Erich": "<b>Eryk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Nadawane wielu jarlom i królom <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">szwedzkim</a> i <a href=\"https://pl.wikipedia.org/wiki/Dania\" target=\"_blank\" rel=\"noopener noreferrer\">duńskim</a>. Pochodzenie tego imienia podaje się ze staro-wysoko-niemieckiego, gdzie <b>era</b> znaczy: honor, cześć, oraz <b>richi</b> – bogaty. Całość zaś oznacza osobę zasobną w honor lub władcę, który zaszczytnie króluje. Jego popularność sięga czasów króla szwedzkiego Eryka zmarłego w <a href=\"https://pl.wikipedia.org/wiki/1160\" target=\"_blank\" rel=\"noopener noreferrer\">1160</a>. Inne spotykane znaczenie to „wieczny władca” od <i>ei(r)</i> co oznacza w staronordyjskim „wieczny” i <i>ríkr</i> – w staronordyjskim „władca”.", "Emin": "<p>Emin Araz ogle Agalarów (azerb. Emin Araz, syn Ağalarov; rod.</p>", "Eugeniu": "<p>Eugene jest powszechnym męskim imieniem, które pochodzi od greckiego εὐγενής (eugenēs), \"noble\", dosłownie \"dobrze urodzony\", od ε ⁇ (eu), \"dobrze\" i γένος (genos), \"rasy, pochodzenia, krewnych\". Gene to powszechne skrócenie.</p>", "Evgheni": "<p>Eugene jest powszechnym męskim imieniem, które pochodzi od greckiego εὐγενής (eugenēs), \"noble\", dosłownie \"dobrze urodzony\", od ε ⁇ (eu), \"dobrze\" i γένος (genos), \"rasy, pochodzenia, krewnych\". Gene to powszechne skrócenie.</p>", "Enzo": "<b>Wincenty</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>vincens</em> – zwyciężający) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>.", "Enrico": "<p>Enrico (italicki: Enrico; 1020, Kazale-Monferrato, Markgrafstwo Monferrato - 14 marca 1045, Kazale-Monferrato) - markgraf Monferrato z domu Aleramici.</p>", "Eren": "<p>Eren to tureckie imię, które w dzisiejszym tureckim oznacza \"Święty\". Według Mahmudu al-Kashgari jest to liczba wielokrotna słowa \"er\" z dodatkiem wielokrotnie \"-a\".</p>", "Eugene": "<p>Kim Yoo-jin (ur. 3 marca 1981), znana z imieniem Eugene, jest koreańską aktorką, piosenkarką i programistą, znana jako członek S.E.S. Jako solowy piosenkarz Eugene wydał dwa solo albums i obecnie koncentruje się na karierze w wielu koreańskich filmach i telewizjach, a także jako programista w wielu programach...</p>", "Evghenii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Evgheni</b>.</p><p>Eugene jest powszechnym męskim imieniem, które pochodzi od greckiego εὐγενής (eugenēs), \"noble\", dosłownie \"dobrze urodzony\", od ε ⁇ (eu), \"dobrze\" i γένος (genos), \"rasy, pochodzenia, krewnych\". Gene to powszechne skrócenie.</p>", "Evgeny": "<p>Yevgeni (rosyjski: Евгений), również przetransliterowany jako Yevgeny, Yevgenii, Yevgeniy, Evgeniy, Yewgeny, Evgenii, Evgenii, Evgenyi lub Evgenij, jest rosyjską formą męskiego imienia Eugene. Krótka forma jest Zhenya (Женя), również przetłumaczana jako Jenya lub Shenya.</p>", "Ernst": "<p>Gustaw Adolph Ernst (niem. Gustav Adolf Ernst, hiszpański.</p>", "Eli": "<p>Elizabeth Martínez García (hisz. Elisabet Martínez Garcia), znana również jako Eli Martinez (hisz.,</p>", "Erhard": "<b>Erhard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>era</i> - \"honor\", lub \"respekt\" i <i>hard</i> - \"dzielny\".", "Eustachy": "<b>Eustachy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, którego znaczenie można objaśnić jako „kwitnący”, „płodny”. Imię to nosił męczennik <a href=\"https://pl.wikipedia.org/wiki/Eustachy_Rzymski\" target=\"_blank\" rel=\"noopener noreferrer\">Eustachy Rzymski</a>, święty Kościoła katolickiego i prawosławnego.", "Egon": "<b>Egon</b> – imię męskie, alternatywna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Egbert_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Egbert</a>.", "Erazm": "<b>Erazm</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „miły”, „uprzejmy”. W dawnych źródłach mazowieckich Erazm pojawia się jako zamiennik męskiego imienia słowiańskiego <i><b><a href=\"https://pl.wikipedia.org/wiki/Niemir\" target=\"_blank\" rel=\"noopener noreferrer\">Niemierza</a></b></i>.", "Elvis": "<b>Elvis</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskiego</a> <i>Eall-wis</i>, czyli <i>mądrego</i>. Staroangielskie akcentowane „a” często przechodzi w „e”, a więc <i>Alvis</i> → <i>Elvis</i>. Czasami w wyjaśnieniach <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a> imienia alternatywne podaje się, że pochodzi ono od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska</a> <i>Elwes</i>, a wiążąc ją z nazwą <i>Alwyn</i>.", "Elliot": "<p>Daniel Giraud Elliot (ang. Daniel Giraut Elliot, 1835 - 1915) - amerykański zoolog, ornitolog, artysta, pracownik muzeum, jeden z założycieli Amerykańskiego Muzeum Historii Naturalnej w Nowym Jorku, Zowęzowego Towarzystwa Francji i współzałożyciel Amerykańskiej Unii Ornitologicznej.</p>", "Eitan": "Eitan został przedstawiony jako następca używanego obecnie w izraelskiej armii zmodyfikowanego, <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">amerykańskiego</a> transportera <a href=\"https://pl.wikipedia.org/wiki/M113\" target=\"_blank\" rel=\"noopener noreferrer\">M-113 Zelda</a>, a także kołowy odpowiednik transportera gąsienicowego <a href=\"https://pl.wikipedia.org/wiki/Namer\" target=\"_blank\" rel=\"noopener noreferrer\">Namer</a>.", "Elguja": "<p>Elguja (georgijski: ელგუჯა) to gruzińskie imię męskie, które może odnosić się do następujących znaczących osób: Elguja Amashukeli (1928-2002), gruziński rzeźbiarz i malarz Elguja Burduli (1941-2022), radziecki i gruziński aktor filmowy Elguja Gugushvili (ur. 1946), gruziński menedżer piłki nożnej i były gracz Elguja Guvazava (ur. 1952), gruzijski polityk Elguja Khintibidze (ur. 1937), gruzianski filolog Elguja Lobjanidze (ur., 1992), gruzi...</p>", "Evgeniy": "<p>Yevgeni (rosyjski: Евгений), również przetransliterowany jako Yevgeny, Yevgenii, Yevgeniy, Evgeniy, Yewgeny, Evgenii, Evgenii, Evgenyi lub Evgenij, jest rosyjską formą męskiego imienia Eugene. Krótka forma jest Zhenya (Женя), również przetłumaczana jako Jenya lub Shenya.</p>", "Elijah": "<p>Elija (Hebrajski: אֱלִיָּהוּ, Eliyahu, co oznacza \"Bóg jest Jakuba\") lub Elias (Grzecki: Ηλίας Elías; Cyryjski: ⁇ Elyāe; Arabski: Elias lub Elia, Ilyās lub Ilyā) był prorokiem żyjącym w północnym Królestwie Izraela (Samarii) w czasach Ahaba (9 wieku pne), według Księgi Królów. Według Księgi Królów, Eliasz bronił czci Jahwe zamiast bałga.</p>", "Eliezer": "Jego imię znaczy „Bóg mego ojca był dla mnie pomocą”. Główny sługa <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>, który miał po nim dziedziczyć, gdy Abraham nie miał potomka. Najprawdopodobniej to Eliezerowi powierzono misję udania się do <a href=\"https://pl.wikipedia.org/wiki/Mezopotamia\" target=\"_blank\" rel=\"noopener noreferrer\">Mezopotamii</a> po żonę dla <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>.", "Eliot": "<b>Eliot</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Eliyahu</i>, oznaczającego <i>„Mój Bóg jest Panem”</i>.", "Eugenio": "<p>Eugenio - IX-wieczny czynnik kościelny, biskup cardinalis Ostii z 878 roku. Uczestniczył w synodzie 879 roku w Rzymie, następnie był na katedrze w Konstantynopolu.</p>", "Elmir": "<p>Elmir to bosniackie imię męskie. Na Bałkanach Elmir jest popularny wśród bosniaków z dawnych państw jugosłowiańskich.</p>", "Ezra": "<p>Étra (; hebrajskie: עֶזְרָא, 'Ezrā; 480-440 p.n.e.), znany również jako Mistrz Eter (עֶזְرָא הַסּוֹפֵר, Ezra ha-Sofer) i Kapłan Eter w Księdze Eter, był żydowskim uczonym (soferem) i kapłanem (kohenem). W języku hebrajskim jest to Ezdras (Grzeczyński: ας).</p>", "Elian": "Do jego głównych dzieł należą: <i>De natura animalium</i> (<i>Περὶ ζῴων ἰδιότητος</i>) i <i>Varia historia</i> (<i>Ποικίλη ἱστορία</i>) czyli <i>O właściwościach zwierząt</i> i <i>Opowiastki rozmaite</i>. Pierwsze to opowieści o niezwykłych cechach i zaletach zwierząt, zawarte w 17 księgach, drugie to ujęte w 14 księgach anegdoty historyczne i przyrodnicze pochodzące z zaginionej literatury wcześniejszej. Oprócz szerokiej wiedzy tematycznej dają one wgląd w zakres poznania świata grecko-rzymskiego. Elian jest ponadto autorem zbioru 20 utworów <a href=\"https://pl.wikipedia.org/wiki/Epistolografia\" target=\"_blank\" rel=\"noopener noreferrer\">epistolarnych</a>, zatytułowanego <i>Listy wieśniaków</i> (<i>Epistulae rusticae</i>, gr. <i>Ἐπιστολαὶ ἀγροικικαί</i>), mającego szczególną wartość dzięki licznym cytatom z niezachowanych dzieł starszych autorów. Za zaginione uważa się jego niektóre pisma o charakterze filozoficznym (np. o opatrzności) oraz <a href=\"https://pl.wikipedia.org/wiki/Pamflet\" target=\"_blank\" rel=\"noopener noreferrer\">pamflet</a> na Heliogabala.", "Emi̇r": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emira</b>.</p><p>Emir (; arabski: أمير ʾAmīr [ʔæˈmiːr]), czasami przenoszony do Amir, Amier lub Ameer, jest szlachectwem lub szlachetnym urzędnikiem używanym w wielu regionach w krajach Arabskich. Dosłownie oznacza to dowódca, generał, król lub król.</p>", "Edouard": "<p>Édouard to zarówno francuskie imię i nazwisko, co jest równoważne Edward w języku angielskim. Wśród znanych osób z tego nazwiska są: Édouard Balladur (ur. 1929), francuski polityk Édouard Bizimana (ur. 1968), burundyjski dyplomat i polityk Éduard Boubat (1923-1999), francuski fotograf Édouard Colonne (1838-1910), francuski dyrygent Édouard Daladier (1884-1970), francuski premier na początku II wojny światowej Edouard Drumont (1844-1917), francuski...</p>", "Eberhard": "<b>Eberhard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Powstało z od połączenia starogermańskich słów <i>eber</i> – \"dzik\" i <i>hard</i> – \"dzielny\".", "Elman": "<p>Elman Elman oglę Zaynalowa (azerb. Elman Elman syn Zeynalov; rod.</p>", "Elizeusz": "<b>Elizeusz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֱלִישָׁע‎&#8206; – <i>Elišaʿ</i> lub <i>ʾĔlîšaʿ</i> oznaczające „<i>Bóg wybawił; Bóg jest wybawieniem</i>”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_cerkiewnos%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">cs.</a>&#160;Елисей) – <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a> <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijny</a>, uczeń <a href=\"https://pl.wikipedia.org/wiki/Eliasz\" target=\"_blank\" rel=\"noopener noreferrer\">Eliasza</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ci_i_b%C5%82ogos%C5%82awieni_Ko%C5%9Bcio%C5%82a_katolickiego\" target=\"_blank\" rel=\"noopener noreferrer\">święty katolicki</a> i <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ci_prawos%C5%82awni\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławny</a>, wspominany w wielu innych <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bcio%C5%82y_wschodnie\" target=\"_blank\" rel=\"noopener noreferrer\">Kościołach wschodnich</a>.", "Edison": "<p>Thomas Alva Edison (11 lutego 1847 - 18 października 1931) był amerykańskim wynalazcą i przedsiębiorcą, który opracował wiele urządzeń, które miały duży wpływ na życie w 20 wieku. Był nazywany \"Majsterem Czarownic Menlo Park\" przez dziennikarza. Był jednym z pierwszych wynalazców, którzy zastosowali zasady produkcji w procesie twórczym.</p>", "Elliott": "<p>Stephen Elliott (ang. Stephen Elliott; 1771 - 1830) - amerykański botanik i algolod, ojciec botanik południowych Stanów Zjednoczonych.</p>", "Emad": "<p>Emad (tzw. Imad, Imed i Aimad; arabski: عماد) to arabskie męskie imię i nazwisko i oznacza \"podtrzymałość\" lub \"filarz\". W co ufają.</p>", "Efraim": "Młodszy z dwóch synów <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Józefa</a> i <a href=\"https://pl.wikipedia.org/wiki/Asenat\" target=\"_blank\" rel=\"noopener noreferrer\">Asenat</a>, urodzony w <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie</a>. <a href=\"https://pl.wikipedia.org/wiki/Jakub_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Jakub</a> zaadoptował Efraima, swego wnuka, i swoje błogosławieństwo dał jemu, a nie jego starszemu bratu <a href=\"https://pl.wikipedia.org/wiki/Manasses_(syn_J%C3%B3zefa)\" target=\"_blank\" rel=\"noopener noreferrer\">Manassesowi</a>. Początkowo miał dziewięciu synów: Szutelacha, Bereda, Tachata, Eleadę, Tachata, Zabada, Szutelacha, Ezera oraz Eleada. Wszyscy oni zostali jednak zabici. Po tym wydarzeniu urodził się jeszcze tylko jeden syn Efraima, a imię, które zostało mu nadane, to Beria. Od Efraima wywodzi się ważne pokolenie. Prorocy nazywają czasem jego imieniem <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izrael</a>. Pojawia się w <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księdze Rodzaju 41, 52; 48</a>.", "Elio": "<p>Elio: Elio (multfilm) - amerykański komputerowo-animowy, naukowo-fantastyczny film przygodowy z 2025 roku, realizowany przez studia Walt Disney Pictures i Pixar Animation Studios.</p>", "Eustachiusz": "<b>Eustachiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słów <i>eu</i> \"dobrze\" oraz <i>stáchys</i> \"owoc\", sens imienia można objaśniać jako \"płodny, kwitnący\". Oboczna męska forma: <a href=\"https://pl.wikipedia.org/wiki/Eustachy\" target=\"_blank\" rel=\"noopener noreferrer\">Eustachy</a>.", "Ekspedyt": "<b>Ekspedyt</b>, <b>Wierzyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od czasownika <em>expediō, expedīre</em> („uwolnić, wyzwolić z więzów”), <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>expedītus</em> znaczy „uwolniony, lekko ubrany, lekkozbrojny; szybki, zwinny”. Imię to zostało w Polsce przetłumaczone jako <b>Wierzyn</b> („ten, któremu można wierzyć”). Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Ekspedyt\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Ekspedyt</a>.", "Emiliusz": "<b>Emil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a> (<i>Aemilius</i>). Łacińskie słowo <i>aemulor</i> oznacza „rywalizujący”. Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Emil_z_Kordoby\" target=\"_blank\" rel=\"noopener noreferrer\">Emil z Kordoby</a> (†852), męczennik i święty katolicki wspominany 15 września.", "Eden": "<p>Eden (francuski: Eden)  Eden, angielski.</p>", "Edvin": "<p>Edvin to imię męskie. Na Bałkanach Edwin jest popularny wśród Bosniaków i Chorwackich w dawnych krajach Jugosławii.</p>", "Elisei": "<p>Yelisey, Yelisei, Elisey lub Elisei (rosyjski: Елисей) to rosyjskie męskie imię rosyjskiego równoważne z Elizeem; jest to również okazjonalne nazwisko. Nazwa może odnosić się do następujących znaczących osób: Elisey (Ganaba) (ur. 1962), arcybiskup diecezji Hadagi i Holandii Kościoła Prawosławnego Rosyjskiego Elisei Morozov (1798-1868), rosyjski przedsiębiorca Elisey Mysin (ur. 2010), rosyjskie pianista, kompozytor, dzieckiem cudzołóstwowym i aktor...</p>", "Emeka": "<p>Chukwuemeka Odumegwu Ojukwu (z angielskiego i igbo Chukwuemeka Ojukwu 4 listopada 1933, Zungгеру, Brytyjska Kolonia Nigerii - 26 listopada 2011, London, Wielka Brytania) znany również pod przyjemnym nazwaem Emeka (z nigerijskiego imienia Igbo Emeka) - nigeryjski polityk i wojskowy, twórca częściowo uznanego państwa Biafra w czasie wojny domowej w Nigerii.</p>", "Elmer": "<p>Adolph Daniel Edward Elmer (ang. Adolph Daniel Elmer; 1870 - 1942) - amerykański botanik i pterydołóg.</p>", "Edinson": "<p>Edinson to męskie imię. Znani ludzie z nazwiskiem to: Edinson Cavani (ur. 1987), uruguajski piłkarz Édinson Rentería (ur. 1968), kolumbijski piłka baseball Edinson Vólquez (ur. 1983), piłka baseballu w Republice Dominikany</p>", "Ewan": "<p>Ewan (zwany również Awan, Euan, Ewen, Awen, Awanne, Owan, Avan) jest szkocką nazwą z wieloma źródłami. Jest to zwykle anglicyzacja szkockiego gaelickiego imienia Eòghann \"odrodzony szlachetny\" i dlatego ostatecznie pochodzi z łacińskiego Eugenius.</p>", "Emerson": "<p>Emerson - nazwisko, nazwisko i toponim.</p>", "Elwis": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elvis</b>.</p><b>Elvis</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskiego</a> <i>Eall-wis</i>, czyli <i>mądrego</i>. Staroangielskie akcentowane „a” często przechodzi w „e”, a więc <i>Alvis</i> → <i>Elvis</i>. Czasami w wyjaśnieniach <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a> imienia alternatywne podaje się, że pochodzi ono od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska</a> <i>Elwes</i>, a wiążąc ją z nazwą <i>Alwyn</i>.", "Elia": "<p>Elia Group - belgijska firma, która jest operatorem linii przesyłania energii elektrycznej o wysokiej napięciu. Pracuje w Belgii (Elia Transmission Belgium) i Niemczech (50Hertz Transmission), pod jej kierownictwem znajduje się również interkonektor Nemo Link między Belgią a Wielką Brytanią.</p>", "Ernestyn": "<b>Ernest</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego \"powaga, zapał, walka\". Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Ernest_z_Zwiefalten\" target=\"_blank\" rel=\"noopener noreferrer\">Święty Ernest</a> - opat i <a href=\"https://pl.wikipedia.org/wiki/M%C4%99czennicy_chrze%C5%9Bcija%C5%84scy\" target=\"_blank\" rel=\"noopener noreferrer\">męczennik</a> (zginął w 1148 roku).", "Eko": "<b>Eko</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>) – w japońskim <a href=\"https://pl.wikipedia.org/wiki/Buddyzm\" target=\"_blank\" rel=\"noopener noreferrer\">buddyzmie</a> ofiarowanie zasług recytowane po śpiewach jednej lub kilku <a href=\"https://pl.wikipedia.org/wiki/Sutra\" target=\"_blank\" rel=\"noopener noreferrer\">sutr</a> albo <a href=\"https://pl.wikipedia.org/wiki/Dharani\" target=\"_blank\" rel=\"noopener noreferrer\">dharani</a>. Eko dosłownie oznacza \"zwrot w kierunku\" i jest ofiarowaniem <a href=\"https://pl.wikipedia.org/wiki/Pole_zas%C5%82ug\" target=\"_blank\" rel=\"noopener noreferrer\">zasług</a> zyskanych poprzez <a href=\"https://pl.wikipedia.org/wiki/Samadhi\" target=\"_blank\" rel=\"noopener noreferrer\">samadhi</a> śpiewu <a href=\"https://pl.wikipedia.org/wiki/Sutra\" target=\"_blank\" rel=\"noopener noreferrer\">sutr</a> i <a href=\"https://pl.wikipedia.org/wiki/Dharani\" target=\"_blank\" rel=\"noopener noreferrer\">dharani</a> wszystkim <a href=\"https://pl.wikipedia.org/wiki/Budda\" target=\"_blank\" rel=\"noopener noreferrer\">buddom</a>, <a href=\"https://pl.wikipedia.org/wiki/Bodhisattwa\" target=\"_blank\" rel=\"noopener noreferrer\">bodhisattwom</a>, <a href=\"https://pl.wikipedia.org/wiki/Patriarcha\" target=\"_blank\" rel=\"noopener noreferrer\">patriarchom</a> oraz innym <a href=\"https://pl.wikipedia.org/wiki/Czuj%C4%85ce_istoty\" target=\"_blank\" rel=\"noopener noreferrer\">czującym istotom</a>.", "Eliyahu": "<p>Eliahu lub Eliyahu (Hebrajskie: אליהו) jest męskie hebrajskie imię biblijnego pochodzenia. Oznacza to \"Mój Bóg jest Jahwe\" i pochodzi od proroka Eliasza, który według Biblii żył w okresie panowania króla Ahaba (9. w. p.n.e.).</p>", "Eckhard": "<b>Ekhard</b>, <b>Jakert</b>, <b>Eghard</b>, <b>Ekard</b>, <b>Ekehard</b>, <i><b>Hekard</b></i>, <i><b>Hekehard</b></i>, <i><b>Hekhard</b></i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, występujące w Polsce od średniowiecza. Pierwszy człon tego imienia najprawdopodobniej oznacza „ostrze, szpica”, a jego forma podstawowa to <i>eg(g)i</i>, <i>ek(k)i</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gocki\" target=\"_blank\" rel=\"noopener noreferrer\">goc.</a> <i>Agja</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starosakso%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">stsas.</a> <i>eggia</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>egga</i>, <i>ecka</i> — „kąt, kant, ostrze jakiejś broni, miecz”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">śrwniem.</a> <i>ecke</i>, <i>egge</i> — „ostrze broni, kąt, kant”); może być to jednak także <i>egi</i> (goc. <i>agis</i>, stwniem. <i>āgi</i>, <i>ēgi</i> — „strach, trwoga”). Drugi człon to <i>hart</i>, <i>hard</i> — „silny, mocny, krzepki, dzielny”. Imię to było w Polsce zapisywane w formach wymienionych powyżej. Możliwe zdrobnienia: Hekiel, Hekosz.", "Eyüp": "<p>Eyüp jest dzielnicą w prowincji Istanbul w Turcji. Ogromnie obszarzyła 224 km2 i liczba ludności w 2007 roku wynosiła 325532 osób, a jego gęstość 1453 osób/km2.</p>", "Efrem": "<b>Efrem</b>, <b>Efraim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego słowa <i>Ephrayim</i> oznaczającego „przynoszący dobry owoc”. W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> był synem Józefa i <a href=\"https://pl.wikipedia.org/wiki/Asenat\" target=\"_blank\" rel=\"noopener noreferrer\">Asenat</a>, twórcą jednego z plemion Izraela. Ogłoszono siedmiu świętych o tym imieniu.", "Edik": "<p>Edik to męskie imię. Wśród znanych osób z nazwiskiem są: Edik Baghdasaryan, armenijski dziennikarz Edik Korchagin (ur. 1979), rosyjski piłkarz Edik Sajaia (ur. 1981), gruziński piłkarzek</p>", "Edgard": "<p>Edgard może odnosić się do następujących: Edgard, Louisiana Edgard Félix Pierre Jacobs, belgijski twórca i pisarz komiksu Edgard Lévy, francuski żydowski bojownik oporu Edgard Varèse, francuski kompozytor</p>", "Efrain": "<p>Efraín to hiszpańskie imię męskie, krewny Efraima. Znani ludzie z nazwiska to: Efrain Chacurian (1924-2019), argentyński urodzony naturalny amerykański piłkarz Efraín Cortés (urodzony 1984), kolumbijski obrońca Efraín Escudero (urodzona 1986), meksykański walczyciel w mieszanych sztuk walki Efraín Flores (urodzono 1958), meksykański menedżer piłki nożnej Efraín Forero Triviño (1932-2022), kolumbijskie rower Efraín Goldenberg (1929-2025), peruwiański...</p>", "Emeryk": "<b>Emeryk</b>, Amalaryk, Amalryk – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze starogermańskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Amalaryk\" target=\"_blank\" rel=\"noopener noreferrer\">Amalaryk</a>, oznaczającego „władca <a href=\"https://pl.wikipedia.org/wiki/Amalowie\" target=\"_blank\" rel=\"noopener noreferrer\">Amalów</a>” (Amalowie według gockiej legendy to ród królewski pochodzenia boskiego). Człon <i>amal</i> może także oznaczać „gorliwy” lub „dzielny, aktywny”. Emeryk może wywodzić się również z saksońskiego <i>Emmerich</i>, oznaczającego „zawsze bogaty”.", "Efim": "<p>Efim to imię, które można również pisać jako Jefim. Pochodzi od greckiej nazwy Euthymios (Εὐθύμιος; współczesne greckie wymowa: [efθimios]; latynistyczna jako Euthymis).</p>", "Elbek": "<p>Elbek to uzbekska męska nazwa. Wśród znanych osób z nazwiskiem: Elbek Sultonov (ur. 1995), uzbekski sportowca paraolimpijski Elbek Tazhyieu (ur. 1986), białoruski grecko-rzymski walczyk</p>", "Elyas": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elias</b>.</p><p>Eliusz Aleksanderski (w części źródeł Elias, grecki ⁇ λίας) - późnoantyczny grecki filozof-neoplatonik VI wieku n.e.</p>", "Elmin": "<p>Elmin to imię męskie. Na Bałkanach Elmin jest popularny wśród bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Evren": "<p>Evren jest dzielnicą w prowincji Ankara w Turcji. Ogromnie obszarzyła 180 km2 i liczba ludności w 2007 roku wynosiła 4027 osób, a jego gęstość wynosi 22 osoby/km2.</p>", "Ezekiel": "<p>Jeffrey Daniel Shullo (ang. Jeffrey Daniel Sciullo, rodzaj.</p>", "Elbrus": "<p>⁇ Elbrus ⁇ - architektura procesorowa i jednorzędna rodzina uniwersalnych VLIW-mikroprocesorów, opracowywanych przez rosyjską firmę MЦСT przy udziale INEUM, kontynuując rozwój technologii procesorowych sowieckich kompleksów obliczeniowych ⁇ Elbrus ⁇ .</p>", "Erwan": "<p>Erwan to męskie imię bretonskie, czasami pisowane Erwann. Jego franczyzacja jest francuską nazwą Yves.</p>", "Earl": "<b>Earl</b> – najstarszy i pierwotnie najwyższy <a href=\"https://pl.wikipedia.org/wiki/Anglia\" target=\"_blank\" rel=\"noopener noreferrer\">brytyjski</a> tytuł <a href=\"https://pl.wikipedia.org/wiki/Feudalizm\" target=\"_blank\" rel=\"noopener noreferrer\">feudalny</a>, następnie arystokratyczny. Samo słowo wywodzi się ze skandynawskiego <b><a href=\"https://pl.wikipedia.org/wiki/Jarl\" target=\"_blank\" rel=\"noopener noreferrer\">jarl</a></b> (pierwotnie znaczyło to po prostu <i>człowiek możny</i>, <i>potężny</i>, <i>bogaty</i>, później było tytułem wodzów drużyny zbrojnej, namiestników królewskich, zarządców prowincji. W <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a> w <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">Szwecji</a> był to tytuł najwyższego urzędnika państwa). <a href=\"https://pl.wikipedia.org/wiki/Encyklopedia_Britannica\" target=\"_blank\" rel=\"noopener noreferrer\">Encyclopædia Britannica</a> wywodzi ten tytuł również od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starofrancuski\" target=\"_blank\" rel=\"noopener noreferrer\">starofrancuskiego</a> <i>eorl</i>, oznaczającego <i>szlachcica</i>, <i>wojownika</i>. Wprowadzony w <a href=\"https://pl.wikipedia.org/wiki/Anglia\" target=\"_blank\" rel=\"noopener noreferrer\">Anglii</a> w <a href=\"https://pl.wikipedia.org/wiki/XI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XI w.</a> po najeździe duńskim w miejsce wcześniej używanego tytułu <a href=\"https://pl.wikipedia.org/wiki/Ealdorman\" target=\"_blank\" rel=\"noopener noreferrer\">Ealdormana</a>. Kontynentalnym odpowiednikiem earla jest <i><a href=\"https://pl.wikipedia.org/wiki/Hrabia\" target=\"_blank\" rel=\"noopener noreferrer\">hrabia</a></i> (tłumaczony w jęz. ang. jako <i>count</i>, <i>counte</i>).", "Eliott": "<p>Elliot (zwany również Eliot, Elliotte, Elliott, Eliott i Elyot) jest nazwiskiem osobistym, które może służyć jako nazwisko lub imię. Chociaż w historii nazwisko to było nadawane mężczyznom, w Stanach Zjednoczonych nazwisko to coraz częściej nadawano kobietom.</p>", "Eithan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eitan</b>.</p>Eitan został przedstawiony jako następca używanego obecnie w izraelskiej armii zmodyfikowanego, <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">amerykańskiego</a> transportera <a href=\"https://pl.wikipedia.org/wiki/M113\" target=\"_blank\" rel=\"noopener noreferrer\">M-113 Zelda</a>, a także kołowy odpowiednik transportera gąsienicowego <a href=\"https://pl.wikipedia.org/wiki/Namer\" target=\"_blank\" rel=\"noopener noreferrer\">Namer</a>.", "Eliahu": "<p>Eliahu lub Eliyahu (Hebrajskie: אליהו) jest męskie hebrajskie imię biblijnego pochodzenia. Oznacza to \"Mój Bóg jest Jahwe\" i pochodzi od proroka Eliasza, który według Biblii żył w okresie panowania króla Ahaba (9. w. p.n.e.).</p>", "Ehab": "<p>Ehab to męskie imię i nazwisko pochodzące z arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Ertuğrul": "<p>Ertoğrul lub Ertuğrul Ghazi (1198 w Ahlat - 1281 Sögüt) był ojcem Osman Bey, założyciela Imperium Ottomskiego. Ertuğrul był przywódcą plemienia Kayı z Oghuzów.</p>", "Evans": "<p>Howard Evans (ang. Howard Ensign Evans; 23 lutego 1919 - 18 lipca 2002) - amerykański entomolog, paleontolog, gimenopterolog, duży specjalista od żałowanych przeponczołków (osów), który opisał ponad 800 nowych dla nauki gatunków.</p>", "Ebrahim": "<p>Ibrahim (arabski: إبراهيم, Ibrāhīm; również anglicized jako Ibraheem) jest arabskim imieniem Abrahama, wspólnego hebrajskiego patriarchy religii abrahamicznych, w tym judaizmu, chrześcijaństwa i islamu. Jest to powszechne męskie imię i nazwisko wśród muzułmanów i arabskich chrześcijan, pochodzące od imienia Abrahama lub Avram w judaizmie i chrześcijaństwie na Bliskim Wschodzie.</p>", "Elisey": "<p>Yelisey, Yelisei, Elisey lub Elisei (rosyjski: Елисей) to rosyjskie męskie imię rosyjskiego równoważne z Elizeem; jest to również okazjonalne nazwisko. Nazwa może odnosić się do następujących znaczących osób: Elisey (Ganaba) (ur. 1962), arcybiskup diecezji Hadagi i Holandii Kościoła Prawosławnego Rosyjskiego Elisei Morozov (1798-1868), rosyjski przedsiębiorca Elisey Mysin (ur. 2010), rosyjskie pianista, kompozytor, dzieckiem cudzołóstwowym i aktor...</p>", "Edo": "<p>Edo (江 (え) 戸 (ど) (Giang Hộ), Edo (co oznacza \"drzwi rzeki\", wymawiające w języku wietnamskim jako Edo) również pisane jako Yedo lub Yeddo, jest starożytnym nazwiskiem stolicy Japonii, tj. dzisiejszej Tokio. Ludzie byli w okolicy Zatoki Tōkyō na wieki, ale w literaturze dopiero w 15 wieku było wspomniane o Edo, gdy Ōta Dōkan założyła Edo w 1457 roku.</p>", "Egbert": "<b>Egbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia germańskiego. Oznacza „błyszczący jak miecz”. Jego patronem jest <a href=\"https://pl.wikipedia.org/wiki/Egbert_(%C5%9Bwi%C4%99ty)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Egbert</a>, <a href=\"https://pl.wikipedia.org/wiki/Benedyktyni\" target=\"_blank\" rel=\"noopener noreferrer\">benedyktyn</a> z przełomu VII i VIII w. <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>", "Ellis": "<p>Job Bicknell Ellis (ang. Job Bicknel Ellis; 1829 - 1905) - amerykański mikolog.</p>", "Eloy": "<p>Eloy to niemiecki zespół progresywnego/spazowego rocka. Nazwa grupy pochodzi z fantastycznego powieści Gerberta Welssa ⁇ Maszyna czasu ⁇ , gdzie ⁇ eloi ⁇ - to nazwa jednej z ras ludzi w dalekiej przyszłości.</p>", "El Mehdi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Eyyüp": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eyüp</b>.</p><p>Eyüp jest dzielnicą w prowincji Istanbul w Turcji. Ogromnie obszarzyła 224 km2 i liczba ludności w 2007 roku wynosiła 325532 osób, a jego gęstość 1453 osób/km2.</p>", "Eytan": "<p>Ethan lub Eytan to męskie imię hebrajskiego pochodzenia, które oznacza \"pewne, trwałe, silne i długotrwałe\". Nazwa Etan pojawia się osiem razy w Biblii Hebrajskiej (1 Królów 4:31; 1 Kronik 2:6, 8; 6:42, 44; 15:17, 19; nadpis Psalm 89).</p>", "Elon": "<b>Elon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> אֵילֹן) – postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijna</a>, według <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_S%C4%99dzi%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Sędziów</a> (Sdz 12,11-12) dziesiąty <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziowie_(Biblia)\" target=\"_blank\" rel=\"noopener noreferrer\">sędzia</a> <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a>. Pochodził z plemienia <a href=\"https://pl.wikipedia.org/wiki/Zabulon\" target=\"_blank\" rel=\"noopener noreferrer\">Zebulona</a>, objął rządy po śmierci <a href=\"https://pl.wikipedia.org/wiki/Ibsan\" target=\"_blank\" rel=\"noopener noreferrer\">Ibsana</a>. Panował przez dziesięć lat. Po śmierci został pochowany w Ajjalonie na terytorium Zebulonitów, utożsamianym z Chirbet el-Lon w <a href=\"https://pl.wikipedia.org/wiki/Galilea\" target=\"_blank\" rel=\"noopener noreferrer\">Galilei</a>. Jego następcą został <a href=\"https://pl.wikipedia.org/wiki/Abdon_(s%C4%99dzia)\" target=\"_blank\" rel=\"noopener noreferrer\">Abdon</a>.", "Erych": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Erich</b>.</p><b>Eryk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Nadawane wielu jarlom i królom <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">szwedzkim</a> i <a href=\"https://pl.wikipedia.org/wiki/Dania\" target=\"_blank\" rel=\"noopener noreferrer\">duńskim</a>. Pochodzenie tego imienia podaje się ze staro-wysoko-niemieckiego, gdzie <b>era</b> znaczy: honor, cześć, oraz <b>richi</b> – bogaty. Całość zaś oznacza osobę zasobną w honor lub władcę, który zaszczytnie króluje. Jego popularność sięga czasów króla szwedzkiego Eryka zmarłego w <a href=\"https://pl.wikipedia.org/wiki/1160\" target=\"_blank\" rel=\"noopener noreferrer\">1160</a>. Inne spotykane znaczenie to „wieczny władca” od <i>ei(r)</i> co oznacza w staronordyjskim „wieczny” i <i>ríkr</i> – w staronordyjskim „władca”.", "Ezio": "<b>Aecjusz</b> – męskie imię łacińskie. Prawdopodobnie pochodzi od greckiego słowa αετος (Aetos), znaczącego \"orzeł\".", "Elvir": "<p>Elvir to zarówno imię, jak i nazwisko. Jest to męskie odpowiednik kobiecej nazwy Elvira i ma to samo znaczenie szczęścia, włóczni i prawdy.</p>", "Ebenezer": "<p>Elliott Ebenezer (ang. Ebenezer Elliott; 17 marca 1781, Masbro, Yorkshire and Humber - 1 grudnia 1849, Barnsley, Yorkshire &amp; Humber) - angielski pisarz, poeta i przedsiębiorca.</p>", "Ezdrasz": "<b>Ezdrasz</b> – <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijne</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>. Wywodzi się od hebr. <i>ezrā</i>, <i>ezrāh</i> – „[Bóg jest] pomocą”, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aram.</a> <i>ezrā</i> – „pomoc”. Po raz pierwszy w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> imię to zostało zanotowane w <a href=\"https://pl.wikipedia.org/wiki/XIV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIV wieku</a> w formie <i>Esdras</i>.", "Erdoğan": "<p>Recep Tayyip Erdoğan (ur. 26 lutego 1954) to turecki polityk, obecnie prezydent Turcji. Wcześniej był 25-tym premierem Turcji od 2003 do 2014 roku i burmistrzem Stambułu w latach 1994-1998.</p>", "Eugène": "<p>Edmond Neefs (francuski: Edmond Neifs; 1 kwietnia 1881 r. w Lewen, Brabant - 29 listopada 1949 r. w Loven, Brabant) - belgijski piłkarz, grający na pozycji półobręża, brązowy nagródek letnich igrzysk olimpijskich 1900 r.</p>", "Enoch": "<b>Enoch</b> (lub <b>Henoch</b>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego imienia <i>Chanok</i>, oznaczającego „pełny poświęcenia”.", "Ekene": "<p>Ekene to unisex. Wśród znanych osób z nazwiska są: Ekene Abubakar Adams (1985-2024), nigerijski polityk Ekene Ibekwe (urodzony 1985), amerykańsko-nigerijski piłkarz koszykówki Ekene Ikenwa (urodzona 1977), nigeriński piłkarzek Ekene Obi (urodzono 2003), nigerijska blogerka i farmaceuta Ekene Umenwa (ur. 1991), nigerianska aktorka Ekene Okoli (ur. 1980) Nigerijski dyrektor generalny</p>", "Ervis": "<p>Ervis to albanska męska nazwa i może odnosić się do: Ervis Çaço (ur. 1989), albanski piłkarz. Ervis Kaja (ur. 1987), albanianki piłkarz.</p>", "Eduardi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eduard</b>.</p><p>Edwarda - męskie imię, pochodzące od angielsko-saksońskiego Ēadweard - ⁇ strzeganie bogactwa, szczęścia ⁇ (ead oznacza ⁇ szczęśliwy, kwitnący ⁇ , a weard tłumaczono jako ⁇ strogę ⁇).</p>", "Eros": "<p>W greckiej mityce Eros jest bogiem miłości. Bogi Eros zawsze nosili ze sobą łuk i strzały miłości.</p>", "Erlend": "<p>Erlend może odnosić się do: Erlend Apneseth (ur. 1990), nagradzany hardingfele Erlend Bjøntegaard (ur. 1990, norweski biatleta Erlend Bratland (ur. 1991), norweski piosenkarz Erlend Caspersen (ur. 1982), norweskiego basisty Erlend Engelsvoll (ur. 1975), norweskiego byłego profesjonalnego rowerzystę wyścigowego Erlend Erichsen z Gorgoroth, norweskiego black metal zespołu Erlend Fuglum (ur. 1978), norweska polityka dla Partii Centrum Erlend...</p>", "Eusebio": "<p>Eusébio da Silva Ferreira (portugalski w Europie: [ewˈzɛβju ðɐ ˈsi ⁇ vɐ fɨˈʁɐjɾɐ]; 25 stycznia 1942 - 5 stycznia 2014) był portugalskim piłkarzem, który grał w pozycji piłkarza. Jest uważany za jednego z największych graczy wszechczasów i Benfica.</p>", "Eamonn": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eamon</b>.</p><p>Eamon (czasami spotykana jest również dłuższa nazwa The Wonderful World of Eamon) - gra komputerowa łącząca elementy gry rołowej i kwest, stworzona przez Donalda Browna i wydana dla Apple II w 1980 roku. Gra to tekst, który przypomina wcześniejsze gry, takie jak Adventure (1976) lub Zork (1980), ale zawiera istotne elementy roli, których nie ma w innych przedstawicielach gatunku interaktywnej fikcji.</p>", "Etai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Etay</b>.</p><p>Itai to męskie imię pochodzące z hebrajskiego, a także imię szonowe. Nazwa może być również napisana: Itai, Itahy, Ittai, Ittay, Etay, Eitay, Itay, Ytai, Etai, Itaj, Ithai lub Eatai.</p>", "Emilien": "<p>Émilien to francuskie męskie imię i może odnosić się do: Émilien z Nantes (zmarł około 725), francuski przywódca religijny kanonizowany jako święty Émilien Allard (1915-1977), kanadyjski karillonarz, pianista, klarnetista i kompozytor Émilien Amaury (1909-1977), francuski magnat wydawnictwa Émilien-Benoît Bergès (ur. 1983), francuski rower wyścigowy Émilien Dumas (1804-1873), francuski uczony, paleontolog i geolog Émilien Jacquelin (ur. 1995),...</p>", "Endri": "<p>Endri to głównie albaniańska męska nazwa i może odnosić się do: Endri Bakiu (ur. 1987), albaniański piłkarz Endri Çekiçi (ur. 1996), albaniecki piłkarze Endri Dalipi (ur. 1983), albaniec Endri Dema (ur. 2004), albanski piłkarzem Endri Fuga (ur. 1981), albaniego polityka Endri Hasa (ur. 1981), albaniańskiego polityka, Endri Karina (ur. 1989), albanskiego ciężarosta Endri Muçmata (ur. 1996, albaniacki piłker Endri...</p>", "Enea": "<p>Enea jest ptaszką nocną należącą do rodziny Noctuidae.</p>", "Erjon": "<p>Erjon to albanska męska nazwa. Jest to wariant pisowni Erion, i oznacza \"jonski wiatr\".</p>", "Elyes": "<p>Elyes to imię. To imię i nazwisko następujących osób: Elyes Gabel (ur. 1983), angielski aktor Elyes Fakhfakh, tunyjski polityk Elyes Karamosli (ur. 1989 w Hammam-Lif w Tunisie), tunyjski piłkarz siatkówki Elyes Garfi (ur. 1993), tunyński piłkarze siatkówki</p>", "Elías": "<p>Elías jest samodzielnym terenem w prowincji Huila w Kolumbii. Gmina Elías jest stolicą miasta Elías.</p>", "Evhen": "<p>Yevhen (ukraina: Євге́н [jeu̯ˈɦɛn]), również romanizowany Evhen, jest powszechną ukraińską nazwą, odpowiednią angielskiego Eugenia. Jego starożytny kościół słowiańska forma Evgenii (Евгении) pochodzi od greckiego Eugénios (Εὐγένιος), od przymiotu eugen ⁇ s (εὐγενής), dosłownie \"dobrze urodzony\".</p>", "El": "Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Ermal": "<p>Ermal to albaniańska męska nazwa, co oznacza \"wietr góry\". Do osób z imieniem Ermal to: Ermal Allen (1918-1988), amerykański piłkarz i asystent trener Ermal Bojdani (ur. 1985), albansko-amerykański lekarz, medycynę medycyny awaryjnej i publicznej, naukowiec, nauczyciel medycyiny klinicznej Ermal C.</p>", "Endrit": "<p>Endrit to albanianki nazwa dla chłopców, co oznacza \"światło\". Do wybitnych osób z nazwiskiem należą: Endrit Braimllari (ur. 1988), albański polityk Endrit Hysenagolli (ur. 1988, piłkarz koszykówki Endrit Idrizaj (ur. 1989), albański piłkarze Endrit Karameto (ur. 1995), albański gracz Endrit Shala (ur. 1981), kosowski polityk Endret Vrapi (ur. 1982), albański futbolista Endrit Ferizoli, wykonawca na trollowstance ...</p>", "Elwir": "<b>Elwir</b> – imię męskie, wywodzące się od imienia <a href=\"https://pl.wikipedia.org/wiki/Elwira\" target=\"_blank\" rel=\"noopener noreferrer\">Elwira</a>, jako jego męski odpowiednik.", "Exequiel": "<p>Exequiel to męskie imię. Znani ludzie z nazwiskiem to: Exequiel Benavídez (ur. 1989), argentyński piłkarz Exequiil Javier (ur. 1946), filipiński polityk</p>", "Emilia": "Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Eliel": "<p>Eliel to hebrajskie imię. Na angielski można przetłumaczyć: \"Mój Bóg jest Bogiem\".</p>", "Enock": "<p>Enock to zarówno męskie imię, jak i nazwisko. Nosiciele nazwy są często afrykańskiego pochodzenia.</p>", "Emiro": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emir</b>.</p><p>Emir (; arabski: أمير ʾAmīr [ʔæˈmiːr]), czasami przenoszony do Amir, Amier lub Ameer, jest szlachectwem lub szlachetnym urzędnikiem używanym w wielu regionach w krajach Arabskich. Dosłownie oznacza to dowódca, generał, król lub król.</p>", "Evangelista": "<p>Evangelista - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Ephrem": "<p>Efraim to męskie imię, co jest odmianą pisowni Efraima (także Efrem, Efrem, Efraim, Efren lub Efrén). Jest to biblijna nazwa Efraima, syna Józefa i przodka plemienia Efraima.</p>", "Eka": "<b>Eka</b> – w <a href=\"https://pl.wikipedia.org/wiki/Gwara_pozna%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">gwarze poznańskiej</a> miejska grupa koleżeńska pochodząca z jednej dzielnicy lub okolicy; także powiązana terytorialnie grupa złodziejska.", "Ekard": "<b>Ekhard</b>, <b>Jakert</b>, <b>Eghard</b>, <b>Ekard</b>, <b>Ekehard</b>, <i><b>Hekard</b></i>, <i><b>Hekehard</b></i>, <i><b>Hekhard</b></i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, występujące w Polsce od średniowiecza. Pierwszy człon tego imienia najprawdopodobniej oznacza „ostrze, szpica”, a jego forma podstawowa to <i>eg(g)i</i>, <i>ek(k)i</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gocki\" target=\"_blank\" rel=\"noopener noreferrer\">goc.</a> <i>Agja</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starosakso%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">stsas.</a> <i>eggia</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>egga</i>, <i>ecka</i> — „kąt, kant, ostrze jakiejś broni, miecz”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">śrwniem.</a> <i>ecke</i>, <i>egge</i> — „ostrze broni, kąt, kant”); może być to jednak także <i>egi</i> (goc. <i>agis</i>, stwniem. <i>āgi</i>, <i>ēgi</i> — „strach, trwoga”). Drugi człon to <i>hart</i>, <i>hard</i> — „silny, mocny, krzepki, dzielny”. Imię to było w Polsce zapisywane w formach wymienionych powyżej. Możliwe zdrobnienia: Hekiel, Hekosz.", "Ermir": "<p>Ermir to albanskie imię męskie. Jest to połączenie albanskich słów: erë (wiec) i mirë (dobry).</p>", "Evgueni": "<p>Eugene jest powszechnym męskim imieniem, które pochodzi od greckiego εὐγενής (eugenēs), \"noble\", dosłownie \"dobrze urodzony\", od ε ⁇ (eu), \"dobrze\" i γένος (genos), \"rasy, pochodzenia, krewnych\". Gene to powszechne skrócenie.</p>", "Etan": "<p>Ethan jest związkiem chemicznym z formułą chemiczną C2H6. To jest alkan, czyli niezawierający kręgów.</p>", "Eweryst": "<b>Ewaryst</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, które oznacza <i>miły, przyjemny, najlepszy</i>. Imię to nadawane jest w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII</a> w. Istnieje kilku świętych Ewarystów, m.in. <a href=\"https://pl.wikipedia.org/wiki/Ewaryst_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">Ewaryst, papież</a> oraz św. Ewaryst z Konstantynopola.", "Ennio": "<b>Enniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od nazwy rodu <i>Enniuszów</i>.", "Elis": "<p>Elis - z Lichtenšteinu, utworzony w 2003 roku i wykonujący gotycki metal.</p>", "Emmet": "<p>Emmet (dawniej Zen Coding) - zestaw wtyczek dla edytorów tekstowych, które w pewnym stopniu przyspieszają pisanie kodu HTML, XML, XSL, a także kodu w niektórych innych językach. Projekt został rozpoczęty przez Wadyma Makejewa w 2008 roku i jest aktywnie rozwijany przez Sergeja Chicuenka od 2009 roku, a także przez społeczność użytkowników Zen Coding na podstawie idei Zen Coding 2.0.</p>", "Elder": "<p>Szasy Formuły-1, które uczestniczyły tylko w Indy-500 - to samochody używane przez amerykańskich kierowców do udziału w słynnym wyścigu ⁇ Indianapolis-500 ⁇ w latach 1950 - 1960, kiedy formalnie chodziło do zaliczenia mistrzostwa świata Formuły-1. Na początku historii Formuły 1 przez 11 sezonów (1950 - 1960) słynny amerykański wyścig na autodromie Indianapolis-500 był uważany za etap mistrzostw świata.</p>", "Ed": "gdzie n1, n2 określają wiersz lub zakres wierszy, na których operuje polecenie. Specjalny symbol $ oznacza ostatni wiersz i np. polecenie <b>1,$p</b> spowoduje wyświetlenie wszystkich wierszy.", "Emon": "<p>Emon to bengalijska i japońska nazwa. W obu kulturach może to być zarówno imię, jak i nazwisko.</p>", "Eivind": "<p>Eivind jest norweską nazwą męską pochodzącą z północnych krajów, Auja-winduR. Składa się z dwóch części: Auja oznacza \"szczęśliwy/dar\" i winduR oznacza \"wygrywający i/lub wojownik\".</p>", "Erast": "<b>Erast</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Pochodzi od greckiego imienia <i>Erastus</i> oznaczającego \"miły\". Było imieniem pomocnika <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Pawła</a> wymienionego w <a href=\"https://pl.wikipedia.org/wiki/Dzieje_Apostolskie\" target=\"_blank\" rel=\"noopener noreferrer\">Dziejach Apostolskich</a> <a href=\"https://pl.wikipedia.org/wiki/Erast_z_Koryntu\" target=\"_blank\" rel=\"noopener noreferrer\">Erasta z Koryntu</a>.", "Enej": "<p>Enej - polski zespół muzyczny utworzony w 2002 roku w Ołsztynie przez braci Petra i Pawła Soloducha z ich przyjacielem Lukasem Koirisem. W muzyce Enej można znaleźć elementy rocka, folka, ska, regga i jazzowego.</p>", "Essa": "<p>Essa - zespół krzyżowego rytualnego folkloru z Minsk. Utworzony w 2006 roku przez Todora Kaszkuriewicza.</p>", "Erfan": "<p>Irfan (tzw. Erfan) to arabskie / perskie imię męskie, oznaczające \"wiedzę\", \"świadomość\", \"nauka\" i \"mądrość\".</p>", "Ekhard": "<b>Ekhard</b>, <b>Jakert</b>, <b>Eghard</b>, <b>Ekard</b>, <b>Ekehard</b>, <i><b>Hekard</b></i>, <i><b>Hekehard</b></i>, <i><b>Hekhard</b></i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, występujące w Polsce od średniowiecza. Pierwszy człon tego imienia najprawdopodobniej oznacza „ostrze, szpica”, a jego forma podstawowa to <i>eg(g)i</i>, <i>ek(k)i</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gocki\" target=\"_blank\" rel=\"noopener noreferrer\">goc.</a> <i>Agja</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starosakso%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">stsas.</a> <i>eggia</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>egga</i>, <i>ecka</i> — „kąt, kant, ostrze jakiejś broni, miecz”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">śrwniem.</a> <i>ecke</i>, <i>egge</i> — „ostrze broni, kąt, kant”); może być to jednak także <i>egi</i> (goc. <i>agis</i>, stwniem. <i>āgi</i>, <i>ēgi</i> — „strach, trwoga”). Drugi człon to <i>hart</i>, <i>hard</i> — „silny, mocny, krzepki, dzielny”. Imię to było w Polsce zapisywane w formach wymienionych powyżej. Możliwe zdrobnienia: Hekiel, Hekosz.", "Eike": "<p>Eike to imię i nazwisko męskie, a także żeńskie. Do wybitnych osób z tym nazwiskiem należą:</p>", "Edisson": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Edison</b>.</p><p>Thomas Alva Edison (11 lutego 1847 - 18 października 1931) był amerykańskim wynalazcą i przedsiębiorcą, który opracował wiele urządzeń, które miały duży wpływ na życie w 20 wieku. Był nazywany \"Majsterem Czarownic Menlo Park\" przez dziennikarza. Był jednym z pierwszych wynalazców, którzy zastosowali zasady produkcji w procesie twórczym.</p>", "Emeric": "<p>Emerich, Emeric, Emerick i Emerik są nazwiskami i nazwiską. Mogą one odnosić się do:</p>", "Eriks": "<p>Ēriks jest łacińskim imieniem męskim, które jest krewnym nazwiska Eric, co oznacza \"wieczny władca\". Nazwa może odnosić się do: Ēriks Ešenvalds (ur. 1977), latyjskiego kompozytora Ēriks Grigjans (ur. 1964), lotyjskiego piłkarza Ēriks Koņeckis (1920-2006), lotyjskiej hokejisty lodów Ēriks Mesters (1926-2009), lotyjskie teologa i arcybiskup Ēriks Pelcis (ur. 1978), lotyjski piłkarz Ēriks Pētersons (1909-1987), lotyjski piłkarze i...</p>", "Everest": "<p>AIDA64 to aplikacja do profilowania i testowania wydajności systemu, diagnostyki i audytu, opracowana przez węgierską firmę FinalWire Ltd dla systemów operacyjnych Windows, Android, iOS, ChromeOS, Sailfish OS, Windows Phone, Ubuntu Touch i Tizen. Wyświetla szczegółowe informacje o komponentach urządzenia, które można przechowywać w pliku w formacie takim jak HTML, CSV lub XML.</p>", "Everton": "<p>Everton ma wiele znaczeń.</p>", "Erion": "<p>Erion to albanianskie imię męskie, co oznacza \"wiatr jonijski\", jak wiatr z Morza Jonijskiego. Związane imię to Erjon.</p>", "Ermin": "<p>Ermin to bosniackie imię męskie. Na Bałkanach Ermin jest popularny wśród Bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Eamon": "<p>Eamon (czasami spotykana jest również dłuższa nazwa The Wonderful World of Eamon) - gra komputerowa łącząca elementy gry rołowej i kwest, stworzona przez Donalda Browna i wydana dla Apple II w 1980 roku. Gra to tekst, który przypomina wcześniejsze gry, takie jak Adventure (1976) lub Zork (1980), ale zawiera istotne elementy roli, których nie ma w innych przedstawicielach gatunku interaktywnej fikcji.</p>", "Eliah": "<p>Elias (il-EYE-əs; starożytny grecki: ⁇ λίας, romanizowany: Elías) jest hellenistyczną wersją imienia Eliasza (Hebrajskie: אֵלִיָּהוּ, romanized: ʾĒlīyyāhū; Syriac: ⁇ , romanizewany: Elyāe; Arabskie: إلیاس, romanizes: Ilyās, lub إلیا, Ilyā), proroka w północnym królestwie Izraela w IX wieku p.n.e., wspomniany w kilku świętych ksiągach. Ze względu na rolę Eliasza w Pisma Świętego i wielu późniejszych związanych z nim tradycji, imię jest używane jako imię osobiste...</p>", "Etay": "<p>Itai to męskie imię pochodzące z hebrajskiego, a także imię szonowe. Nazwa może być również napisana: Itai, Itahy, Ittai, Ittay, Etay, Eitay, Itay, Ytai, Etai, Itaj, Ithai lub Eatai.</p>", "Edwin Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Ernes": "<p>Ernes jest gminą w Calvados, w normandzkiej północno-zachodniej Francji.</p>", "Emanoil": "<p>Emanoil to rumuńska męska nazwa i może odnosić się do: Emanoil Bacaloglu (1830-1891), wołachijski i rumuński matematycz, fizyk, chemik, scubadiver itp. Emanoil Badoi (ur. 1975), rumuński piłkarz Emanoil Bârzotescu (1888-1968), rumuński major general podczas II wojny światowej Emanoil Bucuța (1887-1946), rumuńskiego pisarza prozy i poety Emanoil Catelli (1883-1943), mołdawski polityk Emanoil Costacheureanu...</p>", "Erkki": "<p>Erkki to fińskie i estońskie imię (od czerpienia z Erika). Do wybitnych osób z tym nazwiskiem należą:</p>", "Ervand": "<p>Yervand (armeńska: Երվանդ) i w niektórych transliteracjach Ervand (w zachodnim armeńskim Yervant), jest ormińskie imię. Greckim odpowiednikiem jest Orontes.</p>", "Eldin": "<p>Eldin to męskie imię i nazwisko. Na Bałkanach Eldin jest popularny wśród bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Ebi": "<p>Abby (ang. Eby; angielski.</p>", "Eoghan": "<p>Éogan jest wczesnym irlandzkim imieniem męskim, które ma również hipokorystyczne i maleńkie formy Eoganán, Eóghainin, Eóghain i Eóghainn. Nowoczesna irlandzka forma nazwy to Eoghan nɣ]).</p>", "Elamine": "<p>Al-Amin (arabski: الأمين, romanized: al-Amīn, lit. 'zaufany'), również romanized El-Amin, El-Amine lub Al-Ameen i czasami nie zrysowany, jest arabskie męskie nazwisko i nazwisko, pochodzące z tytułu Muhammada.</p>", "Elion": "<p>Elion Ettevõtted AS lub Elion - największy w Estonii usługodawca telekomunikacyjny i internetowy. Należy do Eesti Telekom, która jest reprezentowana na giełdach funduszy Tallinn (ETLAT) i Londynu (EETD).</p>", "El Amine": "<p>Al-Amin (arabski: الأمين, romanized: al-Amīn, lit. 'zaufany'), również romanized El-Amin, El-Amine lub Al-Ameen i czasami nie zrysowany, jest arabskie męskie nazwisko i nazwisko, pochodzące z tytułu Muhammada.</p>", "Elek": "<p>Elek jest miastem w hongijskim hrabstwie Békés. Miasto ma powierzchnię 54,91 km2, liczba ludności w 2010 roku wynosi 4985 osób, a jego gęstość 91 osoby/km2.</p>", "Eemeli": "<p>Eemeli to fińskie imię męskie. Nazwa Eemeli jest podzielona przez następujących osób: Eemeli (prawdziwe imię Esko Toivonen), fiński aktor, komik i rozrywka Eemeli Aakula, fiński polityk Eemeli Heikkinen, fiński profesjonalny hokejista lodowy Eemeli Kouki, fiński piłkarz siatkówki Eemeli Paronen, fiński gospodarz i polityk Emeli Peltonen, fińskiego polityka Eemeli Raittinen, fiński futbolista Eemeli...</p>", "Eyyup": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eyüp</b>.</p><p>Eyüp jest dzielnicą w prowincji Istanbul w Turcji. Ogromnie obszarzyła 224 km2 i liczba ludności w 2007 roku wynosiła 325532 osób, a jego gęstość 1453 osób/km2.</p>", "Eial": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eyal</b>.</p><p>Eyal to hebrajskie imię męskie oznaczające \"żenię\". Kobieta jest Ayala.</p>", "Emer": "Dała mu wiele trudnych zadań do wykonania, bo bardzo chciał spędzić z nią noc. Uważała, że skoro jest bardzo piękna, to jest tego warta. Cuchulainn przystał na jej warunki. W innej wersji, w pochodzącej z <a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">ósmego wieku</a> <i>Bricriu's Feast</i>, została ona ukazana jako żona Cuchulainna o imieniu Eimher Pięknowłosa (ang. <i>Eimher of the Beautiful Hair</i>) i córka Forghalla Zwinnego (ang. <i>Forghall the Dexterous</i>). W tej wersji mitu Cuchulainn ujrzał ją po raz pierwszy w czasie swego pobytu na dworze najwyższego króla Irlandii w Tarze. Ojciec Emer, naczelnik klanu Meathu był przeciwny małżeństwu. Aby się go pozbyć nakazał mu wyruszyć w podróż w celu udoskonalenia rzemiosła wojennego i po jego powrocie miał dopiero rozważyć czy Cuchulainn będzie mógł zostać jego zięciem. Cuchulainn sprostał wyzwaniu i powrócił po rękę dziewczyny. Zanim doszło do zaręczyn bohater musiał przejść jeszcze jedną próbę - zaatakować potężnie ufortyfikowany zamek Fogalla. Emer była zakochana bez pamięci w swoim przystojnym mężu, ale w ich małżeństwie także nie brakowało kłopotów, gdyż ulsterski bohater podobał się wielu kobietom. Przed ostatnią bitwą Cuchulainna z królową <a href=\"https://pl.wikipedia.org/wiki/Medb\" target=\"_blank\" rel=\"noopener noreferrer\">Medb</a>, Emer próbowała przekonać męża aby pozostał w zamku Emain Macha, siedzibie króla <a href=\"https://pl.wikipedia.org/wiki/Conchobar_III_mac_Nessa\" target=\"_blank\" rel=\"noopener noreferrer\">Conchobara MacNessy</a> i nie wyruszał samotnie do boju. Wsiadł na rydwan myśląc ciągle o prośbie swojej ukochanej jednak wrogie mu wiedźmy, córki <a href=\"https://pl.wikipedia.org/wiki/Calatin\" target=\"_blank\" rel=\"noopener noreferrer\">Calatina</a> rzuciły na niego czar, który uniemożliwiał podjęcie mu innej decyzji.", "Esko": "<p>Esko to fińskie męskie imię i nazwisko.</p>", "Eiji": "<b>Eiji</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えいじ, エイジ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Eswara Rao": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eswara</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eswar</b>.</p><p>Eswar może odnosić się do następujących osób: Eswar (1938-2021), projektant reklam w Telugu Eswar Prasad (ur. 1965), indyjski ekonomista Theni Eswar, indyjski kinematograf</p>", "Eetu": "<p>Eetu to imię męskie. Może odnosić się do: Sulo Eetu Jussila (1882-1973), fińskiego polityka i rolnika Eetu Karvinen (ur. 1993), fińskiej hokejistki na lodzie Eetu Koski (ur. 1992), fińskie hokejistka na lodzie eetu Luostarinen (ur., 1998), fińską hokejistkę na lodzie, Eetu Muinonen (ur. 1986), fińskego piłkarza Eetu Pöysti (ur. 1989), fińskę hokejistę na lodzie i Eetu Qvist (ur. 1983), fińskącego hokejistów Johan Edvard Eetu Salin...</p>", "Esmail": "<p>Ismail (arabsko: إسماعيل, romanized: ʾIsmāʿīl) to arabskie imię. Odpowiada angielskiej nazwie Ismael.</p>", "Etem": "<b>Etem</b> (<a href=\"https://pl.wikipedia.org/wiki/Alfabet_deseret\" target=\"_blank\" rel=\"noopener noreferrer\">deseret</a> 𐐀𐐛𐐇𐐣) – w wierzeniach <a href=\"https://pl.wikipedia.org/wiki/Ruch_%C5%9Bwi%C4%99tych_w_dniach_ostatnich\" target=\"_blank\" rel=\"noopener noreferrer\">ruchu świętych w dniach ostatnich</a> (mormonów) <a href=\"https://pl.wikipedia.org/wiki/Jeredyci\" target=\"_blank\" rel=\"noopener noreferrer\">jeredycki</a> król, syn Ahaha. Informacje na jego temat zawiera będąca częścią mormońskiej świętej księgi Księga Etera. Jego panowanie przynależy do późnego okresu jeredyckiej historii. Miało być naznaczone niegodziwością oraz działalnością proroków nawołujących do pokuty, trwało też do śmierci Etema. Władca jest obiektem spekulacji teologicznych, bywa też wykorzystywany przez mormońskich apologetów. Imię Etem występuje wśród wyznających mormonizm <a href=\"https://pl.wikipedia.org/wiki/Maorysi\" target=\"_blank\" rel=\"noopener noreferrer\">Maorysów</a>.", "Emenike": "<p>Emenike to nigerijski męski imię i nazwisko, które mogą odnosić się do: Alexander Emenike Nkume, (ur. 1989), nigerijski piłkarz Emenike Uchenna Mbachu (ur. 1989), nigerijski-ur. piłkarze Emmanuel Emenike (ur. 1987), nigeriński piłkarzem Uzoechi Emenike, angielski piosenkarz znany jako MNEK</p>", "Edwin Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Epifaniusz": "<b>Epifaniusz</b>, <b>Epifani</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „objawienie się, ukazanie się bóstwa”, „ten, który przyszedł na świat”. Jego żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Epifania_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Epifania</a>.", "Elbai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elba</b>.</p><p>Elba jest wyspą wśródziemnomorską w Toskanii, Włochy, oddaloną 20 km (12 mi) od przybrzeżnego miasteczka Piombino. Jako największa z wysp Tuscan, wyspa Elba jest również częścią Parku Narodowego Wysp Toskanych i jest trzecim największym wyspą w Włoszech po wyspach Scylii i Sardenii.</p>", "Eris": "<p>Eris (lat. Eris) - rodzaj pająków araneomorph z podrodzinnia Dendryphantinae w rodzinie pająków-skakuonów (Salticidae). Rodzaj ten jest rozmieszczony od Alaski do Ekwadora.</p>", "Eitel": "<p>Eitel może odnosić się do Eitel Friedrich II, hrabia Hohenzollerna (około 1452-1512) Eitel Friedrich z Zollerna (1454-1490), niemiecki szlachetny i admirał Holandii Eitel Friedrich III, hrabia hohenzollarna (1494-1525) Eitel Friedrich IV, hrabia hoenzollern (1545-1605) Eitel Frederick von Hohenzolllern-Sigmaringen (1582-1625), rzymski katolicki kardynał i księc biskup Osnabrück Książę Eitel Friedrich ze Prusy...</p>", "Edwin Fernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Eliyas": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elias</b>.</p><p>Eliusz Aleksanderski (w części źródeł Elias, grecki ⁇ λίας) - późnoantyczny grecki filozof-neoplatonik VI wieku n.e.</p>", "Elián": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eliane</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elian</b>.</p>Do jego głównych dzieł należą: <i>De natura animalium</i> (<i>Περὶ ζῴων ἰδιότητος</i>) i <i>Varia historia</i> (<i>Ποικίλη ἱστορία</i>) czyli <i>O właściwościach zwierząt</i> i <i>Opowiastki rozmaite</i>. Pierwsze to opowieści o niezwykłych cechach i zaletach zwierząt, zawarte w 17 księgach, drugie to ujęte w 14 księgach anegdoty historyczne i przyrodnicze pochodzące z zaginionej literatury wcześniejszej. Oprócz szerokiej wiedzy tematycznej dają one wgląd w zakres poznania świata grecko-rzymskiego. Elian jest ponadto autorem zbioru 20 utworów <a href=\"https://pl.wikipedia.org/wiki/Epistolografia\" target=\"_blank\" rel=\"noopener noreferrer\">epistolarnych</a>, zatytułowanego <i>Listy wieśniaków</i> (<i>Epistulae rusticae</i>, gr. <i>Ἐπιστολαὶ ἀγροικικαί</i>), mającego szczególną wartość dzięki licznym cytatom z niezachowanych dzieł starszych autorów. Za zaginione uważa się jego niektóre pisma o charakterze filozoficznym (np. o opatrzności) oraz <a href=\"https://pl.wikipedia.org/wiki/Pamflet\" target=\"_blank\" rel=\"noopener noreferrer\">pamflet</a> na Heliogabala.", "Eremia": "<p>Eremia to rumuńska nazwa, która może odnosić się do Danowego imienia Eremia Grigorescu (1863-1919), rumuńskiego generała artylerii Nazwisko Alexandra Eremia (urodzona 1987), rumuńskiej gimnastki artystycznej Alina Eremia (urodzona 1993), rumuński piosenkarz, telewizyjna osobowość i aktorka</p>", "Eswara": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eswar</b>.</p><p>Eswar może odnosić się do następujących osób: Eswar (1938-2021), projektant reklam w Telugu Eswar Prasad (ur. 1965), indyjski ekonomista Theni Eswar, indyjski kinematograf</p>", "El Mahdi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Eulogiusz": "<b>Eulogiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wśród patronów – św. Eulogiusz z <a href=\"https://pl.wikipedia.org/wiki/Tarragona\" target=\"_blank\" rel=\"noopener noreferrer\">Tarragony</a>, diakon, spalony na stosie w <a href=\"https://pl.wikipedia.org/wiki/259\" target=\"_blank\" rel=\"noopener noreferrer\">259</a>, św. Eulogiusz, <a href=\"https://pl.wikipedia.org/wiki/Biskup\" target=\"_blank\" rel=\"noopener noreferrer\">biskup</a> <a href=\"https://pl.wikipedia.org/wiki/%C5%9Eanl%C4%B1urfa\" target=\"_blank\" rel=\"noopener noreferrer\">Edessy</a> (zm. w <a href=\"https://pl.wikipedia.org/wiki/383\" target=\"_blank\" rel=\"noopener noreferrer\">383</a>), św. <a href=\"https://pl.wikipedia.org/wiki/Eulogiusz_z_Kordoby\" target=\"_blank\" rel=\"noopener noreferrer\">Eulogiusz z Kordoby</a>, męczennik, ścięty w <a href=\"https://pl.wikipedia.org/wiki/859\" target=\"_blank\" rel=\"noopener noreferrer\">859</a>, a także św. <a href=\"https://pl.wikipedia.org/wiki/Eulogiusz_Aleksandryjski\" target=\"_blank\" rel=\"noopener noreferrer\">Eulogiusz Aleksandryjski</a>, patriarcha Aleksandrii, zm. w <a href=\"https://pl.wikipedia.org/wiki/608\" target=\"_blank\" rel=\"noopener noreferrer\">608</a>.", "Eugeny": "<p>Eugene jest powszechnym męskim imieniem, które pochodzi od greckiego εὐγενής (eugenēs), \"noble\", dosłownie \"dobrze urodzony\", od ε ⁇ (eu), \"dobrze\" i γένος (genos), \"rasy, pochodzenia, krewnych\". Gene to powszechne skrócenie.</p>", "E": "<b>E</b> (<a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>e</b>) – piąta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, siódma litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. Zazwyczaj oznacza <a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska\" target=\"_blank\" rel=\"noopener noreferrer\">samogłoskę</a> [<a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82przymkni%C4%99ta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">e</a>] lub [<a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a>].", "Ergys": "<p>Ergys to albanianskie imię męskie. Znani ludzie z nazwiskiem to: Ergys Kaçe (ur. 1993), albanianki piłkarz Ergys Peposhi (ur. 2000), albanianka piłkarza Ergys Sorra (ur. 1989), albanianski piłkarze</p>", "Ewen": "<p>Ewen to męskie imię, najczęściej stosowane w Szkocji i Kanadzie, ze względu na imigrację Szkockich. Jest angilikacją szkockiego gaelickiego imienia, Eòghann.</p>", "Eben": "<p>Eben to imię pochodzące z hebrajskiego. Czasami jest skrócona na Ebenezer.</p>", "Emanuel-David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emanuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Eliya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elia</b>.</p><p>Elia Group - belgijska firma, która jest operatorem linii przesyłania energii elektrycznej o wysokiej napięciu. Pracuje w Belgii (Elia Transmission Belgium) i Niemczech (50Hertz Transmission), pod jej kierownictwem znajduje się również interkonektor Nemo Link między Belgią a Wielką Brytanią.</p>", "Emal": "<p>Emal to afgańskie imię męskie. Wśród znanych osób z tym nazwiskiem są: Emal Gariwal (ur. 1984), afgański piłkarz Emal Pasarly (ur. 1974), afgański redaktor multimediów dla BBC</p>", "El Mostafa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Eurico": "<p>Eurico to imię. Może odnosić się do:</p>", "Erosi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eros</b>.</p><p>W greckiej mityce Eros jest bogiem miłości. Bogi Eros zawsze nosili ze sobą łuk i strzały miłości.</p>", "Effiong": "<p>Effiong jest zarówno nazwiskiem i męskim nazwiskiem, często używanym w Nigerii. Do wybitnych osób z tym nazwiskiem należą:</p>", "Edwin Fabian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Eliash": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eliasz</b>.</p><b>Eliasz</b>, również <b>Eliasz z Tiszbe</b> lub <b>Eliasz Tiszbita</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֱלִיָּהוּ&#8206; <i>Eliyáhu</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἠλίας <i>Elias</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_cerkiewnos%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">cs.</a>&#160;Илья-пророк) – jeden z <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">proroków</a> <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a> żyjący w IX w. przed Chrystusem w północnym państwie Izraela (imię tłumaczone jako: „Bogiem jest <a href=\"https://pl.wikipedia.org/wiki/Jah\" target=\"_blank\" rel=\"noopener noreferrer\">Jah</a>”, „moim Bogiem jest <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”). <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ci_i_b%C5%82ogos%C5%82awieni_Ko%C5%9Bcio%C5%82a_katolickiego\" target=\"_blank\" rel=\"noopener noreferrer\">Święty Kościoła katolickiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Cerkiew_prawos%C5%82awna\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławnego</a>, <a href=\"https://pl.wikipedia.org/wiki/Koptyjski_Ko%C5%9Bci%C3%B3%C5%82_Ortodoksyjny\" target=\"_blank\" rel=\"noopener noreferrer\">koptyjskiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Apostolski_Ko%C5%9Bci%C3%B3%C5%82_Ormia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskiego</a> i <a href=\"https://pl.wikipedia.org/wiki/Syryjski_Ko%C5%9Bci%C3%B3%C5%82_Ortodoksyjny\" target=\"_blank\" rel=\"noopener noreferrer\">syryjskiego</a>.", "Eckard": "<b>Eckard</b> – imię męskie pochodzenia germańskiego. Forma pokrewna imienia <a href=\"https://pl.wikipedia.org/wiki/Ekhard\" target=\"_blank\" rel=\"noopener noreferrer\">Ekkehard</a>.", "Edgari": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Edgar Mauricio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Erasti": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Erast</b>.</p><b>Erast</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Pochodzi od greckiego imienia <i>Erastus</i> oznaczającego \"miły\". Było imieniem pomocnika <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Pawła</a> wymienionego w <a href=\"https://pl.wikipedia.org/wiki/Dzieje_Apostolskie\" target=\"_blank\" rel=\"noopener noreferrer\">Dziejach Apostolskich</a> <a href=\"https://pl.wikipedia.org/wiki/Erast_z_Koryntu\" target=\"_blank\" rel=\"noopener noreferrer\">Erasta z Koryntu</a>.", "Expedyt": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ekspedyt</b>.</p><b>Ekspedyt</b>, <b>Wierzyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od czasownika <em>expediō, expedīre</em> („uwolnić, wyzwolić z więzów”), <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>expedītus</em> znaczy „uwolniony, lekko ubrany, lekkozbrojny; szybki, zwinny”. Imię to zostało w Polsce przetłumaczone jako <b>Wierzyn</b> („ten, któremu można wierzyć”). Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Ekspedyt\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Ekspedyt</a>.", "Erikh": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Erich</b>.</p><b>Eryk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Nadawane wielu jarlom i królom <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">szwedzkim</a> i <a href=\"https://pl.wikipedia.org/wiki/Dania\" target=\"_blank\" rel=\"noopener noreferrer\">duńskim</a>. Pochodzenie tego imienia podaje się ze staro-wysoko-niemieckiego, gdzie <b>era</b> znaczy: honor, cześć, oraz <b>richi</b> – bogaty. Całość zaś oznacza osobę zasobną w honor lub władcę, który zaszczytnie króluje. Jego popularność sięga czasów króla szwedzkiego Eryka zmarłego w <a href=\"https://pl.wikipedia.org/wiki/1160\" target=\"_blank\" rel=\"noopener noreferrer\">1160</a>. Inne spotykane znaczenie to „wieczny władca” od <i>ei(r)</i> co oznacza w staronordyjskim „wieczny” i <i>ríkr</i> – w staronordyjskim „władca”.", "Erwann": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Erwan</b>.</p><p>Erwan to męskie imię bretonskie, czasami pisowane Erwann. Jego franczyzacja jest francuską nazwą Yves.</p>", "Enrrique": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Enrique</b>.</p><p>Enrique - pierwszy angielski i czwarty album hiszpańskiego piosenkarza popu Enrique Iglesias, wydany w 1999 roku. Jest to pierwszy album Iglesias, który został nagrany we współpracy z amerykańską wytwórnią Interscope Records i producentami Paulem Barry'm i Markem Taylorem.</p>", "Elijas": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elias</b>.</p><p>Eliusz Aleksanderski (w części źródeł Elias, grecki ⁇ λίας) - późnoantyczny grecki filozof-neoplatonik VI wieku n.e.</p>", "Edwin Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Eitán": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eytan</b>.</p><p>Ethan lub Eytan to męskie imię hebrajskiego pochodzenia, które oznacza \"pewne, trwałe, silne i długotrwałe\". Nazwa Etan pojawia się osiem razy w Biblii Hebrajskiej (1 Królów 4:31; 1 Kronik 2:6, 8; 6:42, 44; 15:17, 19; nadpis Psalm 89).</p>", "El Hassan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Estevão": "<p>Estevão to portugalska męska nazwa, pochodząca z greckiego Στέφανος (Stefanos) i związana z angielskimi nazwami Steven i Stephen. Może odnosić się do: Estevão Martins de Leomil (fl.</p>", "Ekkachai": "<p>Ekkachai lub Ekachai (Thai: เอกชัย) to tajskie męskie imię. Mieszkańcy tej nazwy to: Ekkachai Janthana, biegacz Ekkachai Nophajinda, dziennikarz sportowy Ekkachai Rittipan, piłkarz Ekkachai Sumrei, piłkerz Ekachai Jearakul (ur. 1987), tajalski gitarzysta klasyczny Ekachai Uekrongtham, tajlandzki reżyser teatralny i filmowy</p>", "Emmanuele": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emmanuel</b>.</p><b>Emmanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Symbol\" target=\"_blank\" rel=\"noopener noreferrer\">symboliczne</a> imię (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i> 'immanu 'el</i> – <i>Bóg jest z nami</i>), przypisywane przez <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">proroka</a> <a href=\"https://pl.wikipedia.org/wiki/Izajasz\" target=\"_blank\" rel=\"noopener noreferrer\">Izajasza</a> chłopcu, którego królowi <a href=\"https://pl.wikipedia.org/wiki/Achaz\" target=\"_blank\" rel=\"noopener noreferrer\">Achazowi</a> miała urodzić młoda kobieta (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Izajasza\" target=\"_blank\" rel=\"noopener noreferrer\">Iz</a> 7,14) w momencie poważnego zagrożenia dynastii. W chwili wygłoszenia proroctwa król <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Damaszku\" target=\"_blank\" rel=\"noopener noreferrer\">Damaszku</a>, <a href=\"https://pl.wikipedia.org/wiki/Resin\" target=\"_blank\" rel=\"noopener noreferrer\">Resin</a>, i król <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Izraela_(pa%C5%84stwo_p%C3%B3%C5%82nocne)\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a>, <a href=\"https://pl.wikipedia.org/wiki/Pekach\" target=\"_blank\" rel=\"noopener noreferrer\">Pekach</a>, oblegli Jerozolimę w ramach toczącej się <a href=\"https://pl.wikipedia.org/wiki/Wojna_syro-efraimska\" target=\"_blank\" rel=\"noopener noreferrer\">wojny syro-efraimskiej</a>. Emmanuel miał być znakiem Bożej łaski wobec Achaza, skutkującej niepowodzeniem koalicji.", "Ezzeddine": "<p>Izz al-Din (arabski: عزّ الدين lub powszechnie napisany عزّ الدین, 'izzu \"d-dīn, 'izza \"d-Dīn, również napisany Azzedine lub Azzeddine) jest męskie nazwisko i nazwisko pochodzenia arabskiego oznaczające \"wysoki rang (honor, szacunek, prestiż) religii islamskiej / wiary\". Prefiks \"'izz\" oznaczający \"wysoki rangę, honor, szacunek, prestiż\" jest również pojęciem, że ktoś jest szanowany, ceniony, silny lub potężny.</p>", "Eseosa": "<p>Eseosa lub Esosa to imię w języku Edo, co oznacza \"dar Boży\".</p>", "Erin": "<p>Erin (Erin) - starożytne celtyckie nazwisko Irlandii. Nazwa pochodzi od imienia bogini Eryu (dr. -Wyrzeź.</p>", "Edgar David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Elbay": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elbai</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elba</b>.</p><p>Elba jest wyspą wśródziemnomorską w Toskanii, Włochy, oddaloną 20 km (12 mi) od przybrzeżnego miasteczka Piombino. Jako największa z wysp Tuscan, wyspa Elba jest również częścią Parku Narodowego Wysp Toskanych i jest trzecim największym wyspą w Włoszech po wyspach Scylii i Sardenii.</p>", "Eri": "<b>Eri</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えり, エリ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "El Sayed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Emma": "<p>Emma (jap. エマ Emma) - romantyczna saynenn-manga Mori Kaoru, wydana w czasopiśmie Comic Beam od sierpnia 2002 roku do kwietnia 2008 roku.</p>", "Emi̇l": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emila</b>.</p>Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Eustazjusz": "<b>Eustacjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>Eustáthios</i>, przejęte do <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a> jako Eustathius i Eustatius, utworzone od przymiotnika eustathés 'silny, dobrze zbudowany, zdrowy'. Mylone z <a href=\"https://pl.wikipedia.org/wiki/Eustachy\" target=\"_blank\" rel=\"noopener noreferrer\">Eustachym</a>. Imię to nosiło niewielu świętych. Jego ukraińskim odpowiednikiem jest <i><b>Ostap</b></i>.", "Edgar Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Elyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elian</b>.</p>Do jego głównych dzieł należą: <i>De natura animalium</i> (<i>Περὶ ζῴων ἰδιότητος</i>) i <i>Varia historia</i> (<i>Ποικίλη ἱστορία</i>) czyli <i>O właściwościach zwierząt</i> i <i>Opowiastki rozmaite</i>. Pierwsze to opowieści o niezwykłych cechach i zaletach zwierząt, zawarte w 17 księgach, drugie to ujęte w 14 księgach anegdoty historyczne i przyrodnicze pochodzące z zaginionej literatury wcześniejszej. Oprócz szerokiej wiedzy tematycznej dają one wgląd w zakres poznania świata grecko-rzymskiego. Elian jest ponadto autorem zbioru 20 utworów <a href=\"https://pl.wikipedia.org/wiki/Epistolografia\" target=\"_blank\" rel=\"noopener noreferrer\">epistolarnych</a>, zatytułowanego <i>Listy wieśniaków</i> (<i>Epistulae rusticae</i>, gr. <i>Ἐπιστολαὶ ἀγροικικαί</i>), mającego szczególną wartość dzięki licznym cytatom z niezachowanych dzieł starszych autorów. Za zaginione uważa się jego niektóre pisma o charakterze filozoficznym (np. o opatrzności) oraz <a href=\"https://pl.wikipedia.org/wiki/Pamflet\" target=\"_blank\" rel=\"noopener noreferrer\">pamflet</a> na Heliogabala.", "Einari": "<p>Einari jest fińskim i estonijskim męskim imieniem, krewnianym z skandynawskim imieniem Einar. Do osób z imieniem Einari należą: Einari Aalto (1926-1985), fiński pływacz Einari Teräsvirta (1914-1995), fiński gimnast i architekt Einari Vuorela (1889-1972), fiński pisarz</p>", "Ester": "<p>W chemii ester jest składnikiem chemicznym pochodzącym z kwasu (organicznego lub niekomórkowego), w którym przynajmniej jeden z grup LIPOH (hydroxyl) jest zastąpiony grupą alkyl (alkiel). Zazwyczaj estery są składające się z kwasu karboxylowego i alkoholu.</p>", "Edgar Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Edwin Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Esmir": "<p>Esmir to bosniackie imię męskie. Na Bałkanach, Esmir jest popularny wśród Bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Elijasz": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eliasz</b>.</p><b>Eliasz</b>, również <b>Eliasz z Tiszbe</b> lub <b>Eliasz Tiszbita</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֱלִיָּהוּ&#8206; <i>Eliyáhu</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἠλίας <i>Elias</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_cerkiewnos%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">cs.</a>&#160;Илья-пророк) – jeden z <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">proroków</a> <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a> żyjący w IX w. przed Chrystusem w północnym państwie Izraela (imię tłumaczone jako: „Bogiem jest <a href=\"https://pl.wikipedia.org/wiki/Jah\" target=\"_blank\" rel=\"noopener noreferrer\">Jah</a>”, „moim Bogiem jest <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”). <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ci_i_b%C5%82ogos%C5%82awieni_Ko%C5%9Bcio%C5%82a_katolickiego\" target=\"_blank\" rel=\"noopener noreferrer\">Święty Kościoła katolickiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Cerkiew_prawos%C5%82awna\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławnego</a>, <a href=\"https://pl.wikipedia.org/wiki/Koptyjski_Ko%C5%9Bci%C3%B3%C5%82_Ortodoksyjny\" target=\"_blank\" rel=\"noopener noreferrer\">koptyjskiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Apostolski_Ko%C5%9Bci%C3%B3%C5%82_Ormia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskiego</a> i <a href=\"https://pl.wikipedia.org/wiki/Syryjski_Ko%C5%9Bci%C3%B3%C5%82_Ortodoksyjny\" target=\"_blank\" rel=\"noopener noreferrer\">syryjskiego</a>.", "Emanuell": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emanuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Eugenio Jr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eugenio</b>.</p><p>Eugenio - IX-wieczny czynnik kościelny, biskup cardinalis Ostii z 878 roku. Uczestniczył w synodzie 879 roku w Rzymie, następnie był na katedrze w Konstantynopolu.</p>", "Eustazy": "<b>Eustazy</b>, <b>Eustazjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, którego pierwszym członem jest <i>eu-</i> (\"dobrze\"), a drugim – <i>stás(is)</i> (\"staranie, trwanie, wytrwałość\").", "Ebbe": "<p>Ebbe to skandynawskie męskie imię. Kobieta to Ebba.</p>", "Edgar Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Erlin": "Populacja gminy Erlin w 2016 roku liczyła 51&#160;516 mieszkańców – 24&#160;983 kobiety i 26&#160;533 mężczyzn. Liczba gospodarstw domowych wynosiła 14&#160;974, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,44 osób.", "Erika": "<b>Eryka</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eryk\" target=\"_blank\" rel=\"noopener noreferrer\">Eryk</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>.", "El Houcine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Eswar": "<p>Eswar może odnosić się do następujących osób: Eswar (1938-2021), projektant reklam w Telugu Eswar Prasad (ur. 1965), indyjski ekonomista Theni Eswar, indyjski kinematograf</p>", "Estrella": "<p>Estrella - hiszpańska nazwisko i kobiece imię.</p>", "Elly": "<p>Elly może być: Elly Chan Elly, członek Weki Meki</p>", "Elise": "<p>Eliza: Eliza to imię kobiety. Eliza Dolittl - bohaterka piosenki Bernarda Shaw'a ⁇ Pigmalion ⁇ (1912).</p>", "Eleonor": "<p>Eleanor () to żeńskie imię, pochodzące z starofrancuskiej adaptacji starej prowencalski nazwy Aliénor. Było to imię wielu kobiet z rodziny królewskiej i szlachty w Europie Zachodniej w średniowieczu.</p>", "Edgar Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Ehsanullah": "<p>Ehsanullah lub poprawniej Ihsanullah to męskie muzułmańskie imię, składające się z elementów Ihsan i Allah. Znani ludzie z nazwiskiem to: Ehsanullah (więźniak z Guantanamo 523), uwolniony 9 maja 2003 Ehsanullah Ehsan (zmętna), wiele osób Ehsanullah Khan, pakistański polityk Ehsanullah Reki, pakistański polityk</p>", "Emi": "W lutym 2010 w mediach pojawiły się informacje, że EMI z powodu długów sprzeda legendarne <a href=\"https://pl.wikipedia.org/wiki/Abbey_Road_Studios\" target=\"_blank\" rel=\"noopener noreferrer\">studio Abbey Road</a>, w którym nagrywali między innymi <a href=\"https://pl.wikipedia.org/wiki/The_Beatles\" target=\"_blank\" rel=\"noopener noreferrer\">The Beatles</a>.", "Elya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elia</b>.</p><p>Elia Group - belgijska firma, która jest operatorem linii przesyłania energii elektrycznej o wysokiej napięciu. Pracuje w Belgii (Elia Transmission Belgium) i Niemczech (50Hertz Transmission), pod jej kierownictwem znajduje się również interkonektor Nemo Link między Belgią a Wielką Brytanią.</p>", "Ellias": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elias</b>.</p><p>Eliusz Aleksanderski (w części źródeł Elias, grecki ⁇ λίας) - późnoantyczny grecki filozof-neoplatonik VI wieku n.e.</p>", "Emmanuel Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emmanuel</b>.</p><b>Emmanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Symbol\" target=\"_blank\" rel=\"noopener noreferrer\">symboliczne</a> imię (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i> 'immanu 'el</i> – <i>Bóg jest z nami</i>), przypisywane przez <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">proroka</a> <a href=\"https://pl.wikipedia.org/wiki/Izajasz\" target=\"_blank\" rel=\"noopener noreferrer\">Izajasza</a> chłopcu, którego królowi <a href=\"https://pl.wikipedia.org/wiki/Achaz\" target=\"_blank\" rel=\"noopener noreferrer\">Achazowi</a> miała urodzić młoda kobieta (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Izajasza\" target=\"_blank\" rel=\"noopener noreferrer\">Iz</a> 7,14) w momencie poważnego zagrożenia dynastii. W chwili wygłoszenia proroctwa król <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Damaszku\" target=\"_blank\" rel=\"noopener noreferrer\">Damaszku</a>, <a href=\"https://pl.wikipedia.org/wiki/Resin\" target=\"_blank\" rel=\"noopener noreferrer\">Resin</a>, i król <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Izraela_(pa%C5%84stwo_p%C3%B3%C5%82nocne)\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a>, <a href=\"https://pl.wikipedia.org/wiki/Pekach\" target=\"_blank\" rel=\"noopener noreferrer\">Pekach</a>, oblegli Jerozolimę w ramach toczącej się <a href=\"https://pl.wikipedia.org/wiki/Wojna_syro-efraimska\" target=\"_blank\" rel=\"noopener noreferrer\">wojny syro-efraimskiej</a>. Emmanuel miał być znakiem Bożej łaski wobec Achaza, skutkującej niepowodzeniem koalicji.", "Egide": "<p>Egide lub Égide jest męskim imieniem, które może odnosić się do: Égide de Boeck (1875-1944), belgijski kapłan katolicki, biskup, wikariusz apostolski i lingwist w tymczasowym belgijskim Kongo Egide Duny lub Egidio Duni (1708-1775), włoskiego kompozytora operowego Egide Fologne (1830-1919), belgijskiego entomologa Egide François Leemans (1839-1883), belgijskiej malarza, rysunkodawcy i grawerowcy Egide Linnig (1821-1860), belgijskie malarz, rysunkowca i grawerowca Egide ...</p>", "Ervan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Erwan</b>.</p><p>Erwan to męskie imię bretonskie, czasami pisowane Erwann. Jego franczyzacja jest francuską nazwą Yves.</p>", "Edgar Fabian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Emanuel De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emanuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Edwin Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Elysei": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elisei</b>.</p><p>Yelisey, Yelisei, Elisey lub Elisei (rosyjski: Елисей) to rosyjskie męskie imię rosyjskiego równoważne z Elizeem; jest to również okazjonalne nazwisko. Nazwa może odnosić się do następujących znaczących osób: Elisey (Ganaba) (ur. 1962), arcybiskup diecezji Hadagi i Holandii Kościoła Prawosławnego Rosyjskiego Elisei Morozov (1798-1868), rosyjski przedsiębiorca Elisey Mysin (ur. 2010), rosyjskie pianista, kompozytor, dzieckiem cudzołóstwowym i aktor...</p>", "Edwin Ferney": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Elian David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elian</b>.</p>Do jego głównych dzieł należą: <i>De natura animalium</i> (<i>Περὶ ζῴων ἰδιότητος</i>) i <i>Varia historia</i> (<i>Ποικίλη ἱστορία</i>) czyli <i>O właściwościach zwierząt</i> i <i>Opowiastki rozmaite</i>. Pierwsze to opowieści o niezwykłych cechach i zaletach zwierząt, zawarte w 17 księgach, drugie to ujęte w 14 księgach anegdoty historyczne i przyrodnicze pochodzące z zaginionej literatury wcześniejszej. Oprócz szerokiej wiedzy tematycznej dają one wgląd w zakres poznania świata grecko-rzymskiego. Elian jest ponadto autorem zbioru 20 utworów <a href=\"https://pl.wikipedia.org/wiki/Epistolografia\" target=\"_blank\" rel=\"noopener noreferrer\">epistolarnych</a>, zatytułowanego <i>Listy wieśniaków</i> (<i>Epistulae rusticae</i>, gr. <i>Ἐπιστολαὶ ἀγροικικαί</i>), mającego szczególną wartość dzięki licznym cytatom z niezachowanych dzieł starszych autorów. Za zaginione uważa się jego niektóre pisma o charakterze filozoficznym (np. o opatrzności) oraz <a href=\"https://pl.wikipedia.org/wiki/Pamflet\" target=\"_blank\" rel=\"noopener noreferrer\">pamflet</a> na Heliogabala.", "Edwin Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Esmeralda": "<b>Esmeralda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"szmaragd\". Patronem tego imienia jest św. Smaragd (Szmaragd), wspominany razem ze <a href=\"https://pl.wikipedia.org/wiki/Cyriak_Rzymianin\" target=\"_blank\" rel=\"noopener noreferrer\">św. Cyriakiem</a> i <a href=\"https://pl.wikipedia.org/wiki/Largus\" target=\"_blank\" rel=\"noopener noreferrer\">Largusem</a>.", "Eren Can": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eren</b>.</p><p>Eren to tureckie imię, które w dzisiejszym tureckim oznacza \"Święty\". Według Mahmudu al-Kashgari jest to liczba wielokrotna słowa \"er\" z dodatkiem wielokrotnie \"-a\".</p>", "Edwin Orlando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Edwin David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Edwin Eduardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Elmas": "<p>Elmas jest comune prowincji Cagliari w włoskim regionie Sardinii, znajdującym się około 8 km na północny zachód od Cagliari. Na dzień 31 grudnia 2004 roku mieście miało 8.475 mieszkańców i obszar 13.7 km2.</p>", "Edwin Camilo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Elangovan": "<p>Elangovan to nazwisko lub nazwisko, które może odnosić się do: E. V.</p>", "Edel": "<p>Edel to zarówno nazwisko, jak i imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Erico": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eriko</b>.</p><b>Eriko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えりこ, エリコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Eduard-Valentin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eduard</b>.</p><p>Edwarda - męskie imię, pochodzące od angielsko-saksońskiego Ēadweard - ⁇ strzeganie bogactwa, szczęścia ⁇ (ead oznacza ⁇ szczęśliwy, kwitnący ⁇ , a weard tłumaczono jako ⁇ strogę ⁇).</p>", "Eryc": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eryk</b>.</p><b>Eryk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a>. Nadawane wielu jarlom i królom <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">szwedzkim</a> i <a href=\"https://pl.wikipedia.org/wiki/Dania\" target=\"_blank\" rel=\"noopener noreferrer\">duńskim</a>. Pochodzenie tego imienia podaje się ze staro-wysoko-niemieckiego, gdzie <b>era</b> znaczy: honor, cześć, oraz <b>richi</b> – bogaty. Całość zaś oznacza osobę zasobną w honor lub władcę, który zaszczytnie króluje. Jego popularność sięga czasów króla szwedzkiego Eryka zmarłego w <a href=\"https://pl.wikipedia.org/wiki/1160\" target=\"_blank\" rel=\"noopener noreferrer\">1160</a>. Inne spotykane znaczenie to „wieczny władca” od <i>ei(r)</i> co oznacza w staronordyjskim „wieczny” i <i>ríkr</i> – w staronordyjskim „władca”.", "Edward Andrzej": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edward</b>.</p><b>Edward</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia angielskiego. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">języku staroangielskim</a>:", "El Hadji": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Esosa": "<p>Eseosa lub Esosa to imię w języku Edo, co oznacza \"dar Boży\".</p>", "Edison Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edison</b>.</p><p>Thomas Alva Edison (11 lutego 1847 - 18 października 1931) był amerykańskim wynalazcą i przedsiębiorcą, który opracował wiele urządzeń, które miały duży wpływ na życie w 20 wieku. Był nazywany \"Majsterem Czarownic Menlo Park\" przez dziennikarza. Był jednym z pierwszych wynalazców, którzy zastosowali zasady produkcji w procesie twórczym.</p>", "Emannuel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emanuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Eliud": "Jego imię znaczy \"Mój Bóg jest dostojeństwem\", lub \"Bóg dostojeństwa\".", "Emilio Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emilio</b>.</p><p>Emilio, Luciano (ur. 1978) - brazylijski piłkarz.</p>", "Eranga": "<p>Eranga to zarówno imię, jak i nazwisko. Znani ludzie z nazwiska to: Eranga Rathnayake (ur. 1992), kryketar Sri Lankan Achira Eranga (ur. 1987), krykator Sri Lankan Amila Eranga (UR. 1986), krykatar Sri Lankan Romesh Eranga (Ur. 1985), krykater Sri Lankan Shaminda Eranga (U. 1986), Sri Lankan krykator Tharindu Eranga, krykator Ujitha Eranga, Sri Lankan Krykator</p>", "Eufemiusz": "<b>Eufemiusz</b>, <b>Eufemian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „pomyślnie wróżący”, „przychylny”.", "Emanuel-Eduard": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emanuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "El-Din": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Edmund Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edmund</b>.</p><b>Edmund</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a>. Wywodzi się od słowa oznaczającego „zapewniający opiekę”.", "Erofei": "<p>Yerofey lub Erofey (rosyjski: Ерофей) to rosyjskie imię, odpowiednik Hierotheos. Archaiczna forma, nadal używana jako nazwisko klasztorskie, to Iyerofey (Иерофей.</p>", "Ezzeldin": "<p>Izz al-Din (arabski: عزّ الدين lub powszechnie napisany عزّ الدین, 'izzu \"d-dīn, 'izza \"d-Dīn, również napisany Azzedine lub Azzeddine) jest męskie nazwisko i nazwisko pochodzenia arabskiego oznaczające \"wysoki rang (honor, szacunek, prestiż) religii islamskiej / wiary\". Prefiks \"'izz\" oznaczający \"wysoki rangę, honor, szacunek, prestiż\" jest również pojęciem, że ktoś jest szanowany, ceniony, silny lub potężny.</p>", "El Din": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Eve": "<p>Ive Jejeen Jeffers (ang. Eve Jihan Jeffers; rodzaj.</p>", "El Hadi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Emmerson": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emerson</b>.</p><p>Emerson - nazwisko, nazwisko i toponim.</p>", "El Houssine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Edwin Santiago": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "El Mokhtar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Ewerton": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Everton</b>.</p><p>Everton ma wiele znaczeń.</p>", "Egli": "<p>Egli (Szwajcarskie niemiecki: z formy zwierzęcej starożytnego germańskiego imienia osobistego Egenolf lub Egilolf (patrz Egloff)) jest zarówno nazwiskiem i nazwiskiem. Znani ludzie z nazwiskiem: Egli Kaja (ur. 1997), albanianki piłkarz Nowatni ludzie z nazwisko obejmują: Alphons Egli (1924-2016), szwajcarz polityk Jean-François Egli (1928-2023), sędzia szwajcarskiego Sądu Najwyższego Federacyjnego André Egli (ur. 1958), szwajcarka piłkarka Beatrice Egli ...</p>", "Elmani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elman</b>.</p><p>Elman Elman oglę Zaynalowa (azerb. Elman Elman syn Zeynalov; rod.</p>", "Edmund Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edmund</b>.</p><b>Edmund</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a>. Wywodzi się od słowa oznaczającego „zapewniający opiekę”.", "Emerik": "<p>Emerich, Emeric, Emerick i Emerik są nazwiskami i nazwiską. Mogą one odnosić się do:</p>", "Ezer": "<p>Ezer to hebrajskie słowo oznaczające \"pomoc\" lub \"pomocnik\", używane również jako imię lub część imienia. Ezer może odnosić się do:</p>", "Edward Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edward</b>.</p><b>Edward</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia angielskiego. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">języku staroangielskim</a>:", "Edwyn": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Emillio": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emilio</b>.</p><p>Emilio, Luciano (ur. 1978) - brazylijski piłkarz.</p>", "Elmeri": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elmer</b>.</p><p>Adolph Daniel Edward Elmer (ang. Adolph Daniel Elmer; 1870 - 1942) - amerykański botanik i pterydołóg.</p>", "El-Arabi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Edwin Johan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Eliyah": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eliah</b>.</p><p>Elias (il-EYE-əs; starożytny grecki: ⁇ λίας, romanizowany: Elías) jest hellenistyczną wersją imienia Eliasza (Hebrajskie: אֵלִיָּהוּ, romanized: ʾĒlīyyāhū; Syriac: ⁇ , romanizewany: Elyāe; Arabskie: إلیاس, romanizes: Ilyās, lub إلیا, Ilyā), proroka w północnym królestwie Izraela w IX wieku p.n.e., wspomniany w kilku świętych ksiągach. Ze względu na rolę Eliasza w Pisma Świętego i wielu późniejszych związanych z nim tradycji, imię jest używane jako imię osobiste...</p>", "Eustathios": "<b>Eustacjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>Eustáthios</i>, przejęte do <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a> jako Eustathius i Eustatius, utworzone od przymiotnika eustathés 'silny, dobrze zbudowany, zdrowy'. Mylone z <a href=\"https://pl.wikipedia.org/wiki/Eustachy\" target=\"_blank\" rel=\"noopener noreferrer\">Eustachym</a>. Imię to nosiło niewielu świętych. Jego ukraińskim odpowiednikiem jest <i><b>Ostap</b></i>.", "Erii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eri</b>.</p><b>Eri</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えり, エリ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Emil Stanisław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emil</b>.</p><b>Emil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a> (<i>Aemilius</i>). Łacińskie słowo <i>aemulor</i> oznacza „rywalizujący”. Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Emil_z_Kordoby\" target=\"_blank\" rel=\"noopener noreferrer\">Emil z Kordoby</a> (†852), męczennik i święty katolicki wspominany 15 września.", "Edhem": "<p>Edhem to bosniackie i tureckie imię dla mężczyzn, pisane w arabskim Adham (أدهم). Używano go również jako nazwisko.</p>", "Emily": "<p>Emily Brontë Emily Osment Emily Dickinson Emily, wietnamskiej piosenkarki</p>", "Edisson Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edisson</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Edison</b>.</p><p>Thomas Alva Edison (11 lutego 1847 - 18 października 1931) był amerykańskim wynalazcą i przedsiębiorcą, który opracował wiele urządzeń, które miały duży wpływ na życie w 20 wieku. Był nazywany \"Majsterem Czarownic Menlo Park\" przez dziennikarza. Był jednym z pierwszych wynalazców, którzy zastosowali zasady produkcji w procesie twórczym.</p>", "Emmy": "<p>⁇ Emmy ⁇ (ang. Emmy Award) - międzynarodowa nagroda telewizyjna, przyznawana w USA.</p>", "Eric Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eric</b>.</p><p>Eric (pełna nazwa: Eric Python IDE) - wolno dystrybuowane zintegrowane środowisko rozwoju dla języków programowania Python i Ruby. Przez pewien czas Eric4 działał tylko z Python 2, a Eric5 z Python 3, ale od Eric6 wspierają obie wersje Python jednocześnie.</p>", "Emilijan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emilian</b>.</p>Utarło się kilka <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnień</a> tego imienia: <i>Emko</i>, <i>Mila</i>, <i><a href=\"https://pl.wikipedia.org/wiki/Milan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Milan</a></i>, <i>Milo</i> itp., oraz najpopularniejsze <i><b><a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a></b></i>. Ostatnie, dzięki twórczości <a href=\"https://pl.wikipedia.org/wiki/Jean-Jacques_Rousseau\" target=\"_blank\" rel=\"noopener noreferrer\">Jeana-Jacques’a Rousseau</a> (<i><a href=\"https://pl.wikipedia.org/wiki/Emil,_czyli_o_wychowaniu\" target=\"_blank\" rel=\"noopener noreferrer\">Emil, czyli O wychowaniu</a></i>), zostało upowszechnione w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX w.</a> jako odrębne imię i często stosowane wymiennie. Znane <a href=\"https://pl.wikipedia.org/wiki/Spieszczenie\" target=\"_blank\" rel=\"noopener noreferrer\">spieszczenia</a> imienia to m.in.: <i>Jemek</i>, <i>Milek</i>, <i>Miluś</i>, <i>Miłek</i> itp., oraz pochodzące od zdrobnienia <i>Emil</i>: <i>Emilek</i>, <i>Emisz</i>, <i>Emiś</i> itp.", "Etamar": "<p>Itamar (Hebrajskie: אִיתָמָר, romanized: ʼĪṯāmār), również pisownione jako Itamar lub Etamar, jest hebrajskim męskim imieniem. Nazwa oznacza \"wyspa palmy\" w języku hebrajskim, pochodząca z hebrajskiego i (Hebrajskie: אִי, romanized: 'î, lit.</p>", "Eriki": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Erik</b>.</p><p>Erik może być: Erik, prawdziwe imię: Lê Trung Thành, wietnamski piosenkarz, były członek zespołu Monstar Erik Rhodes, amerykański aktor porno Erik, amerykański zawodowy walkacz</p>", "Eddo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Edo</b>.</p><p>Edo (江 (え) 戸 (ど) (Giang Hộ), Edo (co oznacza \"drzwi rzeki\", wymawiające w języku wietnamskim jako Edo) również pisane jako Yedo lub Yeddo, jest starożytnym nazwiskiem stolicy Japonii, tj. dzisiejszej Tokio. Ludzie byli w okolicy Zatoki Tōkyō na wieki, ale w literaturze dopiero w 15 wieku było wspomniane o Edo, gdy Ōta Dōkan założyła Edo w 1457 roku.</p>", "Enguerran": "<p>Enguerrand (lub Engrand, Ingrand) to średniowieczna francuska nazwa, pochodząca z germańskiej nazwy Engilram (Engelram, Ingelram), z Angil, plemiennego imienia Anglesów, a hramn \"rabin\". Starożytna nazwa frankowska jest zapisana w różnych formach w latach VIII-XI wieku, najstarszym świadectwem jest Angalramnus, imię biskupa Metz z VIII wieku; inne formy obejmują Angilrammus, Angelramnus, Ingalramnus,...</p>", "Elizabeth": "<p>Elizabeth lub Elisabeth jest transkrypcją nazwiska dla kobiet z greckiego słowa ⁇ λισάβετ, Elisabet. Nazwa pochodzi od hebrajskiego słowa Elisheva, co oznacza \"Obietnica Boga\". Z czasem Elizabeth i Elisabeth zostały przekształcone w różnych krajach, aby stać się: Libby, Lisa, Liza, Lilly, Lizzie, Liz, Beth, Betty, Ella, Elisa, Elise, i Eliza; Elspeth, Elsa, Bitsy, Betsy, Isabel i Isabella.</p>", "Eduard Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eduard</b>.</p><p>Edwarda - męskie imię, pochodzące od angielsko-saksońskiego Ēadweard - ⁇ strzeganie bogactwa, szczęścia ⁇ (ead oznacza ⁇ szczęśliwy, kwitnący ⁇ , a weard tłumaczono jako ⁇ strogę ⁇).</p>", "El-Hassan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Erik-Solomon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Erik</b>.</p><p>Erik może być: Erik, prawdziwe imię: Lê Trung Thành, wietnamski piosenkarz, były członek zespołu Monstar Erik Rhodes, amerykański aktor porno Erik, amerykański zawodowy walkacz</p>", "El Hassane": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Edrissa": "<p>Edrissa to męskie imię. Znanymi osobami z nazwiska są: Edrisa Lubega (ur. 1998), ugandzkia Edrissa Marong (ur. 2023), Gambijska biegaczka długodystansowa Edrissa Sanneh (ur. 1951), Gambijski urodzony włoski dziennikarz Edrissa Sonko (ur. 1980), Gambijskie piłkarz</p>", "Erik Rafael": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Erik</b>.</p><p>Erik może być: Erik, prawdziwe imię: Lê Trung Thành, wietnamski piosenkarz, były członek zespołu Monstar Erik Rhodes, amerykański aktor porno Erik, amerykański zawodowy walkacz</p>", "Eckbert": "<p>Egbert to nazwa pochodząca z starożytnych germańskich słów, które oznaczają \"świetły krawędzi\", np. ostrza. W wersjach angielsko-sakskich znajdują się Ecgberht i Ecgbert.</p>", "Enayatullah": "<p>Inayatullah, (arabski: عنایت الله) również pisowany jako Enayat Ollah itp., (urdu: عنایت اللہ) jest męskim nazwiskiem i nazwiskiem pochodzenia arabskiego. Jest składany z elementów Inayat, co oznacza \"opiekę\", i Allah, co oznacza\" Bóg\".</p>", "Edgar Esteban": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Euchariusz": "<b>Euchariusz</b>, <b>Eucheriusz</b> (<i>Eucharius</i>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Oznacza „przyjazny”. Patronem imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Euchariusz_z_Trewiru\" target=\"_blank\" rel=\"noopener noreferrer\">Euchariusz</a>, który był pierwszym biskupem <a href=\"https://pl.wikipedia.org/wiki/Trewir\" target=\"_blank\" rel=\"noopener noreferrer\">Trewiru</a> pod koniec III wieku.", "Edward Ferney": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edward</b>.</p><b>Edward</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia angielskiego. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">języku staroangielskim</a>:", "Edwin Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Emanuel-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emanuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "El-Houcine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Eva": "<p>⁇ Eva ⁇ - single Nightwish z albumu Dark Passion Play, wydany w 2007 roku i rozpowszechniony przez internet. Wszystkie pieniądze zebrane z sprzedaży zostały przekazane na dobroczynność.</p>", "Elmaz": "<p>Elmaz to męskie imię. Znanymi osobami z nazwiskiem są: Elmaz Abinader (ur. 1954), arabsko-amerykański autor, poeta i akademik Elmaz Boçe (1852-1925), albanianki wychowawca</p>", "Edvins": "<p>Edvīns to lotyjskie imię męskie.</p>", "Ella": "<p>Ella (ang. - ⁇ Ella ⁇) - trzydziestni dziewiąty album studiów amerykańskiej piosenkarki jazzowej Ella Fitzgerald, wydany na wytwórni Reprise Records w 1969 roku pod numerem RS 6354.</p>", "Enrique Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Enrique</b>.</p><p>Enrique - pierwszy angielski i czwarty album hiszpańskiego piosenkarza popu Enrique Iglesias, wydany w 1999 roku. Jest to pierwszy album Iglesias, który został nagrany we współpracy z amerykańską wytwórnią Interscope Records i producentami Paulem Barry'm i Markem Taylorem.</p>", "Eugeń": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eugene</b>.</p><p>Kim Yoo-jin (ur. 3 marca 1981), znana z imieniem Eugene, jest koreańską aktorką, piosenkarką i programistą, znana jako członek S.E.S. Jako solowy piosenkarz Eugene wydał dwa solo albums i obecnie koncentruje się na karierze w wielu koreańskich filmach i telewizjach, a także jako programista w wielu programach...</p>", "Elias Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elias</b>.</p><p>Eliusz Aleksanderski (w części źródeł Elias, grecki ⁇ λίας) - późnoantyczny grecki filozof-neoplatonik VI wieku n.e.</p>", "Edwin Alexis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Edwin Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Elyass": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elyas</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elias</b>.</p><p>Eliusz Aleksanderski (w części źródeł Elias, grecki ⁇ λίας) - późnoantyczny grecki filozof-neoplatonik VI wieku n.e.</p>", "Erni": "<p>Erni to zarówno imię, często skrótowana forma Ernest, jak i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "El-Sayed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Enlil": "Według jednego z mitów Enlil stworzył pierwszego człowieka wykopując motyką dziurę w ziemi, z której człowiek wyrósł jak roślina. Inny mit opowiada, jak Enlil rozdziela swych rodziców: Niebo (An) zostaje podniesiony w górę, a Matka Ziemia (Ki) pozostaje przy jego boku. Miał również zesłać potop na Ziemię, aby uciszyć ludzi, przez których nie mógł spać. Jedynymi, którzy przetrwali potop, byli <a href=\"https://pl.wikipedia.org/wiki/Utnapisztim\" target=\"_blank\" rel=\"noopener noreferrer\">Utnapisztim</a> (odpowiednik biblijnego <a href=\"https://pl.wikipedia.org/wiki/Noe\" target=\"_blank\" rel=\"noopener noreferrer\">Noego</a>) i jego żona.", "Edgar De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Esmat": "<p>Ismat/Esmat (arabski: عصمت / اسمت lub عصمة) jest nazwą, która oznacza czystość, czystość lub skromność i w klasycznej arabskiej nieomylność, nieskazitelność, bezwzględność, bezwarność. Warianty transliteracji obejmują Esmat i Asmat.</p>", "Edgar Estuardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Enrique Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Enrique</b>.</p><p>Enrique - pierwszy angielski i czwarty album hiszpańskiego piosenkarza popu Enrique Iglesias, wydany w 1999 roku. Jest to pierwszy album Iglesias, który został nagrany we współpracy z amerykańską wytwórnią Interscope Records i producentami Paulem Barry'm i Markem Taylorem.</p>", "El Habib": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Emiro Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emiro</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emir</b>.</p><p>Emir (; arabski: أمير ʾAmīr [ʔæˈmiːr]), czasami przenoszony do Amir, Amier lub Ameer, jest szlachectwem lub szlachetnym urzędnikiem używanym w wielu regionach w krajach Arabskich. Dosłownie oznacza to dowódca, generał, król lub król.</p>", "El Houssein": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Eric Andrew": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eric</b>.</p><p>Eric (pełna nazwa: Eric Python IDE) - wolno dystrybuowane zintegrowane środowisko rozwoju dla języków programowania Python i Ruby. Przez pewien czas Eric4 działał tylko z Python 2, a Eric5 z Python 3, ale od Eric6 wspierają obie wersje Python jednocześnie.</p>", "Edgar Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Emmanuel J.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emmanuel</b>.</p><b>Emmanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Symbol\" target=\"_blank\" rel=\"noopener noreferrer\">symboliczne</a> imię (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i> 'immanu 'el</i> – <i>Bóg jest z nami</i>), przypisywane przez <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">proroka</a> <a href=\"https://pl.wikipedia.org/wiki/Izajasz\" target=\"_blank\" rel=\"noopener noreferrer\">Izajasza</a> chłopcu, którego królowi <a href=\"https://pl.wikipedia.org/wiki/Achaz\" target=\"_blank\" rel=\"noopener noreferrer\">Achazowi</a> miała urodzić młoda kobieta (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Izajasza\" target=\"_blank\" rel=\"noopener noreferrer\">Iz</a> 7,14) w momencie poważnego zagrożenia dynastii. W chwili wygłoszenia proroctwa król <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Damaszku\" target=\"_blank\" rel=\"noopener noreferrer\">Damaszku</a>, <a href=\"https://pl.wikipedia.org/wiki/Resin\" target=\"_blank\" rel=\"noopener noreferrer\">Resin</a>, i król <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Izraela_(pa%C5%84stwo_p%C3%B3%C5%82nocne)\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a>, <a href=\"https://pl.wikipedia.org/wiki/Pekach\" target=\"_blank\" rel=\"noopener noreferrer\">Pekach</a>, oblegli Jerozolimę w ramach toczącej się <a href=\"https://pl.wikipedia.org/wiki/Wojna_syro-efraimska\" target=\"_blank\" rel=\"noopener noreferrer\">wojny syro-efraimskiej</a>. Emmanuel miał być znakiem Bożej łaski wobec Achaza, skutkującej niepowodzeniem koalicji.", "Enyu": "<p>Enyu (bułgarski: Еню) to męskie imię, które może odnosić się do cesarza En'yū (959-991), cesarza Japonii Enyu Todorova (1943-2022), bułgarskiego walki Enyu Valchev (1936-2014), bułgarskiej walki Wu Enyu (1909-1979), chińskiego filozofa, politologa i krytyka literacki</p>", "Elmer Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elmer</b>.</p><p>Adolph Daniel Edward Elmer (ang. Adolph Daniel Elmer; 1870 - 1942) - amerykański botanik i pterydołóg.</p>", "El Houceine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Efrain Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Efrain</b>.</p><p>Efraín to hiszpańskie imię męskie, krewny Efraima. Znani ludzie z nazwiska to: Efrain Chacurian (1924-2019), argentyński urodzony naturalny amerykański piłkarz Efraín Cortés (urodzony 1984), kolumbijski obrońca Efraín Escudero (urodzona 1986), meksykański walczyciel w mieszanych sztuk walki Efraín Flores (urodzono 1958), meksykański menedżer piłki nożnej Efraín Forero Triviño (1932-2022), kolumbijskie rower Efraín Goldenberg (1929-2025), peruwiański...</p>", "Ewa": "<b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Ereño": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eren</b>.</p><p>Eren to tureckie imię, które w dzisiejszym tureckim oznacza \"Święty\". Według Mahmudu al-Kashgari jest to liczba wielokrotna słowa \"er\" z dodatkiem wielokrotnie \"-a\".</p>", "Edwin Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Edward Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edward</b>.</p><b>Edward</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia angielskiego. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">języku staroangielskim</a>:", "Eusebio De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eusebio</b>.</p><p>Eusébio da Silva Ferreira (portugalski w Europie: [ewˈzɛβju ðɐ ˈsi ⁇ vɐ fɨˈʁɐjɾɐ]; 25 stycznia 1942 - 5 stycznia 2014) był portugalskim piłkarzem, który grał w pozycji piłkarza. Jest uważany za jednego z największych graczy wszechczasów i Benfica.</p>", "Edito": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Edit</b>.</p><p>Edit (ang. edytować) - wieloznaczny termin: Edit - niemiecki czasopism literackie, wydany w Leipzczygu.</p>", "Emil-Adrian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emil</b>.</p><b>Emil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a> (<i>Aemilius</i>). Łacińskie słowo <i>aemulor</i> oznacza „rywalizujący”. Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Emil_z_Kordoby\" target=\"_blank\" rel=\"noopener noreferrer\">Emil z Kordoby</a> (†852), męczennik i święty katolicki wspominany 15 września.", "Elbayi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elbay</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elbai</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elba</b>.</p><p>Elba jest wyspą wśródziemnomorską w Toskanii, Włochy, oddaloną 20 km (12 mi) od przybrzeżnego miasteczka Piombino. Jako największa z wysp Tuscan, wyspa Elba jest również częścią Parku Narodowego Wysp Toskanych i jest trzecim największym wyspą w Włoszech po wyspach Scylii i Sardenii.</p>", "Edgar Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Edeltraud": "<p>Edeltraud to niemiecka feminina, pochodząca z dwóch starożytnych elementów wysokiego niemieckiego: \"aþalaz\" (\"adal\") oznacza \"noble\" i \"þrūþiz\" (\"trud\") oznacza \"silność\". Edeltraud najczęściej występuje w krajach niemieckojęzycznych.</p>", "Ezzedine": "<p>Izz al-Din (arabski: عزّ الدين lub powszechnie napisany عزّ الدین, 'izzu \"d-dīn, 'izza \"d-Dīn, również napisany Azzedine lub Azzeddine) jest męskie nazwisko i nazwisko pochodzenia arabskiego oznaczające \"wysoki rang (honor, szacunek, prestiż) religii islamskiej / wiary\". Prefiks \"'izz\" oznaczający \"wysoki rangę, honor, szacunek, prestiż\" jest również pojęciem, że ktoś jest szanowany, ceniony, silny lub potężny.</p>", "Edwin Alirio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Edgar Eduardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Erik-Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Erik</b>.</p><p>Erik może być: Erik, prawdziwe imię: Lê Trung Thành, wietnamski piosenkarz, były członek zespołu Monstar Erik Rhodes, amerykański aktor porno Erik, amerykański zawodowy walkacz</p>", "Edward Ignacy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edward</b>.</p><b>Edward</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia angielskiego. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">języku staroangielskim</a>:", "Erik Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Erik</b>.</p><p>Erik może być: Erik, prawdziwe imię: Lê Trung Thành, wietnamski piosenkarz, były członek zespołu Monstar Erik Rhodes, amerykański aktor porno Erik, amerykański zawodowy walkacz</p>", "Eduard-Ionuţ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eduard</b>.</p><p>Edwarda - męskie imię, pochodzące od angielsko-saksońskiego Ēadweard - ⁇ strzeganie bogactwa, szczęścia ⁇ (ead oznacza ⁇ szczęśliwy, kwitnący ⁇ , a weard tłumaczono jako ⁇ strogę ⁇).</p>", "Emerson Julian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emerson</b>.</p><p>Emerson - nazwisko, nazwisko i toponim.</p>", "Edward Antony": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edward</b>.</p><b>Edward</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia angielskiego. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">języku staroangielskim</a>:", "Edgarus": "<p>Edgar jest powszechnie używanym męskim angielskim nazwiskiem, pochodzącym z angielsko-saksyjskiego imienia Edgar (złożonego z ead \"bogaty, dobrobytny\" i gar \"piedź\"). Podobnie jak większość nazw anglosaskiej, wygasła z użycia w późnym średniowieczu; jednak odrodzona została w XVIII wieku i została popularyzowana przez jej użycie jako postaci w książce Sir Waltera Scotta \"The Bride of Lammermoor\" (1819).</p>", "Edgar Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Edwardo": "<p>Eduardo to hiszpańska i portugalska forma męskiego imienia Edward. Inną wersją jest Duarte.</p>", "Evgenyi": "<p>Yevgeni (rosyjski: Евгений), również przetransliterowany jako Yevgeny, Yevgenii, Yevgeniy, Evgeniy, Yewgeny, Evgenii, Evgenii, Evgenyi lub Evgenij, jest rosyjską formą męskiego imienia Eugene. Krótka forma jest Zhenya (Женя), również przetłumaczana jako Jenya lub Shenya.</p>", "Erdinc": "<p>Erdinç to tureckie imię i nazwisko dla mężczyzn. Mieszkańcy imienia Erdinç to:</p>", "Enyinnaya": "<p>Enyinnaya to nigerijskie imię i nazwisko pochodzenia Igbo. To znaczy \"przyjaciel jego ojca\".</p>", "Edwin Humberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edwin</b>.</p><b>Edwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „pomyślność”, „szczęście” lub „przyjaciel”. Patronem tego imienia jest św. Edwin, król Northumbrii. Forma żeńska: <a href=\"https://pl.wikipedia.org/wiki/Edwina\" target=\"_blank\" rel=\"noopener noreferrer\">Edwina</a>", "Ehren": "<p>Ehren to imię. Wśród znanych osób z tej nazwy są: Ehren Earleywine, amerykański trener sportowy i administrator Ehren Kruger (ur. 1972), amerykański producent filmowy i scenarzysta Ehren McGhehey (ur. 1976), amerykańskiego wykonawcy akcji stuntów i aktor Ehren Painter (ur. 1998), angielski gracz rugby Ehren Wassermann (ur. 1980), amerykański piłkarz baseballu i trener Ehren Watada (ur. 1978), oficer wojskowy Kyle Ehren Snyder (ur. 1977),...</p>", "Edgar Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Eduard-Florin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eduard</b>.</p><p>Edwarda - męskie imię, pochodzące od angielsko-saksońskiego Ēadweard - ⁇ strzeganie bogactwa, szczęścia ⁇ (ead oznacza ⁇ szczęśliwy, kwitnący ⁇ , a weard tłumaczono jako ⁇ strogę ⁇).</p>", "Ernest Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ernest</b>.</p><b>Ernest</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego \"powaga, zapał, walka\". Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Ernest_z_Zwiefalten\" target=\"_blank\" rel=\"noopener noreferrer\">Święty Ernest</a> - opat i <a href=\"https://pl.wikipedia.org/wiki/M%C4%99czennicy_chrze%C5%9Bcija%C5%84scy\" target=\"_blank\" rel=\"noopener noreferrer\">męczennik</a> (zginął w 1148 roku).", "Emerson Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emerson</b>.</p><p>Emerson - nazwisko, nazwisko i toponim.</p>", "Edgar German": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edgar</b>.</p><b>Edgar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/germańskiego. Wywodzi się od staroangielskich ěad (majątek, bogactwo, szczęście), gard (obrońca, stróż) lub od germańskiego ed- (posiadanie, dziedzictwo). Oznacza: stróż, obrońca własności.", "Ethelbert": "<p>Æthelberht, Aethelbert lub Ethelbert to męskie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Enrico Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Enrico</b>.</p><p>Enrico (italicki: Enrico; 1020, Kazale-Monferrato, Markgrafstwo Monferrato - 14 marca 1045, Kazale-Monferrato) - markgraf Monferrato z domu Aleramici.</p>", "Eiichiro": "<p>Eiichiro, Eiichirō, Eiichiroou lub Eiichiroh (pisanie: 英一郎, 栄一郎 lub ⁇ 一郎) to męskie japońskie imię. Do wybitnych osób z nazwiskiem należą: Eiichiro Azuma, amerykański historyk Eiichiro Komatsu (小松 英一郎; ur. 1974), japoński naukowiec Eiichiro Funakoshi (船越 英一郎, ur. 1960), japoński aktor i telewizyjna osobowość Eiichirō Hasumi (羽住 英一郎 , ur. 1967), japońskiego reżysera filmowego Ishida Eiichiró (石田 英一 ⁇; 1903-1968), japończyka folklorysta i...</p>", "Efrain Rafael": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Efrain</b>.</p><p>Efraín to hiszpańskie imię męskie, krewny Efraima. Znani ludzie z nazwiska to: Efrain Chacurian (1924-2019), argentyński urodzony naturalny amerykański piłkarz Efraín Cortés (urodzony 1984), kolumbijski obrońca Efraín Escudero (urodzona 1986), meksykański walczyciel w mieszanych sztuk walki Efraín Flores (urodzono 1958), meksykański menedżer piłki nożnej Efraín Forero Triviño (1932-2022), kolumbijskie rower Efraín Goldenberg (1929-2025), peruwiański...</p>", "Edisson Fabian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edisson</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Edison</b>.</p><p>Thomas Alva Edison (11 lutego 1847 - 18 października 1931) był amerykańskim wynalazcą i przedsiębiorcą, który opracował wiele urządzeń, które miały duży wpływ na życie w 20 wieku. Był nazywany \"Majsterem Czarownic Menlo Park\" przez dziennikarza. Był jednym z pierwszych wynalazców, którzy zastosowali zasady produkcji w procesie twórczym.</p>", "Edward James": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edward</b>.</p><b>Edward</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia angielskiego. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">języku staroangielskim</a>:", "Erik Anders": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Erik</b>.</p><p>Erik może być: Erik, prawdziwe imię: Lê Trung Thành, wietnamski piosenkarz, były członek zespołu Monstar Erik Rhodes, amerykański aktor porno Erik, amerykański zawodowy walkacz</p>", "Eusebiu": "<p>Eusebiu lub Eusebie to rumuńskie imię męskie, które może odnosić się do: Eusebiu Camilar (1910-1965), rumuński pisarz Eusebiu Diaconu (ur. 1981), rumuński grecko-rumuński walczyk Eusebue Popovici (1863-1937), rumuńskiego polityka Eusebiu Popovici 1838-1922), rumuńczyka pisarz eusebiu Ștefănescu (1944-2015), rumuinskiego aktora Eusebiu Tudor (ur. 1974), rumuyńskiego kierownika półfalarza piłki nożnej</p>", "Ebrahim Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ebrahim</b>.</p><p>Ibrahim (arabski: إبراهيم, Ibrāhīm; również anglicized jako Ibraheem) jest arabskim imieniem Abrahama, wspólnego hebrajskiego patriarchy religii abrahamicznych, w tym judaizmu, chrześcijaństwa i islamu. Jest to powszechne męskie imię i nazwisko wśród muzułmanów i arabskich chrześcijan, pochodzące od imienia Abrahama lub Avram w judaizmie i chrześcijaństwie na Bliskim Wschodzie.</p>", "Elyahu": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eliahu</b>.</p><p>Eliahu lub Eliyahu (Hebrajskie: אליהו) jest męskie hebrajskie imię biblijnego pochodzenia. Oznacza to \"Mój Bóg jest Jahwe\" i pochodzi od proroka Eliasza, który według Biblii żył w okresie panowania króla Ahaba (9. w. p.n.e.).</p>", "Edison Fernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Edison</b>.</p><p>Thomas Alva Edison (11 lutego 1847 - 18 października 1931) był amerykańskim wynalazcą i przedsiębiorcą, który opracował wiele urządzeń, które miały duży wpływ na życie w 20 wieku. Był nazywany \"Majsterem Czarownic Menlo Park\" przez dziennikarza. Był jednym z pierwszych wynalazców, którzy zastosowali zasady produkcji w procesie twórczym.</p>", "Elendil": "Pojawia się w <i><a href=\"https://pl.wikipedia.org/wiki/Silmarillion\" target=\"_blank\" rel=\"noopener noreferrer\">Silmarillionie</a></i>, bardzo często wspominają o nim bohaterowie <i><a href=\"https://pl.wikipedia.org/wiki/W%C5%82adca_Pier%C5%9Bcieni\" target=\"_blank\" rel=\"noopener noreferrer\">Władcy Pierścieni</a></i>. Liczne informacje na jego temat znajdują się w <i>Dodatkach</i> do trzeciego tomu powieści oraz w <i><a href=\"https://pl.wikipedia.org/wiki/Niedoko%C5%84czone_opowie%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">Niedokończonych opowieściach</a></i>.", "Elbio": "<p>Elbio to hiszpańskie imię męskie. Znanymi osobami z nazwiska są: Elbio Anaya (1889-1986), argentyński generał Elbio Rosselli, uruguayski polityk Elbio Álvarez (ur. 1994), uruguayjski piłkarz</p>", "El Walid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Eleni": "<b>Eleni Tzoka</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ελένη Τζόκα) z domu <b>Milopulu</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Μυλοπούλου) (ur. <a href=\"https://pl.wikipedia.org/wiki/27_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">27 kwietnia</a> <a href=\"https://pl.wikipedia.org/wiki/1956\" target=\"_blank\" rel=\"noopener noreferrer\">1956</a> w <a href=\"https://pl.wikipedia.org/wiki/Bielawa\" target=\"_blank\" rel=\"noopener noreferrer\">Bielawie</a>) – <a href=\"https://pl.wikipedia.org/wiki/Polacy\" target=\"_blank\" rel=\"noopener noreferrer\">polska</a> <a href=\"https://pl.wikipedia.org/wiki/Piosenkarz\" target=\"_blank\" rel=\"noopener noreferrer\">piosenkarka</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Grecy\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Autor\" target=\"_blank\" rel=\"noopener noreferrer\">autorka tekstów</a> i <a href=\"https://pl.wikipedia.org/wiki/Kompozytor\" target=\"_blank\" rel=\"noopener noreferrer\">kompozytorka</a>. Wykonuje utwory w języku: polskim, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckim</a> i angielskim.", "Emeric-Ştefan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emeric</b>.</p><p>Emerich, Emeric, Emerick i Emerik są nazwiskami i nazwiską. Mogą one odnosić się do:</p>", "Emill": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emil</b>.</p><b>Emil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a> (<i>Aemilius</i>). Łacińskie słowo <i>aemulor</i> oznacza „rywalizujący”. Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Emil_z_Kordoby\" target=\"_blank\" rel=\"noopener noreferrer\">Emil z Kordoby</a> (†852), męczennik i święty katolicki wspominany 15 września.", "Erno": "<p>Ernő lub Erno to finowska i węgierska męska nazwa. Wśród znanych osób z nazwy znajdują się: Ernő Balogh (1897-1989), węgierski pianista, kompozytor, redaktor i wychowawca Ernő Bánk (1883-1962), węgarski malarz i nauczyciel Ernő Béres (1928-2023), węgarski biegacz na długą metę i olimpijski rywalizacyjny Ernő Csíki (1875-194?), węgrski entomolog Ernő Dohnányi (1877-1960), węgryjski dyrygent, kompozytora i pianista Ernő Foerk (1868-1934),...</p>", "Elisa": "<p>Elisa - skrócie i nazwa: Elisa - japońska piosenkarka Elisa - wolny audio-player dla systemów operacyjnych Linux, Windows i Android. Elisa (Electronic Intelligence Satellite) - system z czterech mikrosatelietów francuskiego ministerstwa obrony.</p>", "Efendi": "<b>Efendi</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_turecki\" target=\"_blank\" rel=\"noopener noreferrer\">turecki</a> tytuł oznaczający <i>pana</i>, <i>władcę</i>. Pierwotnie odnosił się do sułtana, potem do urzędników wysokiego szczebla jak <a href=\"https://pl.wikipedia.org/wiki/Bej\" target=\"_blank\" rel=\"noopener noreferrer\">bej</a> lub <a href=\"https://pl.wikipedia.org/wiki/Pasza_(urz%C4%85d)\" target=\"_blank\" rel=\"noopener noreferrer\">pasza</a>, następnie do osób posiadających wyuczony zawód i osób piśmiennych. Zniesiony w 1934 roku. Współcześnie używany po nazwisku tytuł grzecznościowy odpowiadający polskiemu „pan”.", "Emanuel-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emanuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Emi̇r Can": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emir</b>.</p><p>Emir (; arabski: أمير ʾAmīr [ʔæˈmiːr]), czasami przenoszony do Amir, Amier lub Ameer, jest szlachectwem lub szlachetnym urzędnikiem używanym w wielu regionach w krajach Arabskich. Dosłownie oznacza to dowódca, generał, król lub król.</p>", "Eugenio Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eugenio</b>.</p><p>Eugenio - IX-wieczny czynnik kościelny, biskup cardinalis Ostii z 878 roku. Uczestniczył w synodzie 879 roku w Rzymie, następnie był na katedrze w Konstantynopolu.</p>", "Elżbieta": "<b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Edyta": "<b>Edyta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a>. Imię pochodzące od staroangielskiego <i><b>ead</b></i> i starogermańskiego <i><b>od</b></i>- pomyślność, szczęście, oraz od staroangielskiego <i><b>gyth</b></i> i starogermańskiego <i><b>gunt</b></i> – walka.", "Eliza": "<b>Eliza</b> – skrócona forma <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Elisabeth</i>, czyli po polsku <a href=\"https://pl.wikipedia.org/wiki/El%C5%BCbieta\" target=\"_blank\" rel=\"noopener noreferrer\">Elżbiety</a>. W Polsce jest znane od <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a> jako imię literackie, a gwałtowną popularność zyskało w <a href=\"https://pl.wikipedia.org/wiki/Lata_70._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 70 XX wieku</a>.", "Eugenia": "<b>Eugenia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeńska forma męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Eugeniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Eugeniusz</a>.", "Elwira": "<b>Elwira</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niepewnej etymologii. Na ogół przypisywane jest jej pochodzenie z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gocki\" target=\"_blank\" rel=\"noopener noreferrer\">gockiego</a> i znaczenie „prawdziwie szlachetna”, ale mogłoby też oznaczać „opiekunka wszystkich”. Według najnowszych publikacji naukowych imię to wywodzi się jednak z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">języka arabskiego</a>, a przedostało się do Polski za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hiszpańskiego</a>, podobnie jak <a href=\"https://pl.wikipedia.org/wiki/Eleonora\" target=\"_blank\" rel=\"noopener noreferrer\">Eleonora</a>.", "Eleonora": "<b>Eleonora</b> – imię żeńskie nieustalonego pochodzenia; być może <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (może od <i>el</i> – „Bóg” oraz <i>or</i> – „światło”; czyli „Bóg mi światłem”), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (od <i>eleo</i> – „lituję się”).", "Estera": "<b>Estera</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Nosiła je <a href=\"https://pl.wikipedia.org/wiki/Estera_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">tytułowa bohaterka</a> <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Estery\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Estery</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֶסְתֵּר&#8206;). Imię to wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroperski\" target=\"_blank\" rel=\"noopener noreferrer\">staroperskiego</a> słowa <i>setarah</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">pers.</a>&#160;&#8207;ستاره&#8206;) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Gwiazda\" target=\"_blank\" rel=\"noopener noreferrer\">gwiazda</a>”; może mieć również rodowód akadyjski – od imienia bogini <a href=\"https://pl.wikipedia.org/wiki/Isztar\" target=\"_blank\" rel=\"noopener noreferrer\">Isztar</a>.", "Elena": "<b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272.", "Eryka": "<b>Eryka</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eryk\" target=\"_blank\" rel=\"noopener noreferrer\">Eryk</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>.", "Emiliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emilia</b>.</p>Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Edwarda": "<b>Edwarda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia angielskiego, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Edward\" target=\"_blank\" rel=\"noopener noreferrer\">Edward</a>. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">języku staroangielskim</a> słowo <i>ead</i> oznacza „pomyślność, dobrobyt, szczęście”, a także „obrońca”.", "Elfryda": "<b>Elfryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „moc elfa” (chroniona przez <a href=\"https://pl.wikipedia.org/wiki/Elf_(fantastyka)\" target=\"_blank\" rel=\"noopener noreferrer\">elfy</a>), a złożone z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskiego</a> słowa <i>ælf</i> połączonego z <i>þryð</i> – „siła, moc”.", "Eulalia": "<b>Eulalia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się ze złożenia słów εὐ („dobrze”) i λαλεῖν („mówić”), oznaczającego „dobrze mówiąca” lub „elokwentna”.", "Edeltrauda": "<b>Edeltruda</b>, <b>Edeltrauda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a>, nienotowane w Polsce w średniowieczu; obecnie występuje w zauważalnym stopniu w Polsce na obszarach zamieszkiwanych przez mniejszość niemiecką. Imię to powstało z połączenia członów <i>adal</i> – 'szlachetny ród' oraz <i>trud</i> – 'siła, potęga' i stanowi późniejszą wersję niemieckiego imienia <i>Adeltraud</i>.", "Emanuela": "<b>Emanuela</b>, <b>Manuela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Emanuel\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuel</a>, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hebrajskiego</a>.", "Ekaterina": "<p>Ekaterina to rosyjskie imię żeńskie i alternatywna transliteracja rosyjskiej Yekateriny. Katya i Katyusha są powszechnymi drobnymi formami Ekaterina.</p>", "Elvira": "<p>Microchera jest rodzajem ptaków z rodziny Trochilidae.</p>", "Erna": "<b>Erna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Skrócona forma imion <a href=\"https://pl.wikipedia.org/wiki/Ernesta\" target=\"_blank\" rel=\"noopener noreferrer\">Ernesta</a> i <a href=\"https://pl.wikipedia.org/wiki/Ernestyna\" target=\"_blank\" rel=\"noopener noreferrer\">Ernestyna</a>.", "Emila": "Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Eunika": "<b>Eunika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, składające się ze słów <i>eu</i> „dobrze” i <i>níke</i> „zwycięstwo”. Imię rozsławił <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, który nadał je w powieści <i><a href=\"https://pl.wikipedia.org/wiki/Quo_vadis\" target=\"_blank\" rel=\"noopener noreferrer\">Quo vadis</a></i> Eunice, ukochanej Petroniusza.", "Ema": "<b>Ema</b>, <b>Emma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia germańskiego, od imienia <i>Erma</i>, które było skróconą formą imion zaczynających się od <i>Erm-</i> i <i>Irm-</i>.", "Esther": "<p>Esther (Hebrajskie אֶסְתֵר/Ester/ʼEstēr, wietniską wersja: Étte lub Esther), zrodzona jako Hadassah, jest głównym bohaterem Biblii. Według Biblii była królową Żydów władzy perskiego króla Ahaswerusza (Ahaswerus).</p>", "Ernestyna": "<b>Ernestyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Ernest\" target=\"_blank\" rel=\"noopener noreferrer\">Ernest</a> oznaczającego „poważny, stanowczy”. W Kościele katolickim istnieją dwie patronki tego imienia.", "Eufemia": "<b>Eufemia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Złożone jest z elementów εὐ- („dobry”) i φήμη („wróżba”), i oznacza „dobrze wróżąca”, „pomyślnie wróżąca”, „przychylna”. W Polsce imię to zanotowano w XIII wieku. Nosiły je m.in. księżniczki piastowskie. Imię zdrabniano jako Ofka.", "Elmira": "<b>Elmira</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niejasnej etymologii.", "Eliana": "<p>Eliana Mihailishin Bezera (port. Eliana Michaelichen Bezerra; bardziej znana jako Eliana; rodzaj.</p>", "Ecaterina": "<p>Ecaterina to rumuńskie nazwisko dla kobiet, które oznacza Catherine. Do wybitnych osób z tym nazwiskiem należą: Ecaterina Andronescu (ur. 1948), rumuńska polityka i inżyniera Ecaterina Arbore (r.</p>", "Emiliya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emilia</b>.</p>Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Erwina": "<b>Erwina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Erwin\" target=\"_blank\" rel=\"noopener noreferrer\">Erwin</a>.", "Elzbieta": "<p>Elżbieta [ɛl ⁇ ˈbjɛta] lub Elžbieta może odnosić się do: Elżbiéta, Lublin Voivodeship, wioska w wschodniej Polsce Elżbietta-Kolonia, wiosko w wschodniej Polsce</p>", "Evgeniia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Evgenii</b>.</p><p>Yevgeni (rosyjski: Евгений), również przetransliterowany jako Yevgeny, Yevgenii, Yevgeniy, Evgeniy, Yewgeny, Evgenii, Evgenii, Evgenyi lub Evgenij, jest rosyjską formą męskiego imienia Eugene. Krótka forma jest Zhenya (Женя), również przetłumaczana jako Jenya lub Shenya.</p>", "Edmunda": "<b>Edmunda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Edmund\" target=\"_blank\" rel=\"noopener noreferrer\">Edmund</a>. Wywodzi się od słowa oznaczającego \"obrończyni, opiekunka majątku, bogactwa\".", "Elsa": "<p>Elsa może odnosić się do: Elsa (królowa lodowa), fikcyjna postać ELSA Speak, startup technologiczny Elsa, Texas, 182 miasto Elsa, asteroid</p>", "Erica": "<p>Erika (lat. Érica) - rozległy gatunek wieczniezielonych roślin rodziny Wereskowych.</p>", "Ekaterine": "<p>Ekaterine to żeńskie imię, które może odnosić się do: Ekaterina Chavchavadze (1816-1882), gruzińskiej księżniczki, ostatniej rządzącej księżniczce Księstwa Mingrelia Ekateriny Gabashvili (1851-1938), gruziński pisarz, feministka i reformator społeczny Keke Geladze ((1856/1858-1937), gruzińska matka Józefa Stalina Ekaterini Gorgodze (ur. 1991), gruzijska tenisa Ekaterino Kherkheulidze (ur. 1972), gruzianska polityka Ekateryn...</p>", "Evgeniya": "<p>Evgenia, Evgeniya, Yevgenia lub Yevgeniya jest imieniem żeńskim, które może odnosić się do:</p>", "Edita": "<p>⁇ Edita ⁇ - literacki kwartałowy czasopism w Westfalii (Niemcy). Revista jest wydawniana i edytowana przez poety i prozaika Aleksandra Barsukow.</p>", "Eufrozyna": "<b>Eufrozyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>euphrosýne</i> oznaczającego radość. Eufrosyne była jedną z mitologicznych <a href=\"https://pl.wikipedia.org/wiki/Charyty\" target=\"_blank\" rel=\"noopener noreferrer\">Gracji</a>, bogiń wdzięku i radości.", "Eligia": "<b>Eligia</b> – żeńska wersja <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eligiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Eligiusz</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"wybrany\".", "Edwina": "<b>Edwina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Edwin\" target=\"_blank\" rel=\"noopener noreferrer\">Edwin</a>. Wywodzi się od słów oznaczających \"pomyślność\", \"szczęście\" i \"przyjaciel\". Patronem tego imienia jest św. Edwin, król Northumbrii.", "Emiliana": "<b>Emiliana, Emilianna</b> - żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>. Patronką tego imienia w Kościele katolickim jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Emiliana\" target=\"_blank\" rel=\"noopener noreferrer\">św. Emiliana</a>, żyjąca w <a href=\"https://pl.wikipedia.org/wiki/VI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VI wieku</a>.", "Emine": "W rejonie przylądka Emine są ruiny <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznego</a> <a href=\"https://pl.wikipedia.org/wiki/Monaster\" target=\"_blank\" rel=\"noopener noreferrer\">monasteru</a> i twierdzy Emona. Jej nazwa pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytna_Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">starogreckiej</a> nazwy Starej Płaniny - <i>Aemon</i> (<i>Αίμος</i> - Aemos). Tę samą nazwę nosi też pobliska wieś <a href=\"https://pl.wikipedia.org/wiki/Emona\" target=\"_blank\" rel=\"noopener noreferrer\">Emona</a>.", "Estelle": "<p>Estelle: Estelle (Estelle Fanta Swaray) - brytyjska piosenkarka. Estelle - metoda formalnego opisu rozproszonych systemów.</p>", "Euzebia": "<b>Euzebia</b> – żeński odpowiednik męskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Euzebiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Euzebiusz</a>. Wywodzi się od greckiego wyrazu <i>eusébeia</i> – pobożność.", "Elodie": "<p>Elodie to francuskie kobiece imię, wariant Alodia, prawdopodobnie gotyckie imię z elementami Ala, może oznaczać \"inne\" lub \"wszystkie\", a od, \"bogaty, dziedzictwo\". Nazwa została rozpowszechniona poprzez czczenie św. Alodii, dziecka męczennika z IX wieku.</p>", "Elisabeta": "<p>Elisabeta jest rumuńskim imieniem dla kobiet, równoważnym z Elżbiotą (nazwa dana), i może odnosić się do: Elisabeta Abrudeanu Elisabeta Anghel Elisabeta Bǎbeanu Elisabeta Bostan Elisabeta Ionescu Elisabeta Lazăr Elisabeta Lipă Elisabeta Movilă Elisabeta Polihroniade Elisabeta Rizea Elisabeta Turcu Elisabeta Știrbey Dwie postacie królewskie są znane jako Elisabeta w rumunskim: Elisabeta Wied Elisabeth z Rumunii Pałac Elisabeta</p>", "Evghenia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Evgheni</b>.</p><p>Eugene jest powszechnym męskim imieniem, które pochodzi od greckiego εὐγενής (eugenēs), \"noble\", dosłownie \"dobrze urodzony\", od ε ⁇ (eu), \"dobrze\" i γένος (genos), \"rasy, pochodzenia, krewnych\". Gene to powszechne skrócenie.</p>", "Ernesta": "<b>Ernesta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ernest\" target=\"_blank\" rel=\"noopener noreferrer\">Ernest</a>.", "Esmira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Esmir</b>.</p><p>Esmir to bosniackie imię męskie. Na Bałkanach, Esmir jest popularny wśród Bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Evangelina": "<b>Ewangelina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Powstało ze złożenia <i>ευ</i> - „dobry” oraz <i>αγγελμα (angelma)</i> - „wiadomość, wieść, przesłanie” i oznacza „dobra nowina”.", "Eunice": "<p>Eunice (lat. Eunice) - rodzaj morskich wieloczęścianych robaków z rodziny Eunicidae oddziału Eunicida. Długość ciała wynosi od 0,5 do 300 cm; ciała składają się z wielu segmentów.</p>", "Elektra": "<p>Elektra Records - amerykańska wytwórnia nagrań dźwiękowych, zakupiona przez Warner Music Group. W 2004 roku został połączony z Atlantic Records Group, należącym również do WMG.</p>", "Emi̇ne": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emin</b>.</p><p>Emin Araz ogle Agalarów (azerb. Emin Araz, syn Ağalarov; rod.</p>", "Esperanza": "<p>Esperanza (hisp. Esperanza - ⁇ Najoda ⁇) - hiszpańskojęzyczne imię i toponim.</p>", "Emmanuelle": "<p>Emmanuelle jest głównym bohaterem serii francuskich lekkich filmów pornograficznych na podstawie postaci stworzonej przez Emmanuelle Arsan w powieści Emmanuelle (1959). Tylko filmy i filmy produkowane przez ASP (\"Alain Siritzky Productions\") firmy filmowej są oficjalne i w charakterze Arsan.</p>", "Eliane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elian</b>.</p>Do jego głównych dzieł należą: <i>De natura animalium</i> (<i>Περὶ ζῴων ἰδιότητος</i>) i <i>Varia historia</i> (<i>Ποικίλη ἱστορία</i>) czyli <i>O właściwościach zwierząt</i> i <i>Opowiastki rozmaite</i>. Pierwsze to opowieści o niezwykłych cechach i zaletach zwierząt, zawarte w 17 księgach, drugie to ujęte w 14 księgach anegdoty historyczne i przyrodnicze pochodzące z zaginionej literatury wcześniejszej. Oprócz szerokiej wiedzy tematycznej dają one wgląd w zakres poznania świata grecko-rzymskiego. Elian jest ponadto autorem zbioru 20 utworów <a href=\"https://pl.wikipedia.org/wiki/Epistolografia\" target=\"_blank\" rel=\"noopener noreferrer\">epistolarnych</a>, zatytułowanego <i>Listy wieśniaków</i> (<i>Epistulae rusticae</i>, gr. <i>Ἐπιστολαὶ ἀγροικικαί</i>), mającego szczególną wartość dzięki licznym cytatom z niezachowanych dzieł starszych autorów. Za zaginione uważa się jego niektóre pisma o charakterze filozoficznym (np. o opatrzności) oraz <a href=\"https://pl.wikipedia.org/wiki/Pamflet\" target=\"_blank\" rel=\"noopener noreferrer\">pamflet</a> na Heliogabala.", "Eliso": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elis</b>.</p><p>Elis - z Lichtenšteinu, utworzony w 2003 roku i wykonujący gotycki metal.</p>", "Eszter": "<p>Eszter jest węgierska nazwisko żony pochodzące z języka hebrajskiego (od Ester). może odnosić się do: Eszter Balint (ur. 1966), piosenkarka, skrzypiecka i aktorka Eszter Csákányi (ur. 1953), węgierskiej aktorki Eszter Hargittai (ur. 1973), naukowcy komunikacji na Uniwersytecie w Zurychu Eszter Hollosi, węgierska aktorka i reżyserka Eszster Krutzler (ur. 1981), węgelska ciężarosta Eszter Mátéfi (ur. 1966) węgierka, która...</p>", "Eteri": "<p>Eteri to gruzińskie imię dla kobiet i może odnosić się do: Eteri Andjaparidze, gruzińsko-amerykańskiego pianisty Eteri Lamoris, gruzińskiego-hiszpańskiego piosenkarza Eteri Liparteliani, gruzijskiej judoki Eteri Tutberidze, rosyjskiego trenerka patiningu figurkowego</p>", "Eleanora": "<p>Eleanora lub Eleonora mogą odnosić się do:</p>", "Evangeline": "<p>Evangelia, Evangeline, Evangelina - żeńskie imię pochodzące od starożytnego greckiego εὐαγγέλιον (⁇ bułachę, dobrą nowiny).</p>", "Eudokia": "<p>Eudoxia (w starożytnym greckim: Εὐδοξία, Eudoxía), Eudokia (Εὐδοκία, Eudokía, anglicized as Eudocia) lub Evdokia to kobiece imię, które pierwotnie oznaczało \"dobrą sławę lub osąd\" lub \"ta, której sławę czy osąd jest dobry\" w języku greckim. Słowiańskie formy nazwy to słowiańskie: Evdokiya (rosyjskie: Евдокия), Yevdokiya (ukraińskie: Євдокія); słowiańska południowa: Evdokija (Евдокија), Jevdokija (Јевдокија).</p>", "Edit": "<p>Edit (ang. edytować) - wieloznaczny termin: Edit - niemiecki czasopism literackie, wydany w Leipzczygu.</p>", "Emmanuela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emmanuel</b>.</p><b>Emmanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Symbol\" target=\"_blank\" rel=\"noopener noreferrer\">symboliczne</a> imię (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i> 'immanu 'el</i> – <i>Bóg jest z nami</i>), przypisywane przez <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">proroka</a> <a href=\"https://pl.wikipedia.org/wiki/Izajasz\" target=\"_blank\" rel=\"noopener noreferrer\">Izajasza</a> chłopcu, którego królowi <a href=\"https://pl.wikipedia.org/wiki/Achaz\" target=\"_blank\" rel=\"noopener noreferrer\">Achazowi</a> miała urodzić młoda kobieta (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Izajasza\" target=\"_blank\" rel=\"noopener noreferrer\">Iz</a> 7,14) w momencie poważnego zagrożenia dynastii. W chwili wygłoszenia proroctwa król <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Damaszku\" target=\"_blank\" rel=\"noopener noreferrer\">Damaszku</a>, <a href=\"https://pl.wikipedia.org/wiki/Resin\" target=\"_blank\" rel=\"noopener noreferrer\">Resin</a>, i król <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3lestwo_Izraela_(pa%C5%84stwo_p%C3%B3%C5%82nocne)\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a>, <a href=\"https://pl.wikipedia.org/wiki/Pekach\" target=\"_blank\" rel=\"noopener noreferrer\">Pekach</a>, oblegli Jerozolimę w ramach toczącej się <a href=\"https://pl.wikipedia.org/wiki/Wojna_syro-efraimska\" target=\"_blank\" rel=\"noopener noreferrer\">wojny syro-efraimskiej</a>. Emmanuel miał być znakiem Bożej łaski wobec Achaza, skutkującej niepowodzeniem koalicji.", "Elissa": "Według przekazu starożytnych historyków <a href=\"https://pl.wikipedia.org/wiki/Timajos\" target=\"_blank\" rel=\"noopener noreferrer\">Timajosa</a> i <a href=\"https://pl.wikipedia.org/wiki/Pompejusz_Trogus\" target=\"_blank\" rel=\"noopener noreferrer\">Pompejusza Trogusa</a> w IX wieku p.n.e. z <a href=\"https://pl.wikipedia.org/wiki/Tyr_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyru</a> miała zbiec grupa jego mieszkańców na północne wybrzeża <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>, niedaleko <a href=\"https://pl.wikipedia.org/wiki/Fenicja\" target=\"_blank\" rel=\"noopener noreferrer\">fenickiej</a> kolonii <a href=\"https://pl.wikipedia.org/wiki/Utyka\" target=\"_blank\" rel=\"noopener noreferrer\">Utyki</a>. Przywódczynią kolonistów była Dydona (zwana też Eliszą lub Elissą), która uciekła, ponieważ jej brat <a href=\"https://pl.wikipedia.org/wiki/Pigmalion_z_Tyru\" target=\"_blank\" rel=\"noopener noreferrer\">Pigmalion</a> zabił jej męża Acharbasa (w <i>Eneidzie</i>: Sycheusza lub Sycheja). W jej otoczeniu znajdowali się bogaci Fenicjanie (nie jest wyjaśnione dlaczego, prawdopodobnie to oni uciekali), w drodze zatrzymali się na <a href=\"https://pl.wikipedia.org/wiki/Cypr_(wyspa)\" target=\"_blank\" rel=\"noopener noreferrer\">Cyprze</a>, skąd zabrano arcykapłana i dużą grupę dziewcząt. Gdy wysiedli na ląd, otoczyli ich miejscowi <a href=\"https://pl.wikipedia.org/wiki/Numidia\" target=\"_blank\" rel=\"noopener noreferrer\">Numidyjczycy</a> i zaczęły się pertraktacje. Ostatecznie Dydonie użyczono takiego skrawka ziemi na wybrzeżu, jaki obejmie skóra wołu. Dydona pocięła więc ją na wąskie paski i objęła nimi miejsce, na którym wzniesiono Byrsę (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;βύρσα – skóra) – <a href=\"https://pl.wikipedia.org/wiki/Akropol\" target=\"_blank\" rel=\"noopener noreferrer\">akropol</a> Kartaginy. Imię Elissy zostało zmienione przez tubylców na Dydona, co oznacza „wędrowniczka”. Wcześniejsze imię pochodzi od fenickiego bóstwa <a href=\"https://pl.wikipedia.org/wiki/El\" target=\"_blank\" rel=\"noopener noreferrer\">Ela</a> – być może więc Elissa była w Fenicji jego kapłanką.", "Evita": "<p>Evita: Music from the Motion Picture (Evita: Muzyka z kin) - soundtrack do filmu Evita, który stał się trzecim soundtrakiem, w tym utworem Madonny i 13 nagraniami w czasie jej kariery. Soundtrack został wydany w 1996 roku.</p>", "Esme": "<p>Esmé (zwykle Esme) lub Esmée jest nazwą pochodzącą z poprzedniego przyczynę starofrancuskiego czasownika esmer, \"cenić\", co oznacza \"oceniony\" lub podobnie \"miłowany\". Pierwotnie męskie imię, Esmé stało się imieniem kobiecym w połowie XX wieku.</p>", "Edeltruda": "<b>Edeltruda</b>, <b>Edeltrauda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a>, nienotowane w Polsce w średniowieczu; obecnie występuje w zauważalnym stopniu w Polsce na obszarach zamieszkiwanych przez mniejszość niemiecką. Imię to powstało z połączenia członów <i>adal</i> – 'szlachetny ród' oraz <i>trud</i> – 'siła, potęga' i stanowi późniejszą wersję niemieckiego imienia <i>Adeltraud</i>.", "Emese": "<p>Emese (Czuwańska: Amăšĕ; wymowa: /·E-mè-sẹ·/) jest legendarną postacią węgierską i środkowoeuropejską.</p>", "Erzsébet": "<p>Erzsébet jest miastem w hrabstwie Baranya w Węgrzech. Miasto ma powierzchnię 9,75 km2, liczba ludności w 2010 roku wynosi 319 osób, a jego gęstość 33 osoby/km2.</p>", "Elisaveta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elisavet</b>.</p><p>Elizabet to imię kobiece, odmiana hebrajskiej nazwy Elishewa (אֱלִישֶׁבַע), co oznacza \"Mój Bóg jest przysięgą\" lub \"Mój Boże jest obfitością\", jak to tłumaczy Septuaginta.</p>", "Eter": "<b>Eter</b> (<a href=\"https://pl.wikipedia.org/wiki/Alfabet_deseret\" target=\"_blank\" rel=\"noopener noreferrer\">deseret</a> 𐐀𐐛𐐇𐐡, 𐐁𐐛𐐇𐐡) – imię męskie występujące w wyznaniach należących do <a href=\"https://pl.wikipedia.org/wiki/Ruch_%C5%9Bwi%C4%99tych_w_dniach_ostatnich\" target=\"_blank\" rel=\"noopener noreferrer\">ruchu świętych w dniach ostatnich</a> (mormonów).", "Elle": "<p>Elle (czytamy ⁇ Эль ⁇ , z francuskiego - ⁇ Она ⁇) - francuski tygodniowy czasopism kobiet o modzie, pięknie, wolnym czasie i zdrowiu, wydany od 1945 roku.</p>", "Elma": "<p>Elasto Mania - gra komputerowa, 2D-symulator mototrialu, opracowany w 2000 roku węgierskim programistą Balazem Rózsem (Balázs Rózsa) i jego bratem Csaba Rózsem. Odróżniającą cechą gry jest wypracowany fizyczny model motoryzacji.</p>", "Elona": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elon</b>.</p><b>Elon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> אֵילֹן) – postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijna</a>, według <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_S%C4%99dzi%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Sędziów</a> (Sdz 12,11-12) dziesiąty <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziowie_(Biblia)\" target=\"_blank\" rel=\"noopener noreferrer\">sędzia</a> <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a>. Pochodził z plemienia <a href=\"https://pl.wikipedia.org/wiki/Zabulon\" target=\"_blank\" rel=\"noopener noreferrer\">Zebulona</a>, objął rządy po śmierci <a href=\"https://pl.wikipedia.org/wiki/Ibsan\" target=\"_blank\" rel=\"noopener noreferrer\">Ibsana</a>. Panował przez dziesięć lat. Po śmierci został pochowany w Ajjalonie na terytorium Zebulonitów, utożsamianym z Chirbet el-Lon w <a href=\"https://pl.wikipedia.org/wiki/Galilea\" target=\"_blank\" rel=\"noopener noreferrer\">Galilei</a>. Jego następcą został <a href=\"https://pl.wikipedia.org/wiki/Abdon_(s%C4%99dzia)\" target=\"_blank\" rel=\"noopener noreferrer\">Abdon</a>.", "Emmanuella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emanuela</b>.</p><b>Emanuela</b>, <b>Manuela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Emanuel\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuel</a>, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hebrajskiego</a>.", "Eustachia": "<b>Eustachia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia greckiego, żeński odpowiednik imion <a href=\"https://pl.wikipedia.org/wiki/Eustachy\" target=\"_blank\" rel=\"noopener noreferrer\">Eustachy</a> i <a href=\"https://pl.wikipedia.org/wiki/Eustachiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Eustachiusz</a>.", "Emilianna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emiliana</b>.</p><b>Emiliana, Emilianna</b> - żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>. Patronką tego imienia w Kościele katolickim jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Emiliana\" target=\"_blank\" rel=\"noopener noreferrer\">św. Emiliana</a>, żyjąca w <a href=\"https://pl.wikipedia.org/wiki/VI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VI wieku</a>.", "Ewangelina": "<b>Ewangelina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Powstało ze złożenia <i>ευ</i> - „dobry” oraz <i>αγγελμα (angelma)</i> - „wiadomość, wieść, przesłanie” i oznacza „dobra nowina”.", "Esfir": "<p>Esfir lub Esphyr (rosyjski: Эсфирь) to rosyjskie imię kobiety, forma nazwiska Esther.</p>", "Ermina": "<p>Ermina to kobiece imię. Do wybitnych osób z nazwiskiem należą: Ermina Lekaj Prljaskaj (ur. 1971), chorwacka polityka Ermina Zaenah (1927-2009), indonezyjska aktorka i producent.</p>", "Enya": "<p>Enia (ang. Enya, pełne imię Ennie Padraigine Nie Brennan, irlandzka.</p>", "Ewa Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ewa</b>.</p><b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Emmi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emmy</b>.</p><p>⁇ Emmy ⁇ (ang. Emmy Award) - międzynarodowa nagroda telewizyjna, przyznawana w USA.</p>", "Emira": "<p>Emir (; arabski: أمير ʾAmīr [ʔæˈmiːr]), czasami przenoszony do Amir, Amier lub Ameer, jest szlachectwem lub szlachetnym urzędnikiem używanym w wielu regionach w krajach Arabskich. Dosłownie oznacza to dowódca, generał, król lub król.</p>", "Elianna": "<p>Eliana, Elianna, אֱלִיעָנָה (Hebrajczy), Ηλιάνα (Grzeczy), إليانا (Arabic), jest imieniem żeńskim znalezione w języku hebrajskim, włoskim, portugalskim i hiszpańskim.</p>", "Edda": "<b>Edda</b> – włoska forma norweskiego lub szwedzkiego <i>Hedda</i>, co stanowi zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Jadwiga\" target=\"_blank\" rel=\"noopener noreferrer\">Hedwig</a>, czyli germańskiej formy imienia <a href=\"https://pl.wikipedia.org/wiki/Jadwiga\" target=\"_blank\" rel=\"noopener noreferrer\">Jadwiga</a>. Edda jest przede wszystkim jednak znana jako część nazwy <i><a href=\"https://pl.wikipedia.org/wiki/Edda_starsza\" target=\"_blank\" rel=\"noopener noreferrer\">Eddy poetyckiej</a></i>, najstarszego zabytku <a href=\"https://pl.wikipedia.org/wiki/Literatura_islandzka\" target=\"_blank\" rel=\"noopener noreferrer\">piśmiennictwa islandzkiego</a>.", "Eglė": "<b>Eglė</b> lub <b>Eglija</b> – żeńskie imię bałtyckie. Z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">lit.</a> <i>eglė</i>, co znaczy <i>świerk</i>.", "Emanuella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emanuell</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emanuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Elfreda": "<p>Elfriede, znana również jako Elfreda, Elfrida, Alfrida, Aelfrida, Elfrieda, Elftrude, Elftraut wśród innych wariantów, jest nazwiskiem żeńskim, pochodzącym od Ælfþryð (Aelfthryth) oznaczającego \"silność siebie\". Nazwa ta w średniowieczu nie była już w modzie, a w XIX wieku odzyskała się zarówno w Anglii, jak i w Niemczech.</p>", "Ekaterini": "<p>Ekaterini lub Aikaterini (grecki: Αικατερίνη, Aikaterínē) to greckie imię żeńskie. To oryginalna grecka forma Katherine.</p>", "Emy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emi</b>.</p>W lutym 2010 w mediach pojawiły się informacje, że EMI z powodu długów sprzeda legendarne <a href=\"https://pl.wikipedia.org/wiki/Abbey_Road_Studios\" target=\"_blank\" rel=\"noopener noreferrer\">studio Abbey Road</a>, w którym nagrywali między innymi <a href=\"https://pl.wikipedia.org/wiki/The_Beatles\" target=\"_blank\" rel=\"noopener noreferrer\">The Beatles</a>.", "Eva-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eva</b>.</p><p>⁇ Eva ⁇ - single Nightwish z albumu Dark Passion Play, wydany w 2007 roku i rozpowszechniony przez internet. Wszystkie pieniądze zebrane z sprzedaży zostały przekazane na dobroczynność.</p>", "Elżbieta Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elżbieta</b>.</p><b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Escada": "<p>Escada - niemiecka firma założona w 1976 roku w Mnichobie, Niemczech przez małżonków Margaret i Wolfgang Lei, producent mody, perfumerii, akceswarów i innych przedmiotów luksusowych. Od 2009 roku należy do rodziny Lakshmi Mittala.</p>", "Emiko": "<b>Emiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えみこ, エミコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Eset": "<p>ESET, s r.o. Firma - twórca oprogramowania antywirusowego i rozwiązań w dziedzinie bezpieczeństwa komputerowego dla użytkowników korporacyjnych i domowych, założona w 1992 roku.</p>", "Ekateryna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ekaterina</b>.</p><p>Ekaterina to rosyjskie imię żeńskie i alternatywna transliteracja rosyjskiej Yekateriny. Katya i Katyusha są powszechnymi drobnymi formami Ekaterina.</p>", "Ewita": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Evita</b>.</p><p>Evita: Music from the Motion Picture (Evita: Muzyka z kin) - soundtrack do filmu Evita, który stał się trzecim soundtrakiem, w tym utworem Madonny i 13 nagraniami w czasie jej kariery. Soundtrack został wydany w 1996 roku.</p>", "Elisavet": "<p>Elizabet to imię kobiece, odmiana hebrajskiej nazwy Elishewa (אֱלִישֶׁבַע), co oznacza \"Mój Bóg jest przysięgą\" lub \"Mój Boże jest obfitością\", jak to tłumaczy Septuaginta.</p>", "Ernestina": "<p>Ernestina jest miastem w brazylijskim stanie Rio Grande do Sul. Miasto to ma powierzchnię 239,147 km2, liczba ludności w 2007 roku wynosi 3010 osób, a jego gęstość 12,59 osób/km2.</p>", "Eléonore": "<p>Eleanor (francuski: Eleanor)  - To jest Eléonore.</p>", "Ewarysta": "<b>Ewarysta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ewaryst\" target=\"_blank\" rel=\"noopener noreferrer\">Ewaryst</a>.", "Emillia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emilia</b>.</p>Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Eunseo": "<p>WJSN lub Cosmic Girls (Korejski: 우주소녀; Romaja: Ujusonyeo; Han-Vietnam: Universe girl) to koreańska grupa muzyczna utworzona i zarządzana przez Starship Entertainment i Yuehua Entertainment, która powstała w 2016 roku. Pierwotnie zespół składał się z 13 członków, w tym 10 członków z Korei, 3 członków Chin.</p>", "Eudoksja": "<b>Eudoksja</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ευδοξία) – imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik męskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eudoksjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Eudoksjusz</a>. Oznacza „dobra sława”, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;εὐ (<i>ew</i>, „dobrze”) i δόξα (doksa, „sława, chwała”).", "Eni": "<p>Eni SpA pronounced Italian: [ˈɛːni] (NYSE: E) jest jego wielorządową firmą naftową i gazową. Eni ma swoją działalność w 70 krajach i jest obecnie największą włoską firmą przemysłową. Ma ona kapitał rynkowy 87,700,000,000 euro (USD 138 miliardów), w dniu 24 lipca 2008 roku.</p>", "Emilya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emily</b>.</p><p>Emily Brontë Emily Osment Emily Dickinson Emily, wietnamskiej piosenkarki</p>", "Era": "<p>Era - projekt muzyczny w stylu new-age, założony w 1996 roku przez francuskiego kompozytora i multiinstrumentalistę (klawiatury, gitary) Erica Levy'ego.</p>", "Ewalda": "<b>Ewalda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Ewald\" target=\"_blank\" rel=\"noopener noreferrer\">Ewald</a>. Wywodzi się ze złożenia słów <i>eo</i> – „prawo” i <i>wald</i> – „rządzić”, „panować”. Jego znaczenie można interpretować jako „panująca sprawiedliwie, w zgodzie z prawem”. Patronami tego imienia są bracia śwśw. Ewald Biały i Ewald Czarny (<a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII wiek</a>), wspominani 3 października.", "Elfi": "<p>Elfi, Elfie i Elphie to imiona kobiet. Elfi jest również krótką formą (hipokoryzm) Elfriede.</p>", "Erazma": "<b>Erazma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Erazm\" target=\"_blank\" rel=\"noopener noreferrer\">Erazm</a>, wywodzącego się od greckiego <i>Erasmōs</i>, co oznacza „godny miłości, miły”.", "Emanuelle": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emanuell</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emanuel</b>.</p><b>Emanuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa עִמָּנוּאֵל oznaczającego „Bóg z nami”. Imię mesjasza oraz kilku świętych katolickich. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Emanuela\" target=\"_blank\" rel=\"noopener noreferrer\">Emanuela</a>.", "Elba": "<p>Elba jest wyspą wśródziemnomorską w Toskanii, Włochy, oddaloną 20 km (12 mi) od przybrzeżnego miasteczka Piombino. Jako największa z wysp Tuscan, wyspa Elba jest również częścią Parku Narodowego Wysp Toskanych i jest trzecim największym wyspą w Włoszech po wyspach Scylii i Sardenii.</p>", "Elvia": "<p>Elvia jest ptaszką w rodzinie Geometridae.</p>", "Edytta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Edyta</b>.</p><b>Edyta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a>. Imię pochodzące od staroangielskiego <i><b>ead</b></i> i starogermańskiego <i><b>od</b></i>- pomyślność, szczęście, oraz od staroangielskiego <i><b>gyth</b></i> i starogermańskiego <i><b>gunt</b></i> – walka.", "Elaina": "<p>Elena to popularne kobiece imię z pochodzenia greckiego. Nazwa oznacza \"światło świecące\".</p>", "Ediie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Edie</b>.</p><p>Edie to kobiece imię, często diminutiwna forma (hipokoryzm) Edith, a także nazwisko. Może odnosić się do:</p>", "Ericka": "<p>Ericka, czyli w francuskim Éricka, to imię dziewczyny, które jest wariantem Erica i Eriki. Mieszkańcy nazwiska to: Ericka Huggins Ericka Bareigts Ericka Hart Ericka Hunter Ericka Beckman Ericka Dunlap</p>", "Eftychia": "<p>Eutychia (grecki: ευτυχία), fonetycznie przetransliterowana jako Eftychia lub Eftichia () jest greckie nazwisko żeńskie, oznaczające \"szczęście\". Pochodzi od greckiego ε ⁇ (dobry) i τύχη (szczęście).</p>", "Electra": "<p>W mityce greckiej Electra, znana również jako Elektra (; starożytny grecki: ⁇ λέκτρα, latynikowany: Ēléktrā, n.e. 'amber'; [ɛː.lék.traː]) jest jedną z najbardziej popularnych postaci mitycznych w dramatyce.</p>", "Elitsa": "<p>Elitsa (bułgarski: Елица) to bułgarskie imię żeńskie, które może odnosić się do Elitsa Kostova (ur. 1990), bułgarskiej tenistki Elitsa Todorova (ur., 1977), bułgarskich piosenkarki ludowej i perkusyjczyki Elitsa &amp; Stoyan, bułgarskiego muzycznego duo Elitsa Vasileva (ur. 1990, bułgarska piłkarka siatkówka Elitsa Yankova (ur.).</p>", "Etsuko": "<b>Etsuko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えつこ, エツコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Erzsebet": "<p>Elizabet to imię kobiece, odmiana hebrajskiej nazwy Elishewa (אֱלִישֶׁבַע), co oznacza \"Mój Bóg jest przysięgą\" lub \"Mój Boże jest obfitością\", jak to tłumaczy Septuaginta.</p>", "Eriko": "<b>Eriko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えりこ, エリコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Eira": "<p>Tyra (lat. Eira barbara) - gatunek drapieżników mleczarzy z rodziny kumek (Mustelidae), rozmieszczonych w Ameryce Środkowej i Południowej.</p>", "Eilidh": "<p>Eilidh to szkocka gaelicka imiona żeńskie. Chociaż jest to odpowiednik Ellie, zazwyczaj jest anglicizowana jako Helen.</p>", "Eiko": "<b>Eiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;えいこ, エイコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Elze": "<p>Elze jest gminą w hildesheimskim dzielnicy w niemieckim stanie Niedersachsen. Miasto to ma powierzchnię 47,71 km2.</p>", "Etelka": "<p>Etelka lub Etelke to węgierska nazwa. Jest to kobiecy ekwiwalent Etele, wariant Attila.</p>", "Eliz": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eliza</b>.</p><b>Eliza</b> – skrócona forma <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Elisabeth</i>, czyli po polsku <a href=\"https://pl.wikipedia.org/wiki/El%C5%BCbieta\" target=\"_blank\" rel=\"noopener noreferrer\">Elżbiety</a>. W Polsce jest znane od <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a> jako imię literackie, a gwałtowną popularność zyskało w <a href=\"https://pl.wikipedia.org/wiki/Lata_70._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 70 XX wieku</a>.", "Eugeniya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eugenia</b>.</p><b>Eugenia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeńska forma męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Eugeniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Eugeniusz</a>.", "Eta": "<b>Eta</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;ἦτα, pisana <b>Ηη</b>) – siódma <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a> oznaczająca w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starogrecki\" target=\"_blank\" rel=\"noopener noreferrer\">języku starogreckim</a> długą „ē” (długie „e”). W greckim systemie liczbowym oznacza liczbę <a href=\"https://pl.wikipedia.org/wiki/8_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">8</a>.", "Eugeniia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eugenia</b>.</p><b>Eugenia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeńska forma męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Eugeniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Eugeniusz</a>.", "Eliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elia</b>.</p><p>Elia Group - belgijska firma, która jest operatorem linii przesyłania energii elektrycznej o wysokiej napięciu. Pracuje w Belgii (Elia Transmission Belgium) i Niemczech (50Hertz Transmission), pod jej kierownictwem znajduje się również interkonektor Nemo Link między Belgią a Wielką Brytanią.</p>", "Emmie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emmi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emmy</b>.</p><p>⁇ Emmy ⁇ (ang. Emmy Award) - międzynarodowa nagroda telewizyjna, przyznawana w USA.</p>", "Eila": "<p>Eila może odnosić się do: Eila Campbell (1915-1994), angielskiej geografa i kartografa Eila Hiltunen (1922-2003), fińskiej rzeźbiarzy Eila Ilmatar Juutilainen, postaci z anime Strike Witches Eila Kivikk'aho (1921-2004), fińskiej poetki Eila Pellinen (1938-1977), fińskiej piosenkarki Eila Roine (1931-2025), fińskiego aktorki Eila C. Skinner, amerykańskiego onkologa urologicznego i chirurga Eila (film), fiński film z 2003 roku</p>", "Ewdokia": "<b>Eudokia</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Εὐδοκία) – imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;ευδοκεω (<i>eudokeo</i>), co według niektórych źródeł oznacza „być bardzo zadowolonym, być zadowolonym”, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;ευ – „dobra” i δοκεω (<i>dokeo</i>) – „myśleć, wyobrażać sobie, przypuszczać”, według innych – \"życzliwość\". Jej ludową formą rosyjską jest <i><b>Awdotia</b></i>. W polskiej literaturze Eudokia jest utożsamiana z <a href=\"https://pl.wikipedia.org/wiki/Eudoksja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Eudoksją</a>.", "Etty": "<p>Etty, Ettie lub Etti to kobiece imię, często krótka wersja Esther. To też nazwisko.</p>", "Epifania": "<b>Epifania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Epifaniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Epifaniusz</a> lub <a href=\"https://pl.wikipedia.org/wiki/Epifani\" target=\"_blank\" rel=\"noopener noreferrer\">Epifani</a>, pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>epifaneia</i> – objawienie, ukazanie się.", "Enia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Enya</b>.</p><p>Enia (ang. Enya, pełne imię Ennie Padraigine Nie Brennan, irlandzka.</p>", "Egle": "<b>Eglė</b> lub <b>Eglija</b> – żeńskie imię bałtyckie. Z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">lit.</a> <i>eglė</i>, co znaczy <i>świerk</i>.", "Eleana": "<p>Eleana to kobiece imię.</p>", "Elyana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elyan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elian</b>.</p>Do jego głównych dzieł należą: <i>De natura animalium</i> (<i>Περὶ ζῴων ἰδιότητος</i>) i <i>Varia historia</i> (<i>Ποικίλη ἱστορία</i>) czyli <i>O właściwościach zwierząt</i> i <i>Opowiastki rozmaite</i>. Pierwsze to opowieści o niezwykłych cechach i zaletach zwierząt, zawarte w 17 księgach, drugie to ujęte w 14 księgach anegdoty historyczne i przyrodnicze pochodzące z zaginionej literatury wcześniejszej. Oprócz szerokiej wiedzy tematycznej dają one wgląd w zakres poznania świata grecko-rzymskiego. Elian jest ponadto autorem zbioru 20 utworów <a href=\"https://pl.wikipedia.org/wiki/Epistolografia\" target=\"_blank\" rel=\"noopener noreferrer\">epistolarnych</a>, zatytułowanego <i>Listy wieśniaków</i> (<i>Epistulae rusticae</i>, gr. <i>Ἐπιστολαὶ ἀγροικικαί</i>), mającego szczególną wartość dzięki licznym cytatom z niezachowanych dzieł starszych autorów. Za zaginione uważa się jego niektóre pisma o charakterze filozoficznym (np. o opatrzności) oraz <a href=\"https://pl.wikipedia.org/wiki/Pamflet\" target=\"_blank\" rel=\"noopener noreferrer\">pamflet</a> na Heliogabala.", "Essi": "<p>Essi to fińskie imię. Essi jest skrótem perskiego imienia Esther, co oznacza gwiazdę.</p>", "Ekspedyta": "<b>Ekspedyta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od czasownika <i>expedio</i> – \"uwolnić, wyzwolić z więzów\". <i>Expeditus</i> zaś oznacza \"wolny, lekko ubrany, lekkozbrojny, szybki, zwinny\". Jest to żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Ekspedyt\" target=\"_blank\" rel=\"noopener noreferrer\">Ekspedyt</a>, a patronem tego imienia jest św. Ekspedyt (św. Wierzyn), patron spraw pilnych, nie cierpiących zwłoki.", "Emily-Rose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emily</b>.</p><p>Emily Brontë Emily Osment Emily Dickinson Emily, wietnamskiej piosenkarki</p>", "Edie": "<p>Edie to kobiece imię, często diminutiwna forma (hipokoryzm) Edith, a także nazwisko. Może odnosić się do:</p>", "Eva Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eva</b>.</p><p>⁇ Eva ⁇ - single Nightwish z albumu Dark Passion Play, wydany w 2007 roku i rozpowszechniony przez internet. Wszystkie pieniądze zebrane z sprzedaży zostały przekazane na dobroczynność.</p>", "Elyssa": "<p>Elyssa to imię. Znanymi osobami z imieniem są: Elyssa Davalos (ur. 1959), amerykańska aktorka Elyssa East (ur.</p>", "Evguenia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Evgueni</b>.</p><p>Eugene jest powszechnym męskim imieniem, które pochodzi od greckiego εὐγενής (eugenēs), \"noble\", dosłownie \"dobrze urodzony\", od ε ⁇ (eu), \"dobrze\" i γένος (genos), \"rasy, pochodzenia, krewnych\". Gene to powszechne skrócenie.</p>", "Emilina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emil</b>.</p><b>Emil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a> (<i>Aemilius</i>). Łacińskie słowo <i>aemulor</i> oznacza „rywalizujący”. Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Emil_z_Kordoby\" target=\"_blank\" rel=\"noopener noreferrer\">Emil z Kordoby</a> (†852), męczennik i święty katolicki wspominany 15 września.", "Esthera": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Esther</b>.</p><p>Esther (Hebrajskie אֶסְתֵר/Ester/ʼEstēr, wietniską wersja: Étte lub Esther), zrodzona jako Hadassah, jest głównym bohaterem Biblii. Według Biblii była królową Żydów władzy perskiego króla Ahaswerusza (Ahaswerus).</p>", "Ermine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ermin</b>.</p><p>Ermin to bosniackie imię męskie. Na Bałkanach Ermin jest popularny wśród Bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Eunica": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eunika</b>.</p><b>Eunika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, składające się ze słów <i>eu</i> „dobrze” i <i>níke</i> „zwycięstwo”. Imię rozsławił <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, który nadał je w powieści <i><a href=\"https://pl.wikipedia.org/wiki/Quo_vadis\" target=\"_blank\" rel=\"noopener noreferrer\">Quo vadis</a></i> Eunice, ukochanej Petroniusza.", "Emilla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emila</b>.</p>Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Emie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emi</b>.</p>W lutym 2010 w mediach pojawiły się informacje, że EMI z powodu długów sprzeda legendarne <a href=\"https://pl.wikipedia.org/wiki/Abbey_Road_Studios\" target=\"_blank\" rel=\"noopener noreferrer\">studio Abbey Road</a>, w którym nagrywali między innymi <a href=\"https://pl.wikipedia.org/wiki/The_Beatles\" target=\"_blank\" rel=\"noopener noreferrer\">The Beatles</a>.", "Ermelinda": "<b>Ermelinda</b>, Irmelinda, <i>Hermelinda</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, składające się z członów: <i>Ermen–</i>, od germ. <i>ermana</i> („wielki, wszechogarniający” – imię <a href=\"https://pl.wikipedia.org/wiki/P%C3%B3%C5%82b%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">półboga</a> germańskiego) oraz <i>lind</i> – „giętka, miękka, łagodna, przyjazna”, może też „<a href=\"https://pl.wikipedia.org/wiki/Tarcza_(uzbrojenie)\" target=\"_blank\" rel=\"noopener noreferrer\">tarcza</a> z drewna <a href=\"https://pl.wikipedia.org/wiki/Lipa\" target=\"_blank\" rel=\"noopener noreferrer\">lipowego</a>”.", "Eskada": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Escada</b>.</p><p>Escada - niemiecka firma założona w 1976 roku w Mnichobie, Niemczech przez małżonków Margaret i Wolfgang Lei, producent mody, perfumerii, akceswarów i innych przedmiotów luksusowych. Od 2009 roku należy do rodziny Lakshmi Mittala.</p>", "Elisa-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elisa</b>.</p><p>Elisa - skrócie i nazwa: Elisa - japońska piosenkarka Elisa - wolny audio-player dla systemów operacyjnych Linux, Windows i Android. Elisa (Electronic Intelligence Satellite) - system z czterech mikrosatelietów francuskiego ministerstwa obrony.</p>", "Eleonóra": "<p>Eleanor () to żeńskie imię, pochodzące z starofrancuskiej adaptacji starej prowencalski nazwy Aliénor. Było to imię wielu kobiet z rodziny królewskiej i szlachty w Europie Zachodniej w średniowieczu.</p>", "Erika Tatiana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Erika</b>.</p><b>Eryka</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eryk\" target=\"_blank\" rel=\"noopener noreferrer\">Eryk</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>.", "Eylul": "<p>Eylül to tureckie imię żeńskie oznaczające września. Wśród znanych osób z nazwiskiem są: Eylül Akarçeşme (ur. 1999), turecki piłkarz siatkówki Eylül Aslan, turecki fotograf Eylül Cansın (1992-2015), kobieta turka transseksualna, której samobójczy zgon spowodował protesty i wezwania do międzynarodowej równości LGBT w społeczeństwie Eylül Elgalp (ur. 1991), turecki gracz piłki nożnej</p>", "Efrema": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Efrem</b>.</p><b>Efrem</b>, <b>Efraim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego słowa <i>Ephrayim</i> oznaczającego „przynoszący dobry owoc”. W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> był synem Józefa i <a href=\"https://pl.wikipedia.org/wiki/Asenat\" target=\"_blank\" rel=\"noopener noreferrer\">Asenat</a>, twórcą jednego z plemion Izraela. Ogłoszono siedmiu świętych o tym imieniu.", "Edeltrud": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Edeltruda</b>.</p><b>Edeltruda</b>, <b>Edeltrauda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a>, nienotowane w Polsce w średniowieczu; obecnie występuje w zauważalnym stopniu w Polsce na obszarach zamieszkiwanych przez mniejszość niemiecką. Imię to powstało z połączenia członów <i>adal</i> – 'szlachetny ród' oraz <i>trud</i> – 'siła, potęga' i stanowi późniejszą wersję niemieckiego imienia <i>Adeltraud</i>.", "Elvire": "<p>Elvira to imię kobiece. Uważa się, że po raz pierwszy został zarejestrowany w średniowiecznej Hiszpanii; niektóre źródła twierdzą, że prawdopodobnie pochodzi z niemieckiego (gotyckiego) pochodzenia.</p>", "Erika Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Erika</b>.</p><b>Eryka</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eryk\" target=\"_blank\" rel=\"noopener noreferrer\">Eryk</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>.", "Euzebiusza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Euzebiusz</b>.</p><b>Euzebiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> <i>eusébeios</i>. Pierwotnie przymiotnik ten użyty został dla określenia jednego z miesięcy na cześć cesarza rzymskiego <a href=\"https://pl.wikipedia.org/wiki/Antoninus_Pius\" target=\"_blank\" rel=\"noopener noreferrer\">Antonina Piusa</a>. Wywodzi się od słowa oznaczającego „bogobojny”, „święty”.", "Elçin": "<p>Elçin to kobiece turskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Eli̇z": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eliza</b>.</p><b>Eliza</b> – skrócona forma <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Elisabeth</i>, czyli po polsku <a href=\"https://pl.wikipedia.org/wiki/El%C5%BCbieta\" target=\"_blank\" rel=\"noopener noreferrer\">Elżbiety</a>. W Polsce jest znane od <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a> jako imię literackie, a gwałtowną popularność zyskało w <a href=\"https://pl.wikipedia.org/wiki/Lata_70._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 70 XX wieku</a>.", "Elspeth": "<p>Elspeth lub Elspet jest imieniem żeńskim, które jest szkocką formą Elizabeth. Oznacza to \"wybrany przez Boga\" lub \"oświęty przez Boga\".</p>", "Eligiusza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eligiusz</b>.</p><b>Eligiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> czasownika <i>eligo, elegi, electum</i> oznaczające – „wybrany”.", "Ellona": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elona</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elon</b>.</p><b>Elon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> אֵילֹן) – postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijna</a>, według <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_S%C4%99dzi%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Sędziów</a> (Sdz 12,11-12) dziesiąty <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziowie_(Biblia)\" target=\"_blank\" rel=\"noopener noreferrer\">sędzia</a> <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a>. Pochodził z plemienia <a href=\"https://pl.wikipedia.org/wiki/Zabulon\" target=\"_blank\" rel=\"noopener noreferrer\">Zebulona</a>, objął rządy po śmierci <a href=\"https://pl.wikipedia.org/wiki/Ibsan\" target=\"_blank\" rel=\"noopener noreferrer\">Ibsana</a>. Panował przez dziesięć lat. Po śmierci został pochowany w Ajjalonie na terytorium Zebulonitów, utożsamianym z Chirbet el-Lon w <a href=\"https://pl.wikipedia.org/wiki/Galilea\" target=\"_blank\" rel=\"noopener noreferrer\">Galilei</a>. Jego następcą został <a href=\"https://pl.wikipedia.org/wiki/Abdon_(s%C4%99dzia)\" target=\"_blank\" rel=\"noopener noreferrer\">Abdon</a>.", "Eustazja": "<b>Eustazja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, stanowiące żeński odpowiednik imion <a href=\"https://pl.wikipedia.org/wiki/Eustazjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Eustazjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Eustazy\" target=\"_blank\" rel=\"noopener noreferrer\">Eustazy</a>. Wśród patronów tego imienia – św. Eustazjusz, biskup <a href=\"https://pl.wikipedia.org/wiki/Neapol\" target=\"_blank\" rel=\"noopener noreferrer\">Neapolu</a>.", "Eva-Lotta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eva</b>.</p><p>⁇ Eva ⁇ - single Nightwish z albumu Dark Passion Play, wydany w 2007 roku i rozpowszechniony przez internet. Wszystkie pieniądze zebrane z sprzedaży zostały przekazane na dobroczynność.</p>", "Elysa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elisa</b>.</p><p>Elisa - skrócie i nazwa: Elisa - japońska piosenkarka Elisa - wolny audio-player dla systemów operacyjnych Linux, Windows i Android. Elisa (Electronic Intelligence Satellite) - system z czterech mikrosatelietów francuskiego ministerstwa obrony.</p>", "Eftichia": "<p>Eutychia (grecki: ευτυχία), fonetycznie przetransliterowana jako Eftychia lub Eftichia () jest greckie nazwisko żeńskie, oznaczające \"szczęście\". Pochodzi od greckiego ε ⁇ (dobry) i τύχη (szczęście).</p>", "Evgenya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Evgeny</b>.</p><p>Yevgeni (rosyjski: Евгений), również przetransliterowany jako Yevgeny, Yevgenii, Yevgeniy, Evgeniy, Yewgeny, Evgenii, Evgenii, Evgenyi lub Evgenij, jest rosyjską formą męskiego imienia Eugene. Krótka forma jest Zhenya (Женя), również przetłumaczana jako Jenya lub Shenya.</p>", "Enara": "<p>Ainara lub Enara jest baskijską nazwą żeńską, co oznacza \"ptakę połykającą\".</p>", "Elena-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elena</b>.</p><b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272.", "Esterina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ester</b>.</p><p>W chemii ester jest składnikiem chemicznym pochodzącym z kwasu (organicznego lub niekomórkowego), w którym przynajmniej jeden z grup LIPOH (hydroxyl) jest zastąpiony grupą alkyl (alkiel). Zazwyczaj estery są składające się z kwasu karboxylowego i alkoholu.</p>", "Ewodia": "<b>Ewodia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Ewodiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Ewodiusz</a>, złożonego z członów <i>eu-</i> (\"dobry\") i <i>hodos-</i> (\"droga\"), i oznaczającego \"człowiek dobrej drogi, mający powodzenie\". Ewodia jest wspomniana w <a href=\"https://pl.wikipedia.org/wiki/List_do_Filipian\" target=\"_blank\" rel=\"noopener noreferrer\">liście św. Pawła do Filipian</a>. <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościół katolicki</a> notuje sześciu świętych Ewodiuszów — patronów tego imienia.", "Emilyia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emiliia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emilia</b>.</p>Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Eyla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eila</b>.</p><p>Eila może odnosić się do: Eila Campbell (1915-1994), angielskiej geografa i kartografa Eila Hiltunen (1922-2003), fińskiej rzeźbiarzy Eila Ilmatar Juutilainen, postaci z anime Strike Witches Eila Kivikk'aho (1921-2004), fińskiej poetki Eila Pellinen (1938-1977), fińskiej piosenkarki Eila Roine (1931-2025), fińskiego aktorki Eila C. Skinner, amerykańskiego onkologa urologicznego i chirurga Eila (film), fiński film z 2003 roku</p>", "Elżbieta Jadwiga": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elżbieta</b>.</p><b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Elizabeth Mary": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elizabeth</b>.</p><p>Elizabeth lub Elisabeth jest transkrypcją nazwiska dla kobiet z greckiego słowa ⁇ λισάβετ, Elisabet. Nazwa pochodzi od hebrajskiego słowa Elisheva, co oznacza \"Obietnica Boga\". Z czasem Elizabeth i Elisabeth zostały przekształcone w różnych krajach, aby stać się: Libby, Lisa, Liza, Lilly, Lizzie, Liz, Beth, Betty, Ella, Elisa, Elise, i Eliza; Elspeth, Elsa, Bitsy, Betsy, Isabel i Isabella.</p>", "Ewerysta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eweryst</b>.</p><b>Ewaryst</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, które oznacza <i>miły, przyjemny, najlepszy</i>. Imię to nadawane jest w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII</a> w. Istnieje kilku świętych Ewarystów, m.in. <a href=\"https://pl.wikipedia.org/wiki/Ewaryst_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">Ewaryst, papież</a> oraz św. Ewaryst z Konstantynopola.", "Eleny": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eleni</b>.</p><b>Eleni Tzoka</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ελένη Τζόκα) z domu <b>Milopulu</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Μυλοπούλου) (ur. <a href=\"https://pl.wikipedia.org/wiki/27_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">27 kwietnia</a> <a href=\"https://pl.wikipedia.org/wiki/1956\" target=\"_blank\" rel=\"noopener noreferrer\">1956</a> w <a href=\"https://pl.wikipedia.org/wiki/Bielawa\" target=\"_blank\" rel=\"noopener noreferrer\">Bielawie</a>) – <a href=\"https://pl.wikipedia.org/wiki/Polacy\" target=\"_blank\" rel=\"noopener noreferrer\">polska</a> <a href=\"https://pl.wikipedia.org/wiki/Piosenkarz\" target=\"_blank\" rel=\"noopener noreferrer\">piosenkarka</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Grecy\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Autor\" target=\"_blank\" rel=\"noopener noreferrer\">autorka tekstów</a> i <a href=\"https://pl.wikipedia.org/wiki/Kompozytor\" target=\"_blank\" rel=\"noopener noreferrer\">kompozytorka</a>. Wykonuje utwory w języku: polskim, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckim</a> i angielskim.", "Ewa Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ewa</b>.</p><b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Eli̇sa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elis</b>.</p><p>Elis - z Lichtenšteinu, utworzony w 2003 roku i wykonujący gotycki metal.</p>", "Enora": "<p>Enora lub Énora to bretonskie nazwisko kobiet. Wśród znanych osób z nazwiskiem są: Enora Latuillière (ur. 1992), francuska biatleta Énora Malagré (ur. 1980), francuska kolumnista i prezenterka radiowo-telewizji Énora Villard (ur. 1993), francuska profesjonalna piłkarka squashu</p>", "Eija": "<p>Eija to fińskie imię dla kobiet. Nazwa jest 19 lutego.</p>", "Emmily": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emily</b>.</p><p>Emily Brontë Emily Osment Emily Dickinson Emily, wietnamskiej piosenkarki</p>", "Elżbieta Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elżbieta</b>.</p><b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Elleonora": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eleonora</b>.</p><b>Eleonora</b> – imię żeńskie nieustalonego pochodzenia; być może <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (może od <i>el</i> – „Bóg” oraz <i>or</i> – „światło”; czyli „Bóg mi światłem”), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (od <i>eleo</i> – „lituję się”).", "Eniko": "<p>Enikő to węgierskie imię dla kobiet, które zostało stworzone przez węgierskiego poeta Mihály Vörösmarty w XIX wieku i pochodzi z imienia Enéh, co oznacza \"młody hind\" (żwięcę jelenia). W mitologii węgierskiej Enéh lub Eneth była matką Hunora i Magora, którzy byli ojcami narodów Hunów i Węgierów.</p>", "Ewa Grażyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ewa</b>.</p><b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Elżbieta Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elżbieta</b>.</p><b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Erazmina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Erazm</b>.</p><b>Erazm</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „miły”, „uprzejmy”. W dawnych źródłach mazowieckich Erazm pojawia się jako zamiennik męskiego imienia słowiańskiego <i><b><a href=\"https://pl.wikipedia.org/wiki/Niemir\" target=\"_blank\" rel=\"noopener noreferrer\">Niemierza</a></b></i>.", "Elżbieta Irena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elżbieta</b>.</p><b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Eunike": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eunice</b>.</p><p>Eunice (lat. Eunice) - rodzaj morskich wieloczęścianych robaków z rodziny Eunicidae oddziału Eunicida. Długość ciała wynosi od 0,5 do 300 cm; ciała składają się z wielu segmentów.</p>", "Eva-Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eva</b>.</p><p>⁇ Eva ⁇ - single Nightwish z albumu Dark Passion Play, wydany w 2007 roku i rozpowszechniony przez internet. Wszystkie pieniądze zebrane z sprzedaży zostały przekazane na dobroczynność.</p>", "Ekatherina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ekaterina</b>.</p><p>Ekaterina to rosyjskie imię żeńskie i alternatywna transliteracja rosyjskiej Yekateriny. Katya i Katyusha są powszechnymi drobnymi formami Ekaterina.</p>", "Elżbieta Janina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elżbieta</b>.</p><b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Elizabeth Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elizabeth</b>.</p><p>Elizabeth lub Elisabeth jest transkrypcją nazwiska dla kobiet z greckiego słowa ⁇ λισάβετ, Elisabet. Nazwa pochodzi od hebrajskiego słowa Elisheva, co oznacza \"Obietnica Boga\". Z czasem Elizabeth i Elisabeth zostały przekształcone w różnych krajach, aby stać się: Libby, Lisa, Liza, Lilly, Lizzie, Liz, Beth, Betty, Ella, Elisa, Elise, i Eliza; Elspeth, Elsa, Bitsy, Betsy, Isabel i Isabella.</p>", "Emilli": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emill</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emil</b>.</p><b>Emil</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Emiliusze\" target=\"_blank\" rel=\"noopener noreferrer\">Emiliuszów</a> (<i>Aemilius</i>). Łacińskie słowo <i>aemulor</i> oznacza „rywalizujący”. Patronem imienia jest <a href=\"https://pl.wikipedia.org/wiki/Emil_z_Kordoby\" target=\"_blank\" rel=\"noopener noreferrer\">Emil z Kordoby</a> (†852), męczennik i święty katolicki wspominany 15 września.", "Eva Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eva</b>.</p><p>⁇ Eva ⁇ - single Nightwish z albumu Dark Passion Play, wydany w 2007 roku i rozpowszechniony przez internet. Wszystkie pieniądze zebrane z sprzedaży zostały przekazane na dobroczynność.</p>", "Evgenyia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Evgenyi</b>.</p><p>Yevgeni (rosyjski: Евгений), również przetransliterowany jako Yevgeny, Yevgenii, Yevgeniy, Evgeniy, Yewgeny, Evgenii, Evgenii, Evgenyi lub Evgenij, jest rosyjską formą męskiego imienia Eugene. Krótka forma jest Zhenya (Женя), również przetłumaczana jako Jenya lub Shenya.</p>", "Ewdokija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ewdokia</b>.</p><b>Eudokia</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Εὐδοκία) – imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;ευδοκεω (<i>eudokeo</i>), co według niektórych źródeł oznacza „być bardzo zadowolonym, być zadowolonym”, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;ευ – „dobra” i δοκεω (<i>dokeo</i>) – „myśleć, wyobrażać sobie, przypuszczać”, według innych – \"życzliwość\". Jej ludową formą rosyjską jest <i><b>Awdotia</b></i>. W polskiej literaturze Eudokia jest utożsamiana z <a href=\"https://pl.wikipedia.org/wiki/Eudoksja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Eudoksją</a>.", "Ellianna": "<p>Eliana, Elianna, אֱלִיעָנָה (Hebrajczy), Ηλιάνα (Grzeczy), إليانا (Arabic), jest imieniem żeńskim znalezione w języku hebrajskim, włoskim, portugalskim i hiszpańskim.</p>", "Ellisa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ellis</b>.</p><p>Job Bicknell Ellis (ang. Job Bicknel Ellis; 1829 - 1905) - amerykański mikolog.</p>", "Eldina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eldin</b>.</p><p>Eldin to męskie imię i nazwisko. Na Bałkanach Eldin jest popularny wśród bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Eleonora Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eleonora</b>.</p><b>Eleonora</b> – imię żeńskie nieustalonego pochodzenia; być może <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (może od <i>el</i> – „Bóg” oraz <i>or</i> – „światło”; czyli „Bóg mi światłem”), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (od <i>eleo</i> – „lituję się”).", "Elisawet": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elisavet</b>.</p><p>Elizabet to imię kobiece, odmiana hebrajskiej nazwy Elishewa (אֱלִישֶׁבַע), co oznacza \"Mój Bóg jest przysięgą\" lub \"Mój Boże jest obfitością\", jak to tłumaczy Septuaginta.</p>", "Eva-Sofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eva</b>.</p><p>⁇ Eva ⁇ - single Nightwish z albumu Dark Passion Play, wydany w 2007 roku i rozpowszechniony przez internet. Wszystkie pieniądze zebrane z sprzedaży zostały przekazane na dobroczynność.</p>", "Esfira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Esfir</b>.</p><p>Esfir lub Esphyr (rosyjski: Эсфирь) to rosyjskie imię kobiety, forma nazwiska Esther.</p>", "Ellaina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ella</b>.</p><p>Ella (ang. - ⁇ Ella ⁇) - trzydziestni dziewiąty album studiów amerykańskiej piosenkarki jazzowej Ella Fitzgerald, wydany na wytwórni Reprise Records w 1969 roku pod numerem RS 6354.</p>", "Ewa Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ewa</b>.</p><b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Emilia Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emilia</b>.</p>Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Ediye": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Edie</b>.</p><p>Edie to kobiece imię, często diminutiwna forma (hipokoryzm) Edith, a także nazwisko. Może odnosić się do:</p>", "Eryca": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eryka</b>.</p><b>Eryka</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eryk\" target=\"_blank\" rel=\"noopener noreferrer\">Eryk</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>.", "Ewa Barbara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ewa</b>.</p><b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Elżbieta Stanisława": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elżbieta</b>.</p><b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Eliana Marcela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eliana</b>.</p><p>Eliana Mihailishin Bezera (port. Eliana Michaelichen Bezerra; bardziej znana jako Eliana; rodzaj.</p>", "Elena-Andreea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elena</b>.</p><b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272.", "Elżbieta Regina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elżbieta</b>.</p><b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Evva": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eva</b>.</p><p>⁇ Eva ⁇ - single Nightwish z albumu Dark Passion Play, wydany w 2007 roku i rozpowszechniony przez internet. Wszystkie pieniądze zebrane z sprzedaży zostały przekazane na dobroczynność.</p>", "Elenii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eleni</b>.</p><b>Eleni Tzoka</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ελένη Τζόκα) z domu <b>Milopulu</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Μυλοπούλου) (ur. <a href=\"https://pl.wikipedia.org/wiki/27_kwietnia\" target=\"_blank\" rel=\"noopener noreferrer\">27 kwietnia</a> <a href=\"https://pl.wikipedia.org/wiki/1956\" target=\"_blank\" rel=\"noopener noreferrer\">1956</a> w <a href=\"https://pl.wikipedia.org/wiki/Bielawa\" target=\"_blank\" rel=\"noopener noreferrer\">Bielawie</a>) – <a href=\"https://pl.wikipedia.org/wiki/Polacy\" target=\"_blank\" rel=\"noopener noreferrer\">polska</a> <a href=\"https://pl.wikipedia.org/wiki/Piosenkarz\" target=\"_blank\" rel=\"noopener noreferrer\">piosenkarka</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Grecy\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Autor\" target=\"_blank\" rel=\"noopener noreferrer\">autorka tekstów</a> i <a href=\"https://pl.wikipedia.org/wiki/Kompozytor\" target=\"_blank\" rel=\"noopener noreferrer\">kompozytorka</a>. Wykonuje utwory w języku: polskim, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckim</a> i angielskim.", "Emilia Zofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emilia</b>.</p>Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Elegia": "W poezji starogreckiej, skąd wywodzi się ten gatunek, obowiązkowa była dla niego forma wierszowa <a href=\"https://pl.wikipedia.org/wiki/Dystych_elegijny\" target=\"_blank\" rel=\"noopener noreferrer\">dystychu elegijnego</a>. Mistrzem elegii w poezji starorzymskiej był <a href=\"https://pl.wikipedia.org/wiki/Owidiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Owidiusz</a>, po nim gatunek ten uprawiali z powodzeniem <a href=\"https://pl.wikipedia.org/wiki/John_Milton\" target=\"_blank\" rel=\"noopener noreferrer\">John Milton</a>, <a href=\"https://pl.wikipedia.org/wiki/Johann_Wolfgang_von_Goethe\" target=\"_blank\" rel=\"noopener noreferrer\">Johann Wolfgang von Goethe</a>, <a href=\"https://pl.wikipedia.org/wiki/Aleksandr_Puszkin\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandr Puszkin</a>, <a href=\"https://pl.wikipedia.org/wiki/Rainer_Maria_Rilke\" target=\"_blank\" rel=\"noopener noreferrer\">Rainer Maria Rilke</a>.", "Emma-Cristina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emma</b>.</p><p>Emma (jap. エマ Emma) - romantyczna saynenn-manga Mori Kaoru, wydana w czasopiśmie Comic Beam od sierpnia 2002 roku do kwietnia 2008 roku.</p>", "Elizabeth Ann": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elizabeth</b>.</p><p>Elizabeth lub Elisabeth jest transkrypcją nazwiska dla kobiet z greckiego słowa ⁇ λισάβετ, Elisabet. Nazwa pochodzi od hebrajskiego słowa Elisheva, co oznacza \"Obietnica Boga\". Z czasem Elizabeth i Elisabeth zostały przekształcone w różnych krajach, aby stać się: Libby, Lisa, Liza, Lilly, Lizzie, Liz, Beth, Betty, Ella, Elisa, Elise, i Eliza; Elspeth, Elsa, Bitsy, Betsy, Isabel i Isabella.</p>", "Emma-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emma</b>.</p><p>Emma (jap. エマ Emma) - romantyczna saynenn-manga Mori Kaoru, wydana w czasopiśmie Comic Beam od sierpnia 2002 roku do kwietnia 2008 roku.</p>", "Eliasza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eliasz</b>.</p><b>Eliasz</b>, również <b>Eliasz z Tiszbe</b> lub <b>Eliasz Tiszbita</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֱלִיָּהוּ&#8206; <i>Eliyáhu</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἠλίας <i>Elias</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_cerkiewnos%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">cs.</a>&#160;Илья-пророк) – jeden z <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">proroków</a> <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a> żyjący w IX w. przed Chrystusem w północnym państwie Izraela (imię tłumaczone jako: „Bogiem jest <a href=\"https://pl.wikipedia.org/wiki/Jah\" target=\"_blank\" rel=\"noopener noreferrer\">Jah</a>”, „moim Bogiem jest <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”). <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ci_i_b%C5%82ogos%C5%82awieni_Ko%C5%9Bcio%C5%82a_katolickiego\" target=\"_blank\" rel=\"noopener noreferrer\">Święty Kościoła katolickiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Cerkiew_prawos%C5%82awna\" target=\"_blank\" rel=\"noopener noreferrer\">prawosławnego</a>, <a href=\"https://pl.wikipedia.org/wiki/Koptyjski_Ko%C5%9Bci%C3%B3%C5%82_Ortodoksyjny\" target=\"_blank\" rel=\"noopener noreferrer\">koptyjskiego</a>, <a href=\"https://pl.wikipedia.org/wiki/Apostolski_Ko%C5%9Bci%C3%B3%C5%82_Ormia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">ormiańskiego</a> i <a href=\"https://pl.wikipedia.org/wiki/Syryjski_Ko%C5%9Bci%C3%B3%C5%82_Ortodoksyjny\" target=\"_blank\" rel=\"noopener noreferrer\">syryjskiego</a>.", "Elżbieta Danuta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elżbieta</b>.</p><b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Elianah": "<p>Eliana, Elianna, אֱלִיעָנָה (Hebrajczy), Ηλιάνα (Grzeczy), إليانا (Arabic), jest imieniem żeńskim znalezione w języku hebrajskim, włoskim, portugalskim i hiszpańskim.</p>", "Eugenia Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eugenia</b>.</p><b>Eugenia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeńska forma męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Eugeniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Eugeniusz</a>.", "Elżbieta Wiktoria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elżbieta</b>.</p><b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Emiilia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emilia</b>.</p>Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Evon": "<p>Evon to imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Ehab Mohamed Ahmed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ehab</b>.</p><p>Ehab to męskie imię i nazwisko pochodzące z arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Elizabeth Charlotte": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elizabeth</b>.</p><p>Elizabeth lub Elisabeth jest transkrypcją nazwiska dla kobiet z greckiego słowa ⁇ λισάβετ, Elisabet. Nazwa pochodzi od hebrajskiego słowa Elisheva, co oznacza \"Obietnica Boga\". Z czasem Elizabeth i Elisabeth zostały przekształcone w różnych krajach, aby stać się: Libby, Lisa, Liza, Lilly, Lizzie, Liz, Beth, Betty, Ella, Elisa, Elise, i Eliza; Elspeth, Elsa, Bitsy, Betsy, Isabel i Isabella.</p>", "Egidia": "<b>Egidia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia Egidiusz, które funkcjonuje w Polsce przede wszystkim w formie <a href=\"https://pl.wikipedia.org/wiki/Idzi\" target=\"_blank\" rel=\"noopener noreferrer\">Idzi</a>. Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Idzi_z_Saint-Gilles\" target=\"_blank\" rel=\"noopener noreferrer\">św. Idzi</a> i inni święci o tym imieniu. To imię nosiły córki królów szkockich, np. <a href=\"https://pl.wikipedia.org/wiki/Robert_II_Stewart\" target=\"_blank\" rel=\"noopener noreferrer\">Roberta II</a>.", "Eliana Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eliana</b>.</p><p>Eliana Mihailishin Bezera (port. Eliana Michaelichen Bezerra; bardziej znana jako Eliana; rodzaj.</p>", "Elisse": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elise</b>.</p><p>Eliza: Eliza to imię kobiety. Eliza Dolittl - bohaterka piosenki Bernarda Shaw'a ⁇ Pigmalion ⁇ (1912).</p>", "Elizabeth Lucia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elizabeth</b>.</p><p>Elizabeth lub Elisabeth jest transkrypcją nazwiska dla kobiet z greckiego słowa ⁇ λισάβετ, Elisabet. Nazwa pochodzi od hebrajskiego słowa Elisheva, co oznacza \"Obietnica Boga\". Z czasem Elizabeth i Elisabeth zostały przekształcone w różnych krajach, aby stać się: Libby, Lisa, Liza, Lilly, Lizzie, Liz, Beth, Betty, Ella, Elisa, Elise, i Eliza; Elspeth, Elsa, Bitsy, Betsy, Isabel i Isabella.</p>", "Eza": "<a href=\"https://pl.wikipedia.org/wiki/Wikipedia:Zastrze%C5%BCenia_dotycz%C4%85ce_poj%C4%99%C4%87_medycznych\" target=\"_blank\" rel=\"noopener noreferrer\">Przeczytaj ostrzeżenie dotyczące informacji medycznych i pokrewnych zamieszczonych w Wikipedii</a>.", "Ema-Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ema</b>.</p><b>Ema</b>, <b>Emma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia germańskiego, od imienia <i>Erma</i>, które było skróconą formą imion zaczynających się od <i>Erm-</i> i <i>Irm-</i>.", "Evdokija": "<p>Evdokija (srbski cyrylski: Евдокија, makedoniański: Евdoкија) i Jevdokija (Јевдокија) to serbskie i makedoniackie warianty greckiej nazwy Eudokia (Ευδοκία), żeńskiej nazwy. Może odnosić się do: Teodora-Evdokija (1330-po 1381), córka Stefana Dečanskiego, żony Dejana Jevdokij Balšić (fl.</p>", "Erika Vanessa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Erika</b>.</p><b>Eryka</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eryk\" target=\"_blank\" rel=\"noopener noreferrer\">Eryk</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>.", "Eli̇s": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elise</b>.</p><p>Eliza: Eliza to imię kobiety. Eliza Dolittl - bohaterka piosenki Bernarda Shaw'a ⁇ Pigmalion ⁇ (1912).</p>", "Eden Rose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eden</b>.</p><p>Eden (francuski: Eden)  Eden, angielski.</p>", "Emerencja": "<b>Emerencja</b>, <b>Emerencjana</b>, <b>Emerencjanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, o znaczeniu „ta, która się dobrze zasłużyła”. Chrześcijańską patronką tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Emerencjana_(m%C4%99czennica)\" target=\"_blank\" rel=\"noopener noreferrer\">Emerencjana</a>, rzymska męczennica.", "Edyt": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Edit</b>.</p><p>Edit (ang. edytować) - wieloznaczny termin: Edit - niemiecki czasopism literackie, wydany w Leipzczygu.</p>", "Edburga": "<b>Edburga</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, składające się z członów <i>ed–</i> — \"majątek dziedziczny, posiadłość dziedziczna\" i <i>–burg</i> — \"ochrona, opieka\", a oznaczające \"opiekunka posiadłości\". Istnieje sześć świętych patronek tego imienia — wszystkie były angielskimi mniszkami z okresu średniowiecza.", "Ewa Zofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ewa</b>.</p><b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Ewa Elżbieta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ewa</b>.</p><b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Elvisa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elvis</b>.</p><b>Elvis</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskiego</a> <i>Eall-wis</i>, czyli <i>mądrego</i>. Staroangielskie akcentowane „a” często przechodzi w „e”, a więc <i>Alvis</i> → <i>Elvis</i>. Czasami w wyjaśnieniach <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a> imienia alternatywne podaje się, że pochodzi ono od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska</a> <i>Elwes</i>, a wiążąc ją z nazwą <i>Alwyn</i>.", "Elena-Daniela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elena</b>.</p><b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272.", "Eulallia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eulalia</b>.</p><b>Eulalia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się ze złożenia słów εὐ („dobrze”) i λαλεῖν („mówić”), oznaczającego „dobrze mówiąca” lub „elokwentna”.", "Ewa Krystyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ewa</b>.</p><b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Estera-Marta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Estera</b>.</p><b>Estera</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Nosiła je <a href=\"https://pl.wikipedia.org/wiki/Estera_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">tytułowa bohaterka</a> <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Estery\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Estery</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֶסְתֵּר&#8206;). Imię to wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroperski\" target=\"_blank\" rel=\"noopener noreferrer\">staroperskiego</a> słowa <i>setarah</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">pers.</a>&#160;&#8207;ستاره&#8206;) oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Gwiazda\" target=\"_blank\" rel=\"noopener noreferrer\">gwiazda</a>”; może mieć również rodowód akadyjski – od imienia bogini <a href=\"https://pl.wikipedia.org/wiki/Isztar\" target=\"_blank\" rel=\"noopener noreferrer\">Isztar</a>.", "Eriikka": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Erika</b>.</p><b>Eryka</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eryk\" target=\"_blank\" rel=\"noopener noreferrer\">Eryk</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>.", "Elisabeta-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elisabeta</b>.</p><p>Elisabeta jest rumuńskim imieniem dla kobiet, równoważnym z Elżbiotą (nazwa dana), i może odnosić się do: Elisabeta Abrudeanu Elisabeta Anghel Elisabeta Bǎbeanu Elisabeta Bostan Elisabeta Ionescu Elisabeta Lazăr Elisabeta Lipă Elisabeta Movilă Elisabeta Polihroniade Elisabeta Rizea Elisabeta Turcu Elisabeta Știrbey Dwie postacie królewskie są znane jako Elisabeta w rumunskim: Elisabeta Wied Elisabeth z Rumunii Pałac Elisabeta</p>", "Ema-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ema</b>.</p><b>Ema</b>, <b>Emma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia germańskiego, od imienia <i>Erma</i>, które było skróconą formą imion zaczynających się od <i>Erm-</i> i <i>Irm-</i>.", "Eldino": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eldin</b>.</p><p>Eldin to męskie imię i nazwisko. Na Bałkanach Eldin jest popularny wśród bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Eliza-Ioana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eliza</b>.</p><b>Eliza</b> – skrócona forma <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Elisabeth</i>, czyli po polsku <a href=\"https://pl.wikipedia.org/wiki/El%C5%BCbieta\" target=\"_blank\" rel=\"noopener noreferrer\">Elżbiety</a>. W Polsce jest znane od <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a> jako imię literackie, a gwałtowną popularność zyskało w <a href=\"https://pl.wikipedia.org/wiki/Lata_70._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 70 XX wieku</a>.", "Erika Dayana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Erika</b>.</p><b>Eryka</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Eryk\" target=\"_blank\" rel=\"noopener noreferrer\">Eryk</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>.", "Edelburga": "<b>Edelburga</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Powstało ono ze staro-wysoko-niemieckich słów <i>adal</i> – 'szlachetny ród' oraz <i>burg</i> o znaczeniu 'ochraniać, chronić'. Wśród świętych – św. Edelburga, królewna, ksieni (<a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII wiek</a>).", "Emiliia-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emiliia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emilia</b>.</p>Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Emilliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Emilia</b>.</p>Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Elżbieta Wanda": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elżbieta</b>.</p><b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Eleanore": "<p>Eleanor () to żeńskie imię, pochodzące z starofrancuskiej adaptacji starej prowencalski nazwy Aliénor. Było to imię wielu kobiet z rodziny królewskiej i szlachty w Europie Zachodniej w średniowieczu.</p>", "Eva Irene": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eva</b>.</p><p>⁇ Eva ⁇ - single Nightwish z albumu Dark Passion Play, wydany w 2007 roku i rozpowszechniony przez internet. Wszystkie pieniądze zebrane z sprzedaży zostały przekazane na dobroczynność.</p>", "El Zahraa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>El</b>.</p>Według opinii wielu badaczy (Gerd Theissen, Morton Smith, Lowell Handy, <a href=\"https://pl.wikipedia.org/wiki/%C5%81ukasz_Niesio%C5%82owski-Span%C3%B2\" target=\"_blank\" rel=\"noopener noreferrer\">Łukasz Niesiołowski-Spanò</a>), od Ela wywodzi się biblijny Bóg <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, którego żoną była bogini <a href=\"https://pl.wikipedia.org/wiki/Aszera\" target=\"_blank\" rel=\"noopener noreferrer\">Aszera</a>.", "Eniia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Enia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Enya</b>.</p><p>Enia (ang. Enya, pełne imię Ennie Padraigine Nie Brennan, irlandzka.</p>", "Ecaterina-Cristina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ecaterina</b>.</p><p>Ecaterina to rumuńskie nazwisko dla kobiet, które oznacza Catherine. Do wybitnych osób z tym nazwiskiem należą: Ecaterina Andronescu (ur. 1948), rumuńska polityka i inżyniera Ecaterina Arbore (r.</p>", "Engelberta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Engelbert</b>.</p><b>Engelbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od nazwy jednego z plemion germańskich <i>Angil</i> (<a href=\"https://pl.wikipedia.org/wiki/Anglowie\" target=\"_blank\" rel=\"noopener noreferrer\">Anglowie</a>) połączonego słowem <i>beraht</i> oznaczającym \"jasny\".", "Emeryka": "<b>Emeryka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emeryk\" target=\"_blank\" rel=\"noopener noreferrer\">Emeryk</a>, wywodzącego się ze starogermańskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Amalaryk\" target=\"_blank\" rel=\"noopener noreferrer\">Amalaryk</a>, oznaczającego „władca <a href=\"https://pl.wikipedia.org/wiki/Amalowie\" target=\"_blank\" rel=\"noopener noreferrer\">Amalów</a>” (Amalowie według gockiej legendy to ród królewski pochodzenia boskiego). Człon <i>amal</i> może także oznaczać „gorliwy” lub „dzielny, aktywny”. Emeryka może wywodzić się również z saksońskiego <i>Emmerich</i> i oznaczać „zawsze bogata”.", "Elisaweta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elisaveta</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elisavet</b>.</p><p>Elizabet to imię kobiece, odmiana hebrajskiej nazwy Elishewa (אֱלִישֶׁבַע), co oznacza \"Mój Bóg jest przysięgą\" lub \"Mój Boże jest obfitością\", jak to tłumaczy Septuaginta.</p>", "Eva Stik": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Eva</b>.</p><p>⁇ Eva ⁇ - single Nightwish z albumu Dark Passion Play, wydany w 2007 roku i rozpowszechniony przez internet. Wszystkie pieniądze zebrane z sprzedaży zostały przekazane na dobroczynność.</p>", "Elyza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eliza</b>.</p><b>Eliza</b> – skrócona forma <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <i>Elisabeth</i>, czyli po polsku <a href=\"https://pl.wikipedia.org/wiki/El%C5%BCbieta\" target=\"_blank\" rel=\"noopener noreferrer\">Elżbiety</a>. W Polsce jest znane od <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a> jako imię literackie, a gwałtowną popularność zyskało w <a href=\"https://pl.wikipedia.org/wiki/Lata_70._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 70 XX wieku</a>.", "Elizabeth-Ann": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elizabeth</b>.</p><p>Elizabeth lub Elisabeth jest transkrypcją nazwiska dla kobiet z greckiego słowa ⁇ λισάβετ, Elisabet. Nazwa pochodzi od hebrajskiego słowa Elisheva, co oznacza \"Obietnica Boga\". Z czasem Elizabeth i Elisabeth zostały przekształcone w różnych krajach, aby stać się: Libby, Lisa, Liza, Lilly, Lizzie, Liz, Beth, Betty, Ella, Elisa, Elise, i Eliza; Elspeth, Elsa, Bitsy, Betsy, Isabel i Isabella.</p>", "Ewa-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ewa</b>.</p><b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Elżbieta Julia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elżbieta</b>.</p><b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Emilia Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emilia</b>.</p>Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Elena-Ştefania": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elena</b>.</p><b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272.", "Elenna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Elena</b>.</p><b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272.", "Ewa Małgorzata": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ewa</b>.</p><b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Ewa Marta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ewa</b>.</p><b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Eugeniusza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Eugeniusz</b>.</p><b>Eugeniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Oznacza „zacny“ lub „szlachetnie urodzony”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Eugenia\" target=\"_blank\" rel=\"noopener noreferrer\">Eugenia</a>.", "Erica Tatiana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Erica</b>.</p><p>Erika (lat. Érica) - rozległy gatunek wieczniezielonych roślin rodziny Wereskowych.</p>", "Eera": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Era</b>.</p><p>Era - projekt muzyczny w stylu new-age, założony w 1996 roku przez francuskiego kompozytora i multiinstrumentalistę (klawiatury, gitary) Erica Levy'ego.</p>", "Emilia Krystyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Emilia</b>.</p>Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Emil\" target=\"_blank\" rel=\"noopener noreferrer\">Emil</a>, <a href=\"https://pl.wikipedia.org/wiki/Emilian\" target=\"_blank\" rel=\"noopener noreferrer\">Emilian</a>.", "Elisabeta-Denisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elisabeta</b>.</p><p>Elisabeta jest rumuńskim imieniem dla kobiet, równoważnym z Elżbiotą (nazwa dana), i może odnosić się do: Elisabeta Abrudeanu Elisabeta Anghel Elisabeta Bǎbeanu Elisabeta Bostan Elisabeta Ionescu Elisabeta Lazăr Elisabeta Lipă Elisabeta Movilă Elisabeta Polihroniade Elisabeta Rizea Elisabeta Turcu Elisabeta Știrbey Dwie postacie królewskie są znane jako Elisabeta w rumunskim: Elisabeta Wied Elisabeth z Rumunii Pałac Elisabeta</p>", "Elizabeth Margaret": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elizabeth</b>.</p><p>Elizabeth lub Elisabeth jest transkrypcją nazwiska dla kobiet z greckiego słowa ⁇ λισάβετ, Elisabet. Nazwa pochodzi od hebrajskiego słowa Elisheva, co oznacza \"Obietnica Boga\". Z czasem Elizabeth i Elisabeth zostały przekształcone w różnych krajach, aby stać się: Libby, Lisa, Liza, Lilly, Lizzie, Liz, Beth, Betty, Ella, Elisa, Elise, i Eliza; Elspeth, Elsa, Bitsy, Betsy, Isabel i Isabella.</p>", "Elżbieta Antonina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elżbieta</b>.</p><b>Elżbieta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a> wywodzące się od hebrajskiego słowa אלשבת <i>eliszewa</i> („Bóg mą przysięgą”). Zdrobnienia to Ela, Elka, Elcia, Elunia, Elżbietka, Elżunia, a pochodne to <a href=\"https://pl.wikipedia.org/wiki/Halszka\" target=\"_blank\" rel=\"noopener noreferrer\">Halszka</a>, Halżbieta, Alżbieta, <a href=\"https://pl.wikipedia.org/wiki/Izabela\" target=\"_blank\" rel=\"noopener noreferrer\">Izabela</a>, Liza, Elza (germ.), Eliza.", "Elena-Daria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Elena</b>.</p><b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272."};
